function normalizeLanguage(lang) {
  const l = String(lang || '').trim().toLowerCase();
  if (l === 'en' || l === 'th') return l;
  return 'ko';
}

function t(key, fallback = '') {
  const lang = normalizeLanguage(state.lang);
  return I18N?.[lang]?.[key] ?? I18N?.ko?.[key] ?? fallback ?? key;
}

function tf(key, fallback = '', params = {}) {
  let out = String(t(key, fallback));
  if (!params || typeof params !== 'object') return out;
  for (const [k, v] of Object.entries(params)) {
    out = out.replaceAll(`{${k}}`, String(v));
  }
  return out;
}

function applyDataI18n() {
  qsa('[data-i18n]').forEach((el) => {
    const key = el.getAttribute('data-i18n');
    if (!key) return;
    const fallback = el.getAttribute('data-i18n-fallback') || el.textContent || '';
    el.textContent = t(key, fallback);
  });
  qsa('[data-i18n-placeholder]').forEach((el) => {
    const key = el.getAttribute('data-i18n-placeholder');
    if (!key) return;
    const fallback = el.getAttribute('placeholder') || '';
    el.setAttribute('placeholder', t(key, fallback));
  });
  qsa('[data-i18n-title]').forEach((el) => {
    const key = el.getAttribute('data-i18n-title');
    if (!key) return;
    const fallback = el.getAttribute('title') || '';
    el.setAttribute('title', t(key, fallback));
  });
}

function getPageTitles() {
  return {
    'overview': t('title.overview', 'Overview'),
    'strategy-pingpong': t('title.strategy-pingpong', 'PINGPONG 전략'),
    'strategy-autoloop': t('title.strategy-autoloop', 'AUTOLOOP 전략'),
    'strategy-ladder': t('title.strategy-ladder', 'LADDER 전략'),
    'strategy-lightning': t('title.strategy-lightning', 'LIGHTNING 전략'),
    'strategy-gazua': t('title.strategy-gazua', 'GAZUA 전략'),
    'strategy-contrarian': t('title.strategy-contrarian', 'CONTRARIAN 전략'),
    'strategy-sniper': t('title.strategy-sniper', 'SNIPER 전략'),
    'strategy-longshort': t('title.strategy-longshort', 'LONG / SHORT'),
    'market-active': t('title.market-active', 'Active 마켓'),
    'market-reserved': t('title.market-reserved', 'Reserved 후보'),
    'market-reserved-snapshot': t('title.market-reserved-snapshot', 'Reserved 후보 (07:00 KST)'),
    'market-longhold': t('title.market-longhold', 'LongHold'),
    'report': t('title.report', 'Report'),
    'performance': t('title.performance', 'Performance'),
    'ai-status': t('title.ai-status', 'AI Status'),
    'ai-upside': t('title.ai-upside', 'Market Upside'),
    'ai-advisor': t('title.ai-advisor', 'Strategy Advisor'),
    'ai-alerts': t('title.ai-alerts', 'Market Alerts'),
    'guard-matrix': t('title.guard-matrix', 'Guard Matrix'),
    'reserved-settings': t('title.reserved-settings', 'Reserved 설정'),
    'settings': t('title.settings', 'Settings'),
  };
}

function applyLanguage(lang, persist = true) {
  state.lang = normalizeLanguage(lang);
  document.documentElement.setAttribute('lang', state.lang);
  if (persist) localStorage.setItem(LS_LANG, state.lang);

  const sel = qs('lang-select');
  if (sel) sel.value = state.lang;

  applyDataI18n();
  const titleEl = qs('page-title');
  if (titleEl) {
    const titles = getPageTitles();
    titleEl.textContent = titles[state.currentPage] || titleEl.textContent;
  }
}

function initLanguage() {
  const stored = localStorage.getItem(LS_LANG);
  const browserLang = String(navigator.language || '').toLowerCase();
  const detected = browserLang.startsWith('th') ? 'th' : (browserLang.startsWith('en') ? 'en' : 'ko');
  const selected = normalizeLanguage(stored || detected);
  const sel = qs('lang-select');
  if (sel) {
    sel.value = selected;
    sel.addEventListener('change', (e) => applyLanguage(e.target.value, true));
  }
  applyLanguage(selected, false);
}

// ============================================================
// Price Chart (Lightweight Charts) - Dual: Bybit + Binance
// ============================================================

let priceChart = null;
let priceSeries = null;
let binanceChart = null;
let binanceSeries = null;
let chartRefreshTimer = null;
let _focusPriceLines = [];  // TP/SL/Entry 수평선

function initPriceChart() {
  const container = qs('price-chart');
  const binanceContainer = qs('binance-chart');
  if (typeof LightweightCharts === 'undefined') return;
  
  const CHART_HEIGHT = 280;
  
  // Bybit Chart (Left)
  if (container) {
    priceChart = LightweightCharts.createChart(container, {
      layout: {
        background: { type: 'solid', color: 'transparent' },
        textColor: '#666',
      },
      grid: {
        vertLines: { color: 'rgba(42, 46, 57, 0.3)' },
        horzLines: { color: 'rgba(42, 46, 57, 0.3)' },
      },
      width: container.clientWidth,
      height: CHART_HEIGHT,
      rightPriceScale: {
        mode: 0,
        scaleMargins: { top: 0.1, bottom: 0.1 },
      },
      timeScale: {
        timeVisible: true,
        secondsVisible: false,
        fixRightEdge: true,
        rightOffset: 2,
        tickMarkFormatter: (t) => {
          const d = new Date(t * 1000);
          const h = d.getHours().toString().padStart(2,'0');
          const m = d.getMinutes().toString().padStart(2,'0');
          // 자정이면 날짜 표시, 아니면 시간만
          if (h === '00' && m === '00') {
            return `${(d.getMonth()+1)}/${d.getDate()}`;
          }
          return `${h}:${m}`;
        },
      },
      localization: {
        timeFormatter: (t) => {
          const d = new Date(t * 1000);
          return `${(d.getMonth()+1).toString().padStart(2,'0')}/${d.getDate().toString().padStart(2,'0')} ${d.getHours().toString().padStart(2,'0')}:${d.getMinutes().toString().padStart(2,'0')} KST`;
        },
      },
    });
    
    priceSeries = priceChart.addCandlestickSeries({
      upColor: '#10b981',
      downColor: '#ef4444',
      borderVisible: false,
      wickUpColor: '#10b981',
      wickDownColor: '#ef4444',
    });
  }
  
  // Binance Chart (Right)
  if (binanceContainer) {
    binanceChart = LightweightCharts.createChart(binanceContainer, {
      layout: {
        background: { type: 'solid', color: 'transparent' },
        textColor: '#666',
      },
      grid: {
        vertLines: { color: 'rgba(42, 46, 57, 0.3)' },
        horzLines: { color: 'rgba(42, 46, 57, 0.3)' },
      },
      width: binanceContainer.clientWidth,
      height: CHART_HEIGHT,
      rightPriceScale: {
        mode: 0,
        scaleMargins: { top: 0.1, bottom: 0.1 },
      },
      timeScale: {
        timeVisible: true,
        secondsVisible: false,
        fixRightEdge: true,
        rightOffset: 2,
        tickMarkFormatter: (t) => {
          const d = new Date(t * 1000);
          const h = d.getHours().toString().padStart(2,'0');
          const m = d.getMinutes().toString().padStart(2,'0');
          if (h === '00' && m === '00') {
            return `${(d.getMonth()+1)}/${d.getDate()}`;
          }
          return `${h}:${m}`;
        },
      },
      localization: {
        timeFormatter: (t) => {
          const d = new Date(t * 1000);
          return `${(d.getMonth()+1).toString().padStart(2,'0')}/${d.getDate().toString().padStart(2,'0')} ${d.getHours().toString().padStart(2,'0')}:${d.getMinutes().toString().padStart(2,'0')} KST`;
        },
      },
    });
    
    binanceSeries = binanceChart.addCandlestickSeries({
      upColor: '#f0b90b',  // Binance yellow for up
      downColor: '#ef4444',
      borderVisible: false,
      wickUpColor: '#f0b90b',
      wickDownColor: '#ef4444',
    });
  }
  
  window.addEventListener('resize', () => {
    if (priceChart && container) {
      priceChart.applyOptions({ width: container.clientWidth });
    }
    if (binanceChart && binanceContainer) {
      binanceChart.applyOptions({ width: binanceContainer.clientWidth });
    }
  });
  
  loadChartData();
  loadBinanceChartData();
  loadAllMarkets();  // 전체 마켓 목록 로드
  
  // Market change → 양쪽 차트 연동
  const marketInput = qs('chart-market');
  if (marketInput) {
    // 입력 완료 시 (엔터 또는 포커스 아웃)
    marketInput.addEventListener('change', () => {
      // USDT suffix auto-add
      let val = marketInput.value.toUpperCase();
      if (!val.endsWith('USDT') && val.length > 0) {
        val = val + 'USDT';
        marketInput.value = val;
      }
      loadChartData();
      loadBinanceChartData();
    });
    // 엔터키로도 즉시 로드
    marketInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') {
        marketInput.blur();  // change 이벤트 트리거
      }
    });
  }
  qs('chart-interval')?.addEventListener('change', loadChartData);
  qs('binance-chart-interval')?.addEventListener('change', loadBinanceChartData);
  
  // 자동 갱신 설정
  qs('chart-refresh')?.addEventListener('change', setupChartRefresh);
  setupChartRefresh();  // 초기 설정 (기본 10초)
}

function setupChartRefresh() {
  // 기존 타이머 정리
  if (chartRefreshTimer) {
    clearInterval(chartRefreshTimer);
    chartRefreshTimer = null;
  }
  
  const seconds = parseInt(qs('chart-refresh')?.value || '0', 10);
  if (seconds > 0) {
    chartRefreshTimer = setInterval(() => {
      loadChartData();
      loadBinanceChartData();
    }, seconds * 1000);
  }
}

async function loadChartData() {
  if (!priceSeries) return;
  
  const market = qs('chart-market')?.value || 'BTCUSDT';
  const interval = qs('chart-interval')?.value || '15';
  
  try {
    const res = await authFetch(`/api/market/candles?market=${market}&interval=${interval}&count=100`);
    const data = await res.json();
    
    if (data.ok && data.candles && data.candles.length > 0) {
      const chartData = data.candles.map(c => {
        let timeVal;
        if (typeof c.timestamp === 'string') {
          // KST 시간 그대로 사용 (한국 시간 표기)
          const d = new Date(c.timestamp);
          timeVal = Math.floor(d.getTime() / 1000);
        } else {
          timeVal = Math.floor(c.timestamp / 1000);
        }
        return {
          time: timeVal,
          open: c.open,
          high: c.high,
          low: c.low,
          close: c.close,
        };
      });
      
      chartData.sort((a, b) => a.time - b.time);
      
      if (chartData.length > 0) {
        priceSeries.setData(chartData);
        priceChart.timeScale().fitContent();
      }
    }
    // ── FOCUS 포지션 TP/SL/Entry 선 ──
    _drawFocusPriceLines(market);
  } catch (e) {
    console.error('loadChartData error:', e);
  }
}

async function _drawFocusPriceLines(chartMarket) {
  // 기존 선 제거
  _focusPriceLines.forEach(l => { try { priceSeries.removePriceLine(l); } catch(e){} });
  _focusPriceLines = [];
  if (!priceSeries) return;
  try {
    const res = await authFetch('/api/strategy/focus/status');
    const d = await res.json();
    if (!d.ok) return;
    const pos = (d.positions || []).find(p => p.market === chartMarket);
    if (!pos) return;
    const isLong = pos.direction === 'LONG';
    const lines = [
      { price: pos.entry_price, color: '#fbbf24', title: 'Entry $' + pos.entry_price.toFixed(2), style: 2 },
      { price: pos.tp1, color: '#10b981', title: 'TP1 $' + pos.tp1.toFixed(2), style: 0 },
      { price: pos.sl,  color: '#ef4444', title: 'SL $' + pos.sl.toFixed(2), style: 0 },
    ];
    if (pos.tp2) {
      lines.push({ price: pos.tp2, color: '#34d399', title: 'TP2 $' + pos.tp2.toFixed(2), style: 1 });
    }
    lines.forEach(cfg => {
      const pl = priceSeries.createPriceLine({
        price: cfg.price,
        color: cfg.color,
        lineWidth: 1,
        lineStyle: cfg.style,  // 0=solid, 1=dotted, 2=dashed
        axisLabelVisible: true,
        title: cfg.title,
      });
      _focusPriceLines.push(pl);
    });
  } catch(e) {
    console.debug('Focus price lines error:', e);
  }
}

// All exchange markets cache
let allExchangeMarkets = [];

async function loadAllMarkets() {
  if (allExchangeMarkets.length > 0) return;
  try {
    const res = await authFetch('/api/system/markets?quote=USDT');
    const data = await res.json();
    if (data?.ok && Array.isArray(data.markets)) {
      allExchangeMarkets = data.markets;
    } else {
      // fallback: OMA 관리 마켓만이라도 표시
      const mRes = await authFetch('/api/manager/markets');
      const mData = await mRes.json();
      const set = new Set();
      ['active', 'recovery', 'watch'].forEach((k) => {
        (mData?.[k] || []).forEach((it) => {
          const m = (it?.market || '').toUpperCase();
          if (m.endsWith('USDT')) set.add(m);
        });
      });
      allExchangeMarkets = Array.from(set);
    }
    updateChartMarketDatalist();
  } catch (e) {
    console.error('loadAllMarkets error:', e);
  }
}

function updateChartMarketDatalist() {
  const datalist = document.getElementById('chart-market-list');
  if (!datalist) return;
  
  // OMA 관리 코인 우선, 나머지는 전체 목록
  const omaMarkets = Object.keys(state.prices || {});
  const otherMarkets = allExchangeMarkets.filter(m => !omaMarkets.includes(m));
  const allMarkets = [...omaMarkets, ...otherMarkets];
  
  datalist.innerHTML = allMarkets.map(m => 
    `<option value="${m}">${m.replace(/USDT$/i,'')}</option>`
  ).join('');
}

function updateChartMarketOptions() {
  updateChartMarketDatalist();
}

// Binance Chart Data Loading
async function loadBinanceChartData() {
  if (!binanceSeries) return;
  
  // 마켓 심볼에서 Bybit 형식 추출
  const bybitMarket = qs('chart-market')?.value || 'BTCUSDT';
  const binanceSymbol = bybitMarket.endsWith('USDT') ? bybitMarket : bybitMarket + 'USDT';
  const interval = qs('binance-chart-interval')?.value || '15m';
  
  try {
    // Binance API 백엔드 프록시 호출 (CORS 우회)
    const url = `/api/system/binance-klines?symbol=${binanceSymbol}&interval=${interval}&limit=100`;
    const res = await authFetch(url);
    const json = await res.json();
    
    if (json.ok && Array.isArray(json.klines) && json.klines.length > 0) {
      const chartData = json.klines.map(k => ({
        time: Math.floor(k[0] / 1000) + (9 * 3600),  // UTC → KST (+9시간)
        open: parseFloat(k[1]),
        high: parseFloat(k[2]),
        low: parseFloat(k[3]),
        close: parseFloat(k[4]),
      }));
      
      chartData.sort((a, b) => a.time - b.time);
      binanceSeries.setData(chartData);
      binanceChart.timeScale().fitContent();
      
      // Cross-exchange diff (Bybit vs Binance)
      const coin = bybitMarket.replace(/USDT$/i, '');
      updateExchangePremium(coin, chartData[chartData.length - 1]?.close);
    }
  } catch (e) {
    console.error('loadBinanceChartData error:', e);
  }
}

// Exchange price diff display
function updateExchangePremium(coin, binancePrice) {
  const premiumEl = qs('binance-premium');
  if (!premiumEl || !binancePrice) return;

  const bybitPrice = state.prices?.[`${coin}USDT`];
  if (!bybitPrice) {
    premiumEl.textContent = '';
    return;
  }

  const premium = ((bybitPrice / binancePrice) - 1) * 100;

  const sign = premium >= 0 ? '+' : '';
  const color = premium >= 0 ? 'text-success' : 'text-danger';
  premiumEl.innerHTML = `<span class="${color}">Diff ${sign}${premium.toFixed(2)}%</span>`;
}

