// ================= LADDER STEP DETAIL MODAL (GridV2) ===================
async function showLadderStepModal(market) {
  const modal = new bootstrap.Modal(document.getElementById('ladderStepModal'));
  qs('ladder-step-modal-market').textContent = market;
  qs('ladder-step-list').innerHTML = `<tr><td colspan="8" class="text-center text-muted">${t('label.loading', 'Loading...')}</td></tr>`;
  qs('ladder-step-profit-summary').innerHTML = '';
  modal.show();
  try {
    const res = await authFetch(`/api/ladder/grid/state?market=${encodeURIComponent(market)}`);
    const data = await res.json();
    if (!data || !data.ok) {
      qs('ladder-step-list').innerHTML = '<tr><td colspan="8" class="text-center text-danger">No grid data</td></tr>';
      return;
    }
    const curPrice = data.current_price || 0;
    const cfg = data.config || {};
    const gstate = data.state || {};
    const steps = data.steps || [];
    const blocked = gstate.blocked || false;
    const pausedSet = new Set((gstate.paused_steps || []).map(Number));
    const skippedSet = new Set((gstate.skipped_steps || []).map(Number));
    let summaryHtml = `<b>${t('label.current_price', 'Current Price')}:</b> ${formatAmount(curPrice)} | <b>${t('label.step_budget', 'Step Budget')}:</b> ${fmtUsdt(cfg.order_usdt || 0)} | <b>${t('label.spacing', 'Spacing')}:</b> ${cfg.spacing_value || 0}%`;
    summaryHtml += ` | <b>${t('label.window', 'Window')}:</b> ±${gstate.active_window_n || 2}`;
    if (blocked) summaryHtml += ` | <span class="badge bg-danger">${t('status.blocked_downtrend', 'BLOCKED (Downtrend)')}</span>`;
    qs('ladder-step-profit-summary').innerHTML = summaryHtml;
    if (!steps.length) {
      qs('ladder-step-list').innerHTML = `<tr><td colspan="8" class="text-center text-muted">${t('empty.ladder_no_steps_sync', 'No steps - Run Grid Sync')}</td></tr>`;
      return;
    }
    // Filter steps: only show 'active', 'paused', or 'filled' (hide deleted/canceled)
    const visibleSteps = steps.filter(s => {
      const st = s.status || 'active';
      return st === 'active' || st === 'paused' || st === 'filled';
    });
    const sorted = visibleSteps.sort((a,b) => (b.price||0) - (a.price||0));
    qs('ladder-step-list').innerHTML = sorted.map((s, idx) => {
      const price = s.price || 0;
      const side = s.side || 'buy';
      const status = s.status || 'active';
      const isBuy = side === 'buy';
      const isPaused = pausedSet.has(price);
      const isSkipped = skippedSet.has(price);
      const isFilled = status === 'filled';
      const isNearCurrent = curPrice > 0 && price > 0 && Math.abs(price - curPrice) / curPrice < 0.03;
      let rowClass = '';
      if (isFilled) rowClass = 'bg-success bg-opacity-10';
      else if (isPaused) rowClass = 'bg-warning bg-opacity-10';
      else if (isNearCurrent) rowClass = 'bg-info bg-opacity-10';
      const typeBadge = isBuy ? '<span class="badge bg-success">Buy</span>' : '<span class="badge bg-danger">Sell</span>';
      let statusBadge = `<span class="badge bg-secondary">${t('badge.waiting', 'Waiting')}</span>`;
      if (isFilled) statusBadge = `<span class="badge bg-success">${t('badge.filled', 'Filled')}</span>`;
      else if (isPaused) statusBadge = `<span class="badge bg-warning text-dark">${t('badge.paused', 'Paused')}</span>`;
      else if (isSkipped) statusBadge = `<span class="badge bg-dark">${t('badge.skipped', 'Skipped')}</span>`;
      else if (status === 'active') statusBadge = `<span class="badge bg-primary">${t('badge.active', 'Active')}</span>`;
      const profitPct = curPrice > 0 && price > 0 ? ((curPrice / price - 1) * 100).toFixed(2) + '%' : '-';
      const ctrlBtns = isFilled ? '-' : `
        <button class="btn btn-xs btn-outline-warning" onclick="gridAction('${market}',${price},'pause')" title="${t('action.pause', 'Pause')}">⏸</button>
        <button class="btn btn-xs btn-outline-danger" onclick="gridAction('${market}',${price},'delete')" title="${t('action.delete', 'Delete')}">🗑</button>`;
      return `<tr class="${rowClass}">
        <td>${idx+1}</td>
        <td>${typeBadge}</td>
        <td>${formatAmount(price)}</td>
        <td>${fmtUsdt(cfg.order_usdt || 0)}</td>
        <td>${statusBadge}</td>
        <td>${isFilled ? '<span class="badge bg-primary">✓</span>' : '-'}</td>
        <td>${profitPct}</td>
        <td>${ctrlBtns}</td>
      </tr>`;
    }).join('');
  } catch (err) {
    qs('ladder-step-list').innerHTML = `<tr><td colspan="8" class="text-center text-danger">Error: ${err.message}</td></tr>`;
  }
}
async function gridAction(market, price, action) {
  const ep = action === 'delete' ? 'delete-step' : (action === 'pause' ? 'pause-step' : 'resume-step');
  try {
    await authFetch(`/api/ladder/grid/${ep}?market=${encodeURIComponent(market)}&price=${price}`, {method:'POST'});
    showLadderStepModal(market);
  } catch(e) { console.error('gridAction error', e); }
}
window.showLadderStepModal = showLadderStepModal;
window.gridAction = gridAction;

async function updateLadderStepStatus(market, uuid, status) {
  try {
    const res = await authFetch(`/api/ladder/step/status?market=${encodeURIComponent(market)}&step_uuid=${encodeURIComponent(uuid)}&status=${encodeURIComponent(status)}`, { method: 'POST' });
    const data = await res.json();
    if (data.ok) { showToast(t('toast.ladder_step_status_updated', 'Step status updated'), 'success'); showLadderStepModal(market); }
    else { showToast(data.error || t('toast.ladder_step_status_update_failed', 'Failed to update step status'), 'error'); }
  } catch (err) { showToast(`${t('toast.ladder_step_status_update_error', 'Step status update error')}: ${err.message}`, 'error'); }
}
window.updateLadderStepStatus = updateLadderStepStatus;

async function deleteLadderStep(market, uuid) {
  if (!confirm(t('confirm.delete_ladder_step', 'Are you sure you want to delete this step?'))) return;
  try {
    const res = await authFetch(`/api/ladder/step/delete?market=${encodeURIComponent(market)}&step_uuid=${encodeURIComponent(uuid)}`, { method: 'POST' });
    const data = await res.json();
    if (data.ok) { showToast(t('toast.ladder_step_delete_success', 'Step deleted'), 'success'); showLadderStepModal(market); }
    else { showToast(data.error || t('toast.ladder_step_delete_failed', 'Delete failed'), 'error'); }
  } catch (err) { showToast(`${t('toast.ladder_step_delete_error', 'Delete error')}: ${err.message}`, 'error'); }
}
window.deleteLadderStep = deleteLadderStep;

// ============================================================
// Loading State Management
// ============================================================

let loadingCount = 0;

function showLoading() {
  loadingCount++;
  const el = qs('global-loading');
  if (el) el.classList.remove('d-none');
}

function hideLoading() {
  loadingCount = Math.max(0, loadingCount - 1);
  if (loadingCount === 0) {
    const el = qs('global-loading');
    if (el) el.classList.add('d-none');
  }
}

function withLoading(promise) {
  showLoading();
  return promise.finally(() => hideLoading());
}

function escHtml(s) {
  return String(s ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');
}

function renderTableSkeleton(rows = 5, cols = 4) {
  return `
    <table class="table table-sm">
      <tbody>
        ${Array(rows).fill(0).map(() => `
          <tr>
            ${Array(cols).fill(0).map(() => `
              <td><div class="placeholder-glow"><span class="placeholder col-8"></span></div></td>
            `).join('')}
          </tr>
        `).join('')}
      </tbody>
    </table>
  `;
}

function renderListSkeleton(items = 5) {
  return Array(items).fill(0).map(() => `
    <div class="list-group-item">
      <div class="placeholder-glow">
        <span class="placeholder col-6"></span>
        <span class="placeholder col-4 ms-2"></span>
      </div>
    </div>
  `).join('');
}

// ============================================================
// Utilities
// ============================================================
function formatNumber(n) {
  if (n == null || isNaN(n)) return '-';
  return Math.round(n).toLocaleString();
}

function formatAmount(n) {
  if (n == null || isNaN(n)) return '$-';
  return '$' + Number(n).toLocaleString('en-US', {minimumFractionDigits: 2, maximumFractionDigits: 2});
}

function formatPercent(n, decimals = 2) {
  if (n == null || isNaN(n)) return '-';
  const sign = n >= 0 ? '+' : '';
  return sign + n.toFixed(decimals) + '%';
}

function extractBase(market) {
  if (!market) return '';
  return market.replace(/USDT$/i,'');
}

function normMarket(market) {
  if (!market) return '';
  let m = market.toUpperCase().trim();
  if (!m.endsWith('USDT')) m = m + 'USDT';
  return m;
}

function getStrategyBadgeClass(strategy) {
  const map = {
    'LADDER': 'badge-strategy ladder',
    'LIGHTNING': 'badge-strategy lightning',
    'GAZUA': 'badge-strategy gazua',
    'CONTRARIAN': 'badge-strategy contrarian',
    'PINGPONG': 'badge-strategy pingpong',
    'AUTOLOOP': 'badge-strategy autoloop',
    'SNIPER': 'badge-strategy sniper',
    'SNIPER(S)': 'badge-strategy sniper',
    'WHALE': 'badge-strategy whale',
    'FOCUS': 'badge-strategy focus',
    'AI': 'badge-strategy'
  };
  return map[strategy?.toUpperCase()] || 'badge-strategy';
}

function getPnlClass(pnl) {
  if (pnl > 0) return 'profit-positive';
  if (pnl < 0) return 'profit-negative';
  return '';
}

function showToast(message, type = 'info') {
  const adminMsg = qs('admin-msg');
  if (adminMsg) {
    adminMsg.textContent = message;
    adminMsg.className = `text-${type === 'error' ? 'danger' : type === 'success' ? 'success' : 'muted'} small`;
  }
  console.log(`[${type}] ${message}`);
  addNotification(message, type);
}

// ============================================================
// Notification History
// ============================================================

const MAX_NOTIFICATIONS = 50;
let notifications = [];

function addNotification(message, type = 'info') {
  const notif = {
    id: Date.now(),
    message,
    type,
    time: new Date().toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' }),
    read: false
  };
  
  notifications.unshift(notif);
  if (notifications.length > MAX_NOTIFICATIONS) {
    notifications = notifications.slice(0, MAX_NOTIFICATIONS);
  }
  
  renderNotifications();
}

function renderNotifications() {
  const list = qs('notif-list');
  const count = qs('notif-count');
  if (!list) return;
  
  const unread = notifications.filter(n => !n.read).length;
  
  if (count) {
    count.textContent = unread;
    count.style.display = unread > 0 ? 'inline-block' : 'none';
  }
  
  if (!notifications.length) {
    list.innerHTML = `<div class="dropdown-item text-muted text-center">${t('label.no_notifications', 'No Notifications')}</div>`;
    return;
  }
  
  const typeIcons = {
    success: 'ti-check text-success',
    error: 'ti-x text-danger',
    warning: 'ti-alert-triangle text-warning',
    info: 'ti-info-circle text-info'
  };
  
  list.innerHTML = notifications.slice(0, 20).map(n => `
    <div class="dropdown-item d-flex gap-2 ${n.read ? 'text-muted' : ''}" onclick="markNotificationRead(${n.id})">
      <i class="ti ${typeIcons[n.type] || 'ti-bell'}"></i>
      <div class="flex-fill">
        <div class="small">${n.message}</div>
        <div class="text-muted" style="font-size: 10px;">${n.time}</div>
      </div>
    </div>
  `).join('');
}

function markNotificationRead(id) {
  const notif = notifications.find(n => n.id === id);
  if (notif) notif.read = true;
  renderNotifications();
}

function clearNotifications() {
  notifications = [];
  renderNotifications();
}

window.clearNotifications = clearNotifications;
window.markNotificationRead = markNotificationRead;

// ============================================================
// Formatting Utilities
// ============================================================

function fmtUsdt(v) {
  if (v == null || !Number.isFinite(v)) return '—';
  const abs = Math.abs(v);
  const sign = v < 0 ? '-' : '';
  if (abs >= 1e6) return sign + (abs / 1e6).toFixed(2) + 'M USDT';
  if (abs >= 1e3) return sign + (abs / 1e3).toFixed(1) + 'K USDT';
  return sign + abs.toFixed(2) + ' USDT';
}

function fmtPct(v) {
  if (v == null || !Number.isFinite(v)) return '—';
  const sign = v >= 0 ? '+' : '';
  return sign + v.toFixed(2) + '%';
}

function numOr(v, d = 0) {
  return Number.isFinite(v) ? v : d;
}

// ============================================================
// Strategy Badge Rendering
// ============================================================

function renderStrategyBadge(strategy) {
  const colors = {
    'LADDER': 'bg-success',
    'LIGHTNING': 'bg-warning',
    'GAZUA': 'bg-danger',
    'CONTRARIAN': 'bg-purple',
    'PINGPONG': 'bg-secondary',
    'AUTOLOOP': 'bg-info',
    'LONGHOLD': 'bg-orange',
    'AI': 'bg-dark',
    'OFF': 'bg-muted'
  };
  const cls = colors[strategy?.toUpperCase()] || 'bg-secondary';
  return `<span class="badge ${cls}">${strategy || '—'}</span>`;
}

// ============================================================
// Indicator Badges
// ============================================================

function renderIndicatorBadges(item) {
  if (!item) return '';
  const badges = [];
  
  // RSI
  if (item.rsi != null) {
    const rsiClass = item.rsi < 30 ? 'bg-danger' : (item.rsi > 70 ? 'bg-success' : 'bg-secondary');
    badges.push(`<span class="badge ${rsiClass} badge-sm">RSI ${item.rsi}</span>`);
  }
  
  // MACD
  if (item.macd_signal) {
    const macdClass = item.macd_signal === 'BUY' ? 'bg-success' : (item.macd_signal === 'SELL' ? 'bg-danger' : 'bg-secondary');
    badges.push(`<span class="badge ${macdClass} badge-sm">MACD ${item.macd_signal}</span>`);
  }
  
  // Volume
  if (item.volume_score != null) {
    badges.push(`<span class="badge bg-info badge-sm">Vol ${item.volume_score}</span>`);
  }
  
  return badges.join(' ');
}

// ============================================================
// Upside Potential Calculation
// ============================================================

function calcUpsidePotential(brain) {
  if (!brain) return null;
  const tp = brain.tp_target || brain.take_profit_price;
  const current = brain.current_price || brain.price;
  if (!tp || !current || current <= 0) return null;
  return ((tp - current) / current) * 100;
}

function renderPositionGauge(potential) {
  if (potential == null) return '';
  const pct = Math.min(100, Math.max(0, potential));
  const color = pct > 5 ? '#10b981' : (pct > 2 ? '#f59e0b' : '#ef4444');
  return `
    <div class="progress" style="height: 4px;">
      <div class="progress-bar" style="width: ${pct}%; background: ${color};"></div>
    </div>
    <span class="small text-muted">${potential.toFixed(1)}%</span>
  `;
}

// ============================================================
// Page Navigation
// ============================================================
const STRATEGY_DETAIL_POLL_FAST_MS = 2000;
const STRATEGY_DETAIL_POLL_SLOW_MS = 30000;
const LONGSHORT_DETAIL_POLL_FAST_MS = 3000;
const STRATEGY_DETAIL_PAGES = new Set([
  'strategy-ladder',
  'strategy-lightning',
  'strategy-gazua',
  'strategy-contrarian',
  'strategy-sniper',
  'strategy-pingpong',
  'strategy-autoloop',
  'strategy-longshort',
]);
let _strategyDetailPollTimer = null;
let _strategyDetailPollIntervalMs = 0;
let _strategyDetailPollBusy = false;

function isStrategyDetailPage(pageName = state.currentPage) {
  return STRATEGY_DETAIL_PAGES.has(String(pageName || ''));
}

function getStrategyDetailPollIntervalMs(pageName = state.currentPage) {
  if (!isStrategyDetailPage(pageName)) return 0;
  if (document.visibilityState === 'visible' && pageName === 'strategy-longshort') {
    return LONGSHORT_DETAIL_POLL_FAST_MS;
  }
  return document.visibilityState === 'visible'
    ? STRATEGY_DETAIL_POLL_FAST_MS
    : STRATEGY_DETAIL_POLL_SLOW_MS;
}

async function runStrategyDetailPollOnce(pageName = state.currentPage) {
  if (_strategyDetailPollBusy) return;
  if (!isStrategyDetailPage(pageName)) return;
  _strategyDetailPollBusy = true;
  try {
    switch (pageName) {
      case 'strategy-ladder':
        // 2026-03-10: 개별 호출 — 하나가 느려도 나머지는 표시
        fetchStrategyList('ladder');
        loadCircuitBreakerStatus().catch(() => {});
        refreshIcagMarketList().catch(() => {});
        break;
      case 'strategy-lightning':
        await fetchStrategyList('lightning');
        break;
      case 'strategy-gazua':
        await fetchStrategyList('gazua');
        break;
      case 'strategy-contrarian':
        await fetchStrategyList('contrarian');
        break;
      case 'strategy-sniper':
        await fetchStrategyList('sniper');
        break;
      case 'strategy-pingpong':
      case 'strategy-autoloop':
        await Promise.all([fetchActiveMarkets(), fetchReserved()]);
        break;
      case 'strategy-longshort':
        await refreshActiveSlots();
        break;
      default:
        break;
    }
  } finally {
    _strategyDetailPollBusy = false;
  }
}

function restartStrategyDetailPolling({ immediate = false } = {}) {
  const pageName = state.currentPage;
  const intervalMs = getStrategyDetailPollIntervalMs(pageName);
  if (intervalMs <= 0) {
    if (_strategyDetailPollTimer) clearInterval(_strategyDetailPollTimer);
    _strategyDetailPollTimer = null;
    _strategyDetailPollIntervalMs = 0;
    return;
  }

  if (!_strategyDetailPollTimer || _strategyDetailPollIntervalMs !== intervalMs) {
    if (_strategyDetailPollTimer) clearInterval(_strategyDetailPollTimer);
    _strategyDetailPollIntervalMs = intervalMs;
    _strategyDetailPollTimer = setInterval(() => {
      const desiredMs = getStrategyDetailPollIntervalMs(state.currentPage);
      if (desiredMs !== _strategyDetailPollIntervalMs) {
        restartStrategyDetailPolling();
        return;
      }
      runStrategyDetailPollOnce(state.currentPage);
    }, intervalMs);
  }

  if (immediate) runStrategyDetailPollOnce(pageName);
}

document.addEventListener('visibilitychange', () => {
  if (!isStrategyDetailPage(state.currentPage)) return;
  restartStrategyDetailPolling({ immediate: document.visibilityState === 'visible' });
});

function showPage(pageName) {
  // 이전 전략 페이지의 자동 검색 중지
  ['ladder', 'lightning', 'gazua', 'contrarian', 'sniper'].forEach(s => {
    stopStrategyAutoSearch(s);
  });
  // LADDER 전용 폴링 정리
  if (window._ladderPollTimer) { clearInterval(window._ladderPollTimer); window._ladderPollTimer = null; }
  // Precision Scope는 페이지 이탈 시에도 유지 (사용자 요청)
  stopAutoScan();
  
  state.currentPage = pageName;
  
  // 페이지 전환 시 모바일 사이드바 닫기
  closeMobileSidebar();
  
  // Hide all pages
  qsa('.page-content').forEach(p => {
    p.classList.remove('active');
    p.style.display = 'none';
  });
  
  // Show selected page
  const pageEl = qs('page-' + pageName);
  if (pageEl) {
    pageEl.classList.add('active');
    pageEl.style.display = 'block';
  }
  
  // Update title (i18n-aware)
  const titles = getPageTitles();
  const titleEl = qs('page-title');
  if (titleEl) titleEl.textContent = titles[pageName] || pageName;
  
  // Update nav active state
  qsa('[data-page]').forEach(el => {
    el.classList.remove('active');
    if (el.dataset.page === pageName) {
      el.classList.add('active');
    }
  });
  
  // Load page-specific data
  loadPageData(pageName);
  restartStrategyDetailPolling();
  maybeAutoRecommendForCurrentPage('page_enter').catch(() => {});
}

