async function fetchSystemStatus() {
  try {
    const res = await authFetch(API.systemStatus);
    if (!res.ok) return;
    const data = await res.json();
    state.system = data;
    updateHeaderStats(data);
    updateEngineStatus(data);
  } catch (err) {
    console.error('시스템 상태 조회 실패:', err);
  }
}

async function fetchActiveMarkets() {
  try {
    // Fetch both manager markets and system status for strategy info
    const [marketsRes, statusRes] = await Promise.all([
      authFetch(API.managerMarkets),
      authFetch(API.systemStatus)
    ]);
    const marketsData = await marketsRes.json();
    const statusData = await statusRes.json();
    
    // Combine watch, active, recovery arrays
    const watch = marketsData.watch || [];
    const active = marketsData.active || [];
    const recovery = marketsData.recovery || [];
    const omaByMarket = new Map();
    const putOma = (items, stateName) => {
      for (const item of items) {
        const market = (typeof item === 'string') ? item : item?.market;
        if (!market) continue;
        const prev = omaByMarket.get(market) || {};
        const merged = (typeof item === 'object')
          ? { ...prev, ...item, market, _state: stateName }
          : { ...prev, market, _state: stateName };
        omaByMarket.set(market, merged);
      }
    };
    putOma(active, 'ACTIVE');
    putOma(recovery, 'RECOVERY');
    putOma(watch, 'WATCH');
    const omaMarketSet = new Set(Array.from(omaByMarket.keys()));
    
    // Get contexts from system status for strategy info
    // API returns contexts under 'coordinator' key
    const contexts = statusData.system?.coordinator || statusData.system?.contexts || {};
    
    // 2026-01-30: coordinator 기반으로 마켓 리스트 구성 (더 정확함)
    // coordinator에는 실제 활성 마켓 컨텍스트가 있음
    const activePrices = statusData.system?.active_prices || {};
    
    const coordinatorMarkets = Object.keys(contexts)
      .filter(k => !k.startsWith('_'))  // _oma_defensive 등 내부 키 제외
      .filter(market => {
        // Only show OMA-managed markets, except markets that still have holdings.
        const ctx = contexts[market] || {};
        const posQty = Number(ctx?.position?.qty || 0);
        return omaMarketSet.has(market) || posQty > 0;
      })
      .map(market => {
        const ctx = contexts[market] || {};
        const strategyState = ctx.strategy || ctx.strategy_state || {};
        const controls = ctx.controls || {};
        const strategyCtrl = controls.strategy || {};
        const strategyEnabled = !!strategyCtrl.enabled;
        const strategyMode = strategyEnabled ? (strategyCtrl.mode || '') : '';
        const omaEntry = omaByMarket.get(market);
        const marketState = (omaEntry?._state || ctx.market_state || 'WATCH').toUpperCase();
        
        // 가격: active_prices > price_tail > 0
        const currentPrice = activePrices[market] || ctx.price_tail?.[ctx.price_tail?.length - 1] || 0;
        const entryPrice = ctx.position?.entry || 0;
        const pnlPct = (currentPrice > 0 && entryPrice > 0) 
          ? ((currentPrice / entryPrice) - 1) * 100 
          : 0;
        
        // OMA 데이터에서 budget, strategy 가져오기
        const budgetUsdt = typeof omaEntry === 'object' ? omaEntry.budget_usdt : null;
        const omaStrategy = typeof omaEntry === 'object' ? (omaEntry.strategy || '') : '';
        const omaReason = typeof omaEntry === 'object' ? (omaEntry.reason || []) : [];
        const fallbackStrategy = strategyEnabled
          ? (strategyState.selected || ctx.strategy || '')
          : '';
        
        // ctx.strategy: coordinator가 strategy_mode 우선 반환 (SNIPER(S) 구분 포함)
        const coordinatorStrategy = (typeof ctx.strategy === 'string' && ctx.strategy) ? ctx.strategy : '';
        
        const pos = ctx.position || {};
        const entryTs = parseFloat(pos.entry_ts || pos.ts || 0) || 0;
        const holdHours = entryTs > 0 ? (Date.now() / 1000 - entryTs) / 3600 : null;
        return {
          market: market,
          state: marketState,
          strategy: (coordinatorStrategy || strategyMode || omaStrategy || fallbackStrategy || '').toUpperCase(),
          current_price: currentPrice,
          entry_price: entryPrice,
          pnl_pct: pnlPct,
          readiness: ctx.readiness || null,
          position: ctx.position || null,
          context: ctx,
          budget_usdt: budgetUsdt || ctx.allocated_capital || 0,
          oma_reason: omaReason,
          allocated_capital: ctx.allocated_capital || 0,
          unrealized_profit: ctx.unrealized_profit || 0,
          hold_hours: holdHours,
        };
      });
    
    const allMarkets = coordinatorMarkets;
    

    
    state.managedMarkets = allMarkets;
    
    // Store prices from market data
    state.managedMarkets.forEach(m => {
      if (m.current_price) {
        state.prices[m.market] = {
          price: m.current_price,
          change_pct: m.change_pct || 0,
          pnl_pct: m.pnl_pct || 0
        };
      }
    });
    
    renderActiveMarkets(state.managedMarkets);
    renderMarketsTable(state.managedMarkets);
    updateSortableTableData('active-markets-table', state.managedMarkets);
    renderOmaMarketList(state.managedMarkets);
    renderPriceGrid();
    updateMarketDatalist(state.managedMarkets);
    ensureMarketDatalist();
    updateChartMarketOptions();  // 차트 마켓 옵션 업데이트
    populateQuickTradeMarkets();  // 2026-03-10: Quick Trade 드롭다운 갱신
    
    // Update strategy-specific lists
    // PINGPONG/AUTOLOOP는 ACTIVE만 표기 (WATCH/RECOVERY 잔상 제거)
    const activeOnly = state.managedMarkets.filter(
      (m) => String(m.state || '').toUpperCase() === 'ACTIVE'
    );
    renderStrategyMarkets('pingpong', activeOnly.filter(m => m.strategy === 'PINGPONG'));
    renderStrategyMarkets('autoloop', activeOnly.filter(m => m.strategy === 'AUTOLOOP'));
    renderWhaleMarkets(activeOnly.filter(m => m.strategy === 'WHALE'));
    // LADDER/LIGHTNING/GAZUA/CONTRARIAN/SNIPER는 전용 API(fetchStrategyList)로만 렌더
    
    // Update manual trade select
    if (typeof updateManualMarketSelect === 'function') {
      updateManualMarketSelect();
      updateBatchHints();
    }

    maybeAutoRecommendForCurrentPage('slot_change').catch(() => {});
  } catch (err) {
    console.error('Active 마켓 조회 실패:', err);
  }
}

