// ── Capital-based Auto Slot Allocation ──
function computeAutoSlots(equity) {
  let total;
  if (equity < 100) total = 2;
  else if (equity < 500) total = 4;
  else if (equity < 2000) total = 8;
  else if (equity < 10000) total = 12;
  else total = 20;

  const weights = {
    PINGPONG: 1.0, AUTOLOOP: 1.1, LADDER: 1.4, LIGHTNING: 0.7,
    GAZUA: 1.2, CONTRARIAN: 0.8, SNIPER: 0.9, WHALE: 0.8
  };
  const sumW = Object.values(weights).reduce((a, b) => a + b, 0);
  const raw = {};
  let assigned = 0;
  for (const [s, w] of Object.entries(weights)) {
    raw[s] = Math.floor(total * w / sumW);
    assigned += raw[s];
  }
  let remainder = total - assigned;
  const fracs = Object.entries(weights)
    .map(([s, w]) => ({ s, frac: (total * w / sumW) - Math.floor(total * w / sumW) }))
    .sort((a, b) => b.frac - a.frac);
  for (const { s } of fracs) {
    if (remainder <= 0) break;
    raw[s]++;
    remainder--;
  }
  if (total >= 2) {
    const prot = ['PINGPONG', 'AUTOLOOP'];
    for (const key of prot) {
      if ((raw[key] || 0) < 1) {
        const donor = Object.entries(raw)
          .filter(([s]) => !prot.includes(s) && raw[s] > 0)
          .sort((a, b) => b[1] - a[1])[0];
        if (donor) { raw[donor[0]]--; raw[key] = 1; }
      }
    }
  }
  raw.SNIPER = Math.min(raw.SNIPER || 0, 10);
  raw.CONTRARIAN = Math.min(raw.CONTRARIAN || 0, 10);
  raw.WHALE = Math.min(raw.WHALE || 0, 10);
  return raw;
}

function applyAutoSlotUI(on) {
  const ids = ['rs-pingpong-n','rs-autoloop-n','rs-ladder-n','rs-lightning-n',
               'rs-gazua-n','rs-contrarian-n','rs-sniper-n','rs-whale-n'];
  const map = { PINGPONG:'rs-pingpong-n', AUTOLOOP:'rs-autoloop-n', LADDER:'rs-ladder-n',
                LIGHTNING:'rs-lightning-n', GAZUA:'rs-gazua-n', CONTRARIAN:'rs-contrarian-n',
                SNIPER:'rs-sniper-n', WHALE:'rs-whale-n' };
  const label = document.getElementById('auto-slot-equity-label');
  if (on) {
    const equity = parseFloat((state.reservedSettings || {}).equity_usdt || 0);
    const slots = computeAutoSlots(equity);
    for (const [s, id] of Object.entries(map)) {
      const el = document.getElementById(id);
      if (el) { el.value = slots[s] || 0; el.disabled = true; el.classList.add('bg-light', 'text-muted'); }
    }
    const totalSlots = Object.values(slots).reduce((a, b) => a + b, 0);
    if (label) label.textContent = `Equity: $${equity.toFixed(0)} → ${totalSlots} slots ($${totalSlots > 0 ? (equity / totalSlots).toFixed(0) : 0}/slot)`;
  } else {
    ids.forEach(id => {
      const el = document.getElementById(id);
      if (el) { el.disabled = false; el.classList.remove('bg-light', 'text-muted'); }
    });
    if (label) label.textContent = '';
  }
}

const AUTO_RECOMMEND_COOLDOWN_MS = 60000;
const autoRecommendState = {
  inFlight: {},
  lastTs: {},
  prevShortage: {},
};
const RESERVED_CANDIDATES_TTL_MS = 120000;
let reservedCandidatesLastLoadedTs = 0;
let reservedCandidatesLoading = false;
const AUTO_RECOMMEND_SETTINGS_RETRY_MS = 5000;
let autoRecommendSettingsLoading = null;
let autoRecommendSettingsLastAttemptTs = 0;

function _slotInt(v, fallback = 0) {
  const n = parseInt(v, 10);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(0, n);
}

function _currentSystemSnapshot() {
  return (state.system && (state.system.system || state.system)) || {};
}

function _systemReservedSnapshot() {
  const sys = _currentSystemSnapshot();
  const reserved = sys?.reserved || sys?.reserved_settings || sys?.reservedSettings || {};
  return (reserved && typeof reserved === 'object') ? reserved : {};
}

function _systemGuardsSnapshot() {
  const sys = _currentSystemSnapshot();
  const fromStatus = (sys && sys.guards) || {};
  const guardsApi = state.guards || {};
  const fromGuardsApi = guardsApi?.guards || guardsApi?.global || guardsApi;
  return { ...(fromGuardsApi || {}), ...(fromStatus || {}) };
}

function _pickConfiguredSlot(...values) {
  for (const v of values) {
    if (v === undefined || v === null) continue;
    if (typeof v === 'string' && v.trim() === '') continue;
    return _slotInt(v, 0);
  }
  return 0;
}

async function ensureReservedSettingsLoadedForAuto() {
  if (state.reservedSettingsLoaded && state.reservedSettings) return true;
  const now = Date.now();
  if (autoRecommendSettingsLoading) return autoRecommendSettingsLoading;
  if ((now - autoRecommendSettingsLastAttemptTs) < AUTO_RECOMMEND_SETTINGS_RETRY_MS) return false;

  autoRecommendSettingsLastAttemptTs = now;
  autoRecommendSettingsLoading = (async () => {
    try {
      const res = await authFetch(API.reservedSettings);
      if (!res.ok) return false;
      const data = await res.json();
      if (data?.ok === false) return false;
      const settings = data.settings || data;
      if (!settings || typeof settings !== 'object') return false;
      state.reservedSettings = settings;
      state.reservedSettingsLoaded = settings.pingpong_n != null;
      return !!state.reservedSettingsLoaded;
    } catch (_) {
      return false;
    } finally {
      autoRecommendSettingsLoading = null;
    }
  })();

  return autoRecommendSettingsLoading;
}

function getStrategySlotTarget(strategy) {
  const su = String(strategy || '').trim().toUpperCase();
  const settings = state.reservedSettings || {};
  const sys = _currentSystemSnapshot();
  const reserved = _systemReservedSnapshot();
  const guards = _systemGuardsSnapshot();
  const bind = STRATEGY_SLOT_BINDINGS[su];
  if (!bind) return 0;

  const slot = _pickConfiguredSlot(
    settings[bind.settingKey],
    reserved[bind.settingKey],
    reserved[bind.guardKey],
    sys[bind.settingKey],
    sys[bind.guardKey],
    guards[bind.guardKey],
    qs(bind.inputId)?.value,
  );

  if (su === 'SNIPER') {
    const snipersSlot = _pickConfiguredSlot(
      settings.snipers_n,
      settings.scope_target_n,
      reserved.snipers_n,
      reserved.scope_target_n,
      sys.snipers_n,
      sys.scope_target_n,
      sys.autopilot_scope_target_n,
      guards.autopilot_scope_target_n,
      qs('rs-snipers-n')?.value,
    );
    return Math.max(slot, snipersSlot);
  }

  return slot;
}

function isStrategySlotConfigured(strategy) {
  return getStrategySlotTarget(strategy) > 0;
}

function getConfiguredStrategies(strategies) {
  const list = Array.isArray(strategies) ? strategies : [];
  return list.filter((s) => isStrategySlotConfigured(s));
}

function getCandidateStrategyFromPage(pageName = state.currentPage) {
  switch (String(pageName || '')) {
    case 'strategy-ladder':
      return 'LADDER';
    case 'strategy-lightning':
      return 'LIGHTNING';
    case 'strategy-gazua':
      return 'GAZUA';
    case 'strategy-contrarian':
      return 'CONTRARIAN';
    case 'strategy-sniper':
      return 'SNIPER';
    default:
      return '';
  }
}

function _normalizeActiveStrategyName(raw) {
  const s = String(raw || '').trim().toUpperCase();
  if (!s) return '';
  if (s === 'SNIPER(S)' || s === 'SNIPERS') return 'SNIPER';
  return s;
}

function countActiveByStrategy(strategy) {
  const su = String(strategy || '').trim().toUpperCase();
  if (!su) return 0;
  const rows = Array.isArray(state.managedMarkets) ? state.managedMarkets : [];
  let n = 0;
  rows.forEach((row) => {
    const st = String(row?.state || '').trim().toUpperCase();
    if (st !== 'ACTIVE' && st !== 'RECOVERY') return;
    const rs = _normalizeActiveStrategyName(row?.strategy);
    if (rs === su) n += 1;
  });
  return n;
}

function hasStrategySlotShortage(strategy) {
  const su = String(strategy || '').trim().toUpperCase();
  const target = getStrategySlotTarget(su);
  if (target <= 0) return false;
  return countActiveByStrategy(su) < target;
}

async function maybeAutoRecommendForCurrentPage(reason = 'slot_change') {
  const su = getCandidateStrategyFromPage(state.currentPage);
  if (!su) return;
  await ensureReservedSettingsLoadedForAuto();
  if (!isStrategySlotConfigured(su)) {
    autoRecommendState.prevShortage[su] = false;
    return;
  }

  const shortage = hasStrategySlotShortage(su);
  const prev = !!autoRecommendState.prevShortage[su];
  autoRecommendState.prevShortage[su] = shortage;
  if (!shortage) return;
  if (reason !== 'page_enter' && prev) return;

  const key = su;
  const now = Date.now();
  if (autoRecommendState.inFlight[key]) return;
  if ((now - (autoRecommendState.lastTs[key] || 0)) < AUTO_RECOMMEND_COOLDOWN_MS) return;

  autoRecommendState.inFlight[key] = true;
  autoRecommendState.lastTs[key] = now;
  try {
    await loadCandidates(su.toLowerCase());
  } catch (err) {
    console.warn(`[AutoRecommend] ${su} ${reason} failed:`, err);
  } finally {
    autoRecommendState.inFlight[key] = false;
  }
}

async function loadAllReservedCandidates(options = {}) {
  await ensureReservedSettingsLoadedForAuto();
  const force = !!options.force;
  const now = Date.now();
  if (!force && reservedCandidatesLoading) return;
  if (!force && (now - reservedCandidatesLastLoadedTs) < RESERVED_CANDIDATES_TTL_MS) return;

  const allStrategies = ['PINGPONG', 'AUTOLOOP', 'GAZUA', 'LADDER', 'LIGHTNING', 'CONTRARIAN', 'SNIPER'];
  const strategies = getConfiguredStrategies(allStrategies);
  if (!strategies.length) {
    allStrategies.forEach((s) => {
      const container = qs(`reserved-${s.toLowerCase()}-list`);
      if (container) {
        container.innerHTML = `<div class="text-center text-muted p-3">${t('empty.no_recommendations', 'No recommendations')}</div>`;
      }
    });
    return;
  }

  reservedCandidatesLoading = true;
  try {
    await Promise.all(strategies.map(s => loadReservedCandidates(s)));
    reservedCandidatesLastLoadedTs = Date.now();
  } finally {
    reservedCandidatesLoading = false;
  }
}

async function loadReservedCandidates(strategy) {
  if (!isStrategySlotConfigured(strategy)) return;
  const listId = `reserved-${strategy.toLowerCase()}-list`;
  const container = qs(listId);
  if (!container) return;
  
  container.innerHTML = `<div class="text-center text-muted p-3"><div class="spinner-border spinner-border-sm me-2"></div>${t('label.loading', 'Loading...')}</div>`;
  
  try {
    const res = await authFetch(API.recommendations(strategy, 8));
    const data = await res.json();
    
    if (!data.ok || !data.items?.length) {
      container.innerHTML = `<div class="text-center text-muted p-3">${t('empty.no_recommendations', 'No recommendations')}</div>`;
      return;
    }
    
    // ACTIVE/RECOVERY만 '사용중'으로 간주하고 WATCH는 후보 노출
    const occupiedMarkets = new Set(
      state.managedMarkets
        .filter(m => {
          const st = String(m.state || '').toUpperCase();
          return st === 'ACTIVE' || st === 'RECOVERY';
        })
        .map(m => m.market)
    );
    const visibleItems = data.items.filter(c => !occupiedMarkets.has(c.market));
    if (!visibleItems.length) {
      container.innerHTML = `<div class="text-center text-muted p-3">${t('status.all_active', 'All Active')}</div>`;
      return;
    }
    
    // 권장 파라미터 캐시에 저장
    state.recommendedParamsCache = state.recommendedParamsCache || {};
    visibleItems.forEach(c => {
      const cacheKey = `${strategy}:${c.market}`;
      state.recommendedParamsCache[cacheKey] = c.recommended_params || {};
    });
    
    container.innerHTML = visibleItems.map((c, idx) => {
      const meta = c.metrics || c.meta || {};
      // API 응답에서 rsi, change_rate는 최상위에 있음
      const aiScore = c.ai_score ?? meta.ai_score ?? 0;
      const rsi = c.rsi ?? meta.rsi ?? 50;
      const change24h = c.change_rate ?? c.change_24h ?? meta.change_24h ?? 0;
      const budget = c.suggested_budget_usdt || 100;
      const rec = c.recommended_params || {};
      
      const scoreClass = aiScore >= 0.6 ? 'text-success' : (aiScore < 0.4 ? 'text-danger' : 'text-warning');
      const rsiClass = rsi < 35 ? 'text-success' : (rsi > 65 ? 'text-danger' : 'text-muted');
      const changeClass = change24h > 0 ? 'text-success' : (change24h < 0 ? 'text-danger' : '');
      const changeSign = change24h > 0 ? '+' : '';
      
      const rankBadge = idx < 3 ? `<span class="badge bg-${idx === 0 ? 'warning' : 'secondary'} me-1">${idx + 1}</span>` : '';
      const tpSlText = rec.tp_pct ? `TP${rec.tp_pct}%` : '';
      
      return `
        <div class="d-flex justify-content-between align-items-center p-2 border-bottom">
          <div class="flex-grow-1">
            <div class="d-flex align-items-center">
              ${rankBadge}
              <strong>${extractBase(c.market)}</strong>
              <span class="${changeClass} ms-2 small">${changeSign}${change24h.toFixed(1)}%</span>
            </div>
            <div class="small text-muted">
              ${c.confidence != null ? `<span class="${c.confidence >= 50 ? 'text-success' : c.confidence >= 30 ? 'text-warning' : 'text-danger'}"><b>신뢰 ${c.confidence.toFixed(0)}%</b></span>` : ''}
              <span class="${scoreClass} ms-2">AI ${(aiScore * 100).toFixed(0)}%</span>
              <span class="${rsiClass} ms-2">RSI ${rsi.toFixed(0)}</span>
              <span class="ms-2">$${formatNumber(budget)}</span>
              ${tpSlText ? `<span class="text-success ms-1">${tpSlText}</span>` : ''}
            </div>
          </div>
          <div>
            <button class="btn btn-success btn-sm" onclick="promoteWithParams('${c.market}', '${strategy}', ${budget})" title="${t('tooltip.promote_ai_recommended', 'Promote with AI recommended values')}"><i class="ti ti-arrow-up"></i></button>
          </div>
        </div>
      `;
    }).join('');
  } catch (err) {
    container.innerHTML = `<div class="text-center text-danger p-3">Error: ${err.message}</div>`;
  }
}

// ============================================================
// Reserved Snapshot (KST Basis)
// ============================================================

async function fetchReservedSnapshot() {
  const basis = qs('rs-basis')?.value || '07:00';
  const topn = parseInt(qs('rs-topn')?.value, 10) || 5;
  const force = qs('rs-force')?.checked ? 1 : 0;
  const body = qs('rs-table-body');
  if (body) body.innerHTML = `<tr><td colspan="10" class="text-center text-muted">${t('label.loading', 'Loading...')}</td></tr>`;
  
  try {
    const res = await authFetch(API.recommendSnapshot(basis, topn, force));
    const data = await res.json();
    if (!data.ok) {
      throw new Error(data.error || 'snapshot error');
    }
    state.reservedSnapshot = data;
    renderReservedSnapshot(data);
  } catch (err) {
    if (body) body.innerHTML = `<tr><td colspan="10" class="text-center text-danger">Error: ${err.message}</td></tr>`;
  }
}

function renderReservedSnapshot(data) {
  const body = qs('rs-table-body');
  if (!body) return;
  
  const metaEl = qs('rs-meta');
  if (metaEl) {
    const cachedTag = data.cached ? ' (cached)' : '';
    metaEl.textContent = tf(
      'reserved.snapshot_meta',
      'Basis {basis} KST / Date {date} / Created {created}{cached}',
      {
        basis: data.basis_kst,
        date: data.snapshot_date,
        created: data.created_at_kst,
        cached: cachedTag,
      },
    );
  }
  
  const items = data.items || [];
  if (!items.length) {
    body.innerHTML = `<tr><td colspan="10" class="text-center text-muted">${t('empty.no_recommendations', 'No recommendations')}</td></tr>`;
    return;
  }
  
  body.innerHTML = items.map((item, idx) => {
    const market = item.market || '-';
    const base = extractBase(market);
    const strategy = (item.strategy || '').toUpperCase();
    const aiScore = (item.ai_adjusted_score ?? item.ai_score ?? 0) * 100;
    const rsi = item.rsi ?? 50;
    const change = item.change_rate ?? 0;
    const vol = item.volatility ?? 0;
    const budget = item.suggested_budget_usdt ?? item.budget ?? 0;
    const paramsText = formatSnapshotParams(strategy, item.recommended_params || {});
    const active = item.active_strategy;
    const aiShouldBuy = item.ai_should_buy;
    
    const scoreClass = aiScore >= 60 ? 'text-success' : (aiScore < 40 ? 'text-danger' : 'text-warning');
    const rsiClass = rsi < 35 ? 'text-success' : (rsi > 65 ? 'text-danger' : 'text-muted');
    const changeClass = change > 0 ? 'text-success' : (change < 0 ? 'text-danger' : 'text-muted');
    const changeSign = change > 0 ? '+' : '';
    const rowClass = active ? 'table-secondary' : '';
    
    let statusHtml = '';
    if (active) statusHtml += `<span class="badge bg-info">${active}</span>`;
    if (aiShouldBuy === false) statusHtml += `${statusHtml ? ' ' : ''}<span class="badge bg-danger">BUY OFF</span>`;
    if (!statusHtml) statusHtml = '<span class="text-muted small">-</span>';
    
    return `
      <tr class="${rowClass}">
        <td>${idx + 1}</td>
        <td><strong>${base}</strong><div class="small text-muted">${market}</div></td>
        <td>${strategy || '-'}</td>
        <td class="${scoreClass}">${aiScore.toFixed(1)}%</td>
        <td class="${rsiClass}">${Number(rsi).toFixed(1)}</td>
        <td class="${changeClass}">${changeSign}${Number(change).toFixed(1)}%</td>
        <td>${Number(vol).toFixed(3)}</td>
        <td>$${formatNumber(budget)}</td>
        <td class="small text-muted">${paramsText}</td>
        <td>${statusHtml}</td>
      </tr>
    `;
  }).join('');
}

function formatSnapshotParams(strategy, params) {
  const fmt = (v, digits = 2) => {
    if (v === null || v === undefined || Number.isNaN(Number(v))) return '-';
    return Number(v).toFixed(digits).replace(/\.00$/, '');
  };
  if (!params || typeof params !== 'object') return '-';
  
  switch (strategy) {
    case 'LADDER':
      return `GAP ${fmt(params.step_pct, 2)}% · Steps ${params.steps ?? '-'} · TP ${fmt(params.tp_pct, 2)}%`;
    case 'LIGHTNING':
      return `TP ${fmt(params.tp_pct, 2)}% / SL ${fmt(params.sl_pct, 2)}%`;
    case 'GAZUA':
      return `TP ${fmt(params.tp_pct, 1)}% / SL ${fmt(params.sl_pct, 1)}%`;
    case 'CONTRARIAN':
      return `TP ${fmt(params.tp_pct, 1)}% / SL ${fmt(params.sl_pct, 1)}%`;
    case 'SNIPER':
      return `TP ${fmt(params.tp_pct, 1)}% / SL ${fmt(params.sl_pct, 1)}%`;
    case 'PINGPONG':
      return `TP ${fmt(params.tp_pct, 1)}% / SL ${fmt(params.sl_pct, 1)}%`;
    case 'AUTOLOOP':
      return `TP ${fmt(params.tp_pct, 1)}% · Steps ${params.steps ?? '-'}x`;
    default:
      return '-';
  }
}

  async function promoteToStrategy(market, strategy, budget, recommendedParams = null) {
    // recommendedParams: API에서 받은 권장 파라미터 (TP, SL, steps 등)
    const params = recommendedParams || {};
    const mkt = market.endsWith('USDT') ? market : `${market}USDT`;
    const used = state.managedMarkets.find(m => m.market === mkt);
    if (used) {
      const usedStrategy = used.strategy || used.state || t('status.in_use', 'In use');
      showToast(tf('toast.market_in_use', '{market} is already used by {strategy}. Release it first.', {
        market: extractBase(mkt),
        strategy: usedStrategy,
      }), 'warning');
      return;
    }
    
    // [안전필터] 최근 5분간 +2% 이상 급등 시 3분간 진입 보류 (LADDER만)
    if (strategy === 'LADDER') {
      const priceObj = state.prices[mkt];
      // 가격 히스토리(5분 전 가격)가 없으면 진입 자체 차단
      if (!priceObj || typeof priceObj.price_5min_ago !== 'number' || priceObj.price_5min_ago <= 0) {
        showToast(t('error.price_history_insufficient', 'Price history is insufficient. Entry is blocked by safety filter.'), 'error');
        return;
    }
    let recentChange = ((priceObj.price - priceObj.price_5min_ago) / priceObj.price_5min_ago) * 100;
    if (recentChange >= 2) {
      showToast(tf('warning.ladder_recent_spike_hold', 'Recent 5m spike +{pct}%! Entry is held for 3 minutes.', { pct: recentChange.toFixed(2) }), 'warning');
      setTimeout(() => showToast(t('info.ladder_retry_available', 'LADDER entry retry available'), 'info'), 180000);
      return;
    }
  }
  if (!confirm(tf(
    'confirm.promote_strategy',
    'Promote {market} to {strategy}?\nBudget: ${budget}\nTP: {tp}% / SL: {sl}%',
    {
      market: extractBase(market),
      strategy,
      budget: formatNumber(budget),
      tp: params.tp_pct || '-',
      sl: params.sl_pct || '-',
    },
  ))) return;
  
    try {
      let url, body;
      
      switch (strategy) {
      case 'PINGPONG':
        url = `/api/coordinator/add`;
        body = {
          market: mkt,
          strategy: strategy,
          budget_usdt: budget,
          tp_pct: params.tp_pct || 3,
          sl_pct: params.sl_pct || -2,
          buy_now: false
        };
        break;
      case 'AUTOLOOP':
        url = `/api/coordinator/add`;
        body = {
          market: mkt,
          strategy: strategy,
          budget_usdt: budget,
          tp_pct: params.tp_pct || 2.5,
          steps: params.steps || 5,
          buy_now: false
        };
        break;
      case 'GAZUA':
        url = `/api/strategy/gazua/setup`;
        body = {
          market: mkt,
          budget: budget,
          tp: params.tp_pct || 5,
          sl: params.sl_pct || -3,
          buy_now: false
        };
        break;
      case 'LADDER':
        url = `/api/strategy/ladder/setup`;
        // Always propagate order_usdt and grid_auto_sync from UI
        const orderInput = qs('lf-fixed-order-usdt');
        if (orderInput && !String(orderInput.value || '').trim()) {
          updateLadderOrderAmount('budget');
        }
          const gapMode = (qs('lf-gap-mode')?.value || 'PERCENT').toUpperCase();
          const gapInputRaw = parseFloat(qs('lf-gap')?.value);
          const gapInput = Number.isFinite(gapInputRaw) ? gapInputRaw : (params.step_pct || 0);
          const gapPrice = _getLadderPrice();
          const gapPct = (gapMode === 'USDT')
            ? ((gapPrice > 0 && gapInput > 0) ? (gapInput / gapPrice) * 100 : (params.step_pct || 0))
            : (params.step_pct || gapInput || 0);
          const orderUsdt = orderInput?.value ? Number(orderInput.value) : undefined;
          const gridAutoSync = qs('lf-autosync')?.checked;
          body = {
            market: mkt,
            budget_usdt: budget,
            max_steps: params.steps || 5,
            step_pct: gapPct || 2,
            tp: params.tp_pct || 3,
            use_atr: params.use_atr || false,
            martingale: params.martingale || 1.0,
            auto_center: qs('lf-auto-center')?.checked || false,
            spacing_mode: gapMode,
            spacing_value: gapInput || 0,
            emergency_last_step_enabled: qs('lf-emergency-last-step')?.checked || false,
            ...(orderUsdt !== undefined ? { order_usdt: orderUsdt } : {}),
            ...(typeof gridAutoSync === 'boolean' ? { grid_auto_sync: gridAutoSync } : {})
          };
        break;
      case 'LIGHTNING':
        url = `/api/strategy/lightning/setup`;
        body = {
          market: mkt,
          budget: budget,
          tp: params.tp_pct || 5,
          sl: params.sl_pct || -3
        };
        break;
      case 'CONTRARIAN':
        url = `/api/strategy/contrarian/setup`;
        body = {
          market: mkt,
          budget: budget,
          tp: params.tp_pct || 15,
          sl: params.sl_pct || -50,
          min_score: params.min_score || 2,
          cooldown_sec: params.cooldown_sec || 600,
          buy_now: false
        };
        break;
      case 'SNIPER':
        url = `/api/strategy/sniper/setup`;
        body = {
          market: mkt,
          budget: budget,
          tp_pct: params.tp_pct || 3,
          sl_pct: params.sl_pct || 2,
          entry_enabled: params.entry_enabled !== false,
          entry_lookback_min: params.entry_lookback_min || 360,
          entry_threshold_pct: params.entry_threshold_pct || 0.5,
          exit_enabled: params.exit_enabled !== false,
          exit_lookback_min: params.exit_lookback_min || 360,
          exit_threshold_pct: params.exit_threshold_pct || 0.5,
          trail_tp: params.trail_tp !== false,
          buy_now: false
        };
        break;
      default:
        showToast(tf('error.unsupported_strategy', 'Unsupported strategy: {strategy}', { strategy }), 'error');
        return;
    }
    
    const res = await authFetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    
    const data = await res.json();
    if (data.ok || data.success) {
      showToast(tf('toast.promote_success', '{market} -> {strategy} promoted', {
        market: extractBase(market),
        strategy,
      }), 'success');
      await Promise.all([fetchActiveMarkets(), fetchReserved()]);
    } else {
      showToast(tf('toast.promote_failed', 'Promote failed: {error}', {
        error: data.error || data.message || 'Unknown error',
      }), 'error');
    }
  } catch (err) {
    showToast(tf('toast.promote_error', 'Promote error: {error}', { error: err.message }), 'error');
  }
}

// 캐시된 권장 파라미터로 승격
function promoteWithParams(market, strategy, budget) {
  const cacheKey = `${strategy}:${market}`;
  const params = state.recommendedParamsCache?.[cacheKey] || {};
  promoteToStrategy(market, strategy, budget, params);
}

async function refreshReservedQueue() {
  const btn = event?.target?.closest('button');
  if (btn) btn.disabled = true;
  
  try {
    showToast(t('toast.market_scan_running', 'Scanning markets...'), 'info');
    const res = await authFetch('/api/reserved/refresh', { method: 'POST' });
    const data = await res.json();
    
    if (data.ok) {
      const count = data.items?.length || 0;
      showToast(tf('toast.market_scan_complete', 'Scan complete: {count} candidates found', { count }), 'success');
      await fetchReserved();
    } else {
      showToast(tf('toast.market_scan_failed', 'Scan failed: {error}', { error: data.error || 'Unknown' }), 'error');
    }
  } catch (err) {
    showToast(tf('toast.market_scan_error', 'Scan error: {error}', { error: err.message }), 'error');
  } finally {
    if (btn) btn.disabled = false;
  }
}

async function fetchStrategyList(strategy) {
  try {
    let url;
    switch (strategy) {
      case 'ladder': url = API.ladderList; break;
      case 'lightning': url = API.lightningList; break;
      case 'gazua': url = API.gazuaList; break;
      case 'contrarian': url = API.contrarianList; break;
      case 'sniper': url = API.sniperList; break;
      default: return;
    }
    const res = await authFetch(url);
    const data = await res.json();
    const rawItems = data.items || data.markets || [];
    const activeItems = (Array.isArray(rawItems) ? rawItems : []).filter((item) => {
      const stateTag = String(item?.state || item?.status || '').toUpperCase();
      return stateTag === 'ACTIVE';
    });
    const filteredItems = strategy === 'sniper'
      ? activeItems.filter((item) => {
          const p = item?.params || {};
          const profile = String(p.profile || '').toUpperCase();
          const source = String(p.source || '').toLowerCase();
          return profile !== 'SNIPERS' && source !== 'precision_scope';
        })
      : activeItems;
    renderStrategyListTable(strategy, filteredItems);
  } catch (err) {
    console.error(`${strategy} 리스트 조회 실패:`, err);
  }
}

