function reservedUiBusy() {
  const box = qs('rs-controls') || qs('reservedControls');
  if (!box) return false;
  const ae = document.activeElement;
  return !!(ae && box.contains(ae));
}

function summarizeDropCounts(drop) {
  if (!drop || typeof drop !== 'object') return '';
  const keys = Object.keys(drop).sort();
  if (!keys.length) return '';
  const parts = [];
  for (const k of keys) {
    const v = Number(drop[k]);
    if (!Number.isFinite(v) || v <= 0) continue;
    parts.push(`${k}:${v}`);
    if (parts.length >= 6) break;
  }
  return parts.join(' · ');
}

function buildReservedSummaryText(meta) {
  if (!meta) return '';
  const parts = [];
  
  if (meta.ai_score != null) {
    parts.push(`AI: ${(meta.ai_score * 100).toFixed(0)}%`);
  }
  if (meta.momentum_score != null) {
    parts.push(`Mom: ${meta.momentum_score.toFixed(1)}`);
  }
  if (meta.risk_score != null) {
    parts.push(`Risk: ${meta.risk_score.toFixed(1)}`);
  }
  if (meta.suggested_budget_usdt) {
    parts.push(`${t('label.budget_colon', 'Budget:')} ${formatAmount(meta.suggested_budget_usdt)}`);
  }
  
  return parts.join(' | ');
}

function getReservedStatusBadge(status) {
  const badges = {
    'PENDING': 'bg-warning-lt',
    'APPROVED': 'bg-success-lt',
    'REJECTED': 'bg-danger-lt',
    'PROMOTED': 'bg-info-lt',
    'DEMOTED': 'bg-secondary-lt',
    'AUTOPILOT_SKIP': 'bg-dark-lt'
  };
  return badges[status] || 'bg-secondary-lt';
}

function fmtOnOff(b) {
  return b ? 'ON' : 'OFF';
}

function setReservedSaveEnabled(enabled) {
  const btn = qs('btn-save-reserved-settings');
  if (!btn) return;
  btn.disabled = !enabled;
  btn.title = enabled ? '' : 'Reserved 설정 로드 완료 후 저장 가능합니다.';
}

function buildReservedMetaSummary(meta) {
  const m = meta || {};
  const s = m.summary || {};
  const lr = m.last_refresh_ts ? new Date(m.last_refresh_ts * 1000).toLocaleString() : '—';

  const pp = Number(s.picked_pingpong ?? 0);
  const al = Number(s.picked_autoloop ?? 0);
  const uni = Number(s.universe_filtered ?? 0);
  const tick = Number(s.tickers_loaded ?? 0);
  const ob = Number(s.orderbooks_loaded ?? 0);
  const el = s.elapsed_sec !== undefined ? `${s.elapsed_sec}s` : '—';

  const dpp = summarizeDropCounts(s.dropped_pingpong);
  const dal = summarizeDropCounts(s.dropped_autoloop);

  let tail = '';
  if (dpp) tail += ` | drop(PP): ${dpp}`;
  if (dal) tail += ` | drop(AL): ${dal}`;

  return `Last: ${lr} | pick: PP ${pp} / AL ${al} | universe ${uni} | tickers ${tick} · OB ${ob} · ${el}${tail}`;
}

async function fetchReservedSettings() {
  setReservedSaveEnabled(false);
  try {
    const res = await authFetch(API.reservedSettings);
    if (!res.ok) {
      state.reservedSettingsLoaded = false;
      console.error(`Reserved 설정 조회 실패: HTTP ${res.status}`);
      showToast('Reserved 설정 로드 실패(인증/네트워크). 기존 값 유지.', 'warning');
      return;
    }
    const data = await res.json();
    // 2026-01-30: API 응답이 { ok, settings: {...} } 또는 직접 settings 객체일 수 있음
    // 방어: 실패 응답은 UI 기본값으로 덮지 않는다.
    if (data?.ok === false) {
      state.reservedSettingsLoaded = false;
      console.error('Reserved 설정 조회 실패:', data);
      showToast(data.error || 'Reserved 설정 로드 실패. 기존 값 유지.', 'warning');
      return;
    }
    const settings = data.settings || data;
    if (!settings || typeof settings !== 'object' || settings.pingpong_n == null) {
      state.reservedSettingsLoaded = false;
      console.error('Reserved 설정 응답 형식 오류:', data);
      showToast('Reserved 설정 응답이 비정상입니다. 기존 값 유지.', 'warning');
      return;
    }
    state.reservedSettings = settings;
    state.reservedSettingsLoaded = true;
    populateReservedSettings(settings);
    await loadScopeRotationSettings();
    setReservedSaveEnabled(true);
    if (state.currentPage === 'market-reserved') {
      loadAllReservedCandidates({ force: true });
    }
    maybeAutoRecommendForCurrentPage('settings_loaded').catch(() => {});
    
    // [2026-02-01] 먼지 자동 청소 설정 로드
    const dustEnabled = qs('dust-auto-enabled');
    const dustDaily = qs('dust-auto-daily');
    let dustEnabledVal = settings.dust_vacuum_enabled;
    let dustDailyVal = settings.dust_vacuum_daily_count;
    if (dustEnabledVal == null || dustDailyVal == null) {
      try {
        const gRes = await authFetch(API.systemGuards);
        if (gRes.ok) {
          const gData = await gRes.json();
          const guards = (gData && gData.guards) || {};
          if (dustEnabledVal == null) dustEnabledVal = guards.dust_vacuum_enabled;
          if (dustDailyVal == null) dustDailyVal = guards.dust_vacuum_daily_count;
        }
      } catch (_) {}
    }
    if (dustEnabled) dustEnabled.checked = !!dustEnabledVal;
    if (dustDaily) {
      const n = Math.max(1, parseInt(String(dustDailyVal ?? 1), 10) || 1);
      if (![...dustDaily.options].some(o => o.value === String(n))) {
        const opt = document.createElement('option');
        opt.value = String(n);
        opt.textContent = String(n);
        dustDaily.appendChild(opt);
      }
      dustDaily.value = String(n);
    }
  } catch (err) {
    state.reservedSettingsLoaded = false;
    console.error('Reserved 설정 조회 실패:', err);
    showToast('Reserved 설정 로드 예외. 기존 값 유지.', 'warning');
  }
}

