  async function fetchAutoManualReport(sinceHours = 168) {
    try {
      const res = await authFetch(API.autoManualReport(sinceHours));
      const data = await res.json();
      state.autoManualReport = data;
      renderAutoManualReport(data);
      renderAutoManualDetails(data);
      renderAutoManualStrategy(data);
    } catch (err) {
      console.error('Auto/Manual report 조회 실패:', err);
    }
  }

  function renderAutoManualReport(data) {
    const tbody = qs('am-report-body');
    const note = qs('am-report-note');
    if (!tbody) return;

    if (!data || !data.ok) {
    tbody.innerHTML = `<tr><td colspan="5" class="text-center text-muted">${t('empty.no_data', 'No data')}</td></tr>`;
      if (note) note.textContent = t('empty.no_data', 'No data');
      return;
    }

    const summary = data.summary || {};
    const rows = [
      { key: 'A', label: 'Auto', badge: '<span class="badge bg-primary-lt">A</span>' },
      { key: 'M', label: 'Manual', badge: '<span class="badge bg-warning-lt">M</span>' },
      { key: '-', label: 'Unknown', badge: '<span class="text-muted">-</span>' },
    ];

    const html = rows.map(r => {
      const s = summary[r.key] || {};
      const pnl = Number(s.total_pnl_usdt || 0);
      const pnlClass = getPnlClass(pnl);
      const roi = Number(s.roi_pct || 0);
      return `
        <tr>
          <td>${r.badge} <span class="ms-1">${r.label}</span></td>
          <td class="text-center">${s.market_n || 0}</td>
          <td class="text-center">${s.total_trades || 0}</td>
          <td class="text-end ${pnlClass}">${fmtUsdt(pnl)}</td>
          <td class="text-end ${pnlClass}">${fmtPct(roi)}</td>
        </tr>
      `;
    }).join('');

  tbody.innerHTML = html || `<tr><td colspan="5" class="text-center text-muted">${t('empty.no_trades', 'No trades')}</td></tr>`;

    if (note) {
      const hrs = data.since_hours || 168;
      const basis = data.mode_basis || 'OMA reason';
      note.textContent = tf('report.note_recent_hours_basis', 'Last {hours}h · mode basis: {basis}', { hours: hrs, basis });
    }
  }

  function renderAutoManualDetails(data) {
    const tbody = qs('am-detail-body');
    const note = qs('am-detail-note');
    if (!tbody) return;

    if (!data || !data.ok) {
      tbody.innerHTML = `<tr><td colspan="6" class="text-center text-muted">${t('empty.no_data', 'No data')}</td></tr>`;
      if (note) note.textContent = t('empty.no_data', 'No data');
      return;
    }

    const items = Array.isArray(data.items) ? data.items : [];
    populateAutoManualStrategyOptions(items);

    const modeFilter = qs('am-detail-mode')?.value || '';
    const strategyFilter = (qs('am-detail-strategy')?.value || '').toUpperCase();
    const limit = parseInt(qs('am-detail-limit')?.value, 10) || 50;

    const filtered = items.filter(it => {
      if (modeFilter && it.mode !== modeFilter) return false;
      if (strategyFilter && String(it.strategy || '').toUpperCase() !== strategyFilter) return false;
      return true;
    }).slice(0, Math.max(1, limit));

    if (!filtered.length) {
      tbody.innerHTML = `<tr><td colspan="6" class="text-center text-muted">${t('empty.no_trades', 'No trades')}</td></tr>`;
    } else {
      tbody.innerHTML = filtered.map(it => {
        const pnl = Number(it.total_pnl_usdt || 0);
        const pnlClass = getPnlClass(pnl);
        const roi = Number(it.roi_pct || 0);
        const modeBadge = it.mode === 'A'
          ? '<span class="badge bg-primary-lt">A</span>'
          : (it.mode === 'M' ? '<span class="badge bg-warning-lt">M</span>' : '<span class="text-muted">-</span>');
        const stratBadge = it.strategy ? renderStrategyBadge(it.strategy) : '<span class="text-muted">—</span>';
        return `
          <tr>
            <td>${extractBase(it.market || '')}</td>
            <td>${stratBadge}</td>
            <td class="text-center">${modeBadge}</td>
            <td class="text-center">${it.trade_n || 0}</td>
            <td class="text-end ${pnlClass}">${fmtUsdt(pnl)}</td>
            <td class="text-end ${pnlClass}">${fmtPct(roi)}</td>
          </tr>
        `;
      }).join('');
    }

    if (note) {
      const hrs = data.since_hours || 168;
      note.textContent = tf('report.note_recent_hours_display', 'Last {hours}h · showing {shown}/{total}', {
        hours: hrs,
        shown: filtered.length,
        total: items.length,
      });
    }
  }

  function populateAutoManualStrategyOptions(items) {
    const select = qs('am-detail-strategy');
    if (!select) return;
    const existing = Array.from(select.options).map(o => o.value);
    if (existing.length > 1) return; // already populated

    const set = new Set();
    items.forEach(it => {
      if (it.strategy) set.add(String(it.strategy).toUpperCase());
    });
    const strategies = Array.from(set).sort();
    strategies.forEach(s => {
      const opt = document.createElement('option');
      opt.value = s;
      opt.textContent = s;
      select.appendChild(opt);
    });
  }

  function renderAutoManualStrategy(data) {
    const tbody = qs('am-strategy-body');
    const note = qs('am-strategy-note');
    if (!tbody) return;

    if (!data || !data.ok) {
      tbody.innerHTML = `<tr><td colspan="7" class="text-center text-muted">${t('empty.no_data', 'No data')}</td></tr>`;
      if (note) note.textContent = t('empty.no_data', 'No data');
      return;
    }

    const byStrategy = data.by_strategy || {};
    const rows = Object.keys(byStrategy).map(strategy => {
      const bucket = byStrategy[strategy] || {};
      const a = bucket.A || {};
      const m = bucket.M || {};
      const aPnl = Number(a.total_pnl_usdt || 0);
      const mPnl = Number(m.total_pnl_usdt || 0);
      return {
        strategy,
        a,
        m,
        score: aPnl + mPnl
      };
    }).sort((x, y) => y.score - x.score);

    if (!rows.length) {
      tbody.innerHTML = `<tr><td colspan="7" class="text-center text-muted">${t('empty.no_trades', 'No trades')}</td></tr>`;
    } else {
      tbody.innerHTML = rows.map(r => {
        const aPnl = Number(r.a.total_pnl_usdt || 0);
        const mPnl = Number(r.m.total_pnl_usdt || 0);
        return `
          <tr>
            <td>${renderStrategyBadge(r.strategy)}</td>
            <td class="text-center">${r.a.total_trades || 0}</td>
            <td class="text-end ${getPnlClass(aPnl)}">${fmtUsdt(aPnl)}</td>
            <td class="text-end ${getPnlClass(aPnl)}">${fmtPct(Number(r.a.roi_pct || 0))}</td>
            <td class="text-center">${r.m.total_trades || 0}</td>
            <td class="text-end ${getPnlClass(mPnl)}">${fmtUsdt(mPnl)}</td>
            <td class="text-end ${getPnlClass(mPnl)}">${fmtPct(Number(r.m.roi_pct || 0))}</td>
          </tr>
        `;
      }).join('');
    }

    if (note) {
      const hrs = data.since_hours || 168;
      note.textContent = tf('report.note_recent_hours_strategy_count', 'Last {hours}h · {count} strategies', {
        hours: hrs,
        count: rows.length,
      });
    }
  }

