function renderMarketUpside(rankings) {
  const top5El = qs('market-upside-top5');
  const moreEl = qs('market-upside-more');
  
  if (!rankings?.length) {
    if (top5El) top5El.innerHTML = `<div class="text-muted text-center p-3">${t('empty.no_data', 'No data')}</div>`;
    return;
  }
  
  const formatVol = (v) => {
    if (v >= 1e12) return '$' + (v / 1e12).toFixed(1) + t('unit.jo', 'T');
    if (v >= 1e8) return '$' + (v / 1e8).toFixed(0) + t('unit.eok', 'eok');
    if (v >= 1e4) return '$' + (v / 1e4).toFixed(0) + t('unit.man', 'man');
    return '$' + v.toFixed(0);
  };
  
  if (top5El) {
    top5El.innerHTML = rankings.slice(0, 5).map((r, i) => {
      const medal = ['🥇', '🥈', '🥉', '4️⃣', '5️⃣'][i];
      const changeClass = getPnlClass(r.change_pct || 0);
      const scoreClass = r.upside_score >= 50 ? 'text-success' : (r.upside_score >= 30 ? 'text-warning' : 'text-muted');
      const a = r.analysis || {};
      
      return `
        <div class="d-flex justify-content-between align-items-center py-2 px-3 border-bottom cursor-pointer" onclick="window.open('/ui/market_detail.html?market=${encodeURIComponent(r.market)}', '_blank')">
          <div>
            <span class="fs-5">${medal}</span>
            <strong class="ms-1">${r.currency}</strong>
            <span class="text-success small ms-2">${formatAmount(r.current_price)}</span>
            <div class="small text-muted">RSI:${a.rsi || '-'} BB:${Math.round((a.bb_position || 0) * 100)}%</div>
          </div>
          <div class="text-end">
            <div class="${scoreClass} fw-bold">${tf('ranking.score_label', 'Score {score}', { score: r.upside_score })}</div>
            <div class="${changeClass} small">${formatPercent(r.change_pct || 0)}</div>
          </div>
        </div>
      `;
    }).join('');
  }
  
  if (moreEl && rankings.length > 5) {
    moreEl.innerHTML = rankings.slice(5, 20).map(r => {
      const changeClass = getPnlClass(r.change_pct || 0);
      return `
        <div class="d-flex justify-content-between py-1 px-3 border-bottom cursor-pointer small" onclick="window.open('/ui/market_detail.html?market=${encodeURIComponent(r.market)}', '_blank')">
          <span><span class="text-muted">#${r.rank}</span> ${r.currency} <span class="text-success">${formatAmount(r.current_price)}</span></span>
          <span><span class="text-muted">${tf('ranking.score_label', 'Score {score}', { score: r.upside_score })}</span> <span class="${changeClass} ms-2">${formatPercent(r.change_pct || 0)}</span></span>
        </div>
      `;
    }).join('');
  } else if (moreEl) {
    moreEl.innerHTML = `<div class="text-muted small p-2">${t('label.under_five', '5 or fewer')}</div>`;
  }
}

// ============================================================
// Price Grid & Pagination
// ============================================================
let priceGridPage = 0;
let priceGridPageSize = 12;

function getPriceGridPageSize() {
  const el = qs('price-grid-per-page');
  if (el) priceGridPageSize = parseInt(el.value) || 12;
  return priceGridPageSize;
}

function renderPriceGrid(prices) {
  const container = qs('price-grid');
  if (!container) return;
  
  const pageSize = getPriceGridPageSize();
  const priceList = Object.entries(prices || state.prices);
  if (!priceList.length) {
    container.innerHTML = '<div class="col-12 text-center text-muted">No price data</div>';
    return;
  }
  
  const start = priceGridPage * pageSize;
  const pageItems = priceList.slice(start, start + pageSize);
  
  container.innerHTML = pageItems.map(([market, data]) => {
    const price = typeof data === 'object' ? data.price : data;
    const change = typeof data === 'object' ? data.change_pct : 0;
    const pnl = typeof data === 'object' ? data.pnl_pct : 0;
    const changeClass = change >= 0 ? 'text-danger' : 'text-primary';
    const pnlClass = getPnlClass(pnl);
    
    return `
      <div class="col-md-3 col-sm-4 col-6">
        <div class="card card-sm cursor-pointer" onclick="selectMarketForTrade('${market}')">
          <div class="card-body p-2">
            <div class="d-flex justify-content-between align-items-center">
              <strong class="small">${extractBase(market)}</strong>
              <span class="${changeClass} small">${change >= 0 ? '+' : ''}${(change || 0).toFixed(2)}%</span>
            </div>
            <div class="text-muted small">$${formatNumber(price)}</div>
            ${pnl !== 0 ? `<div class="${pnlClass} small">${formatPercent(pnl)}</div>` : ''}
          </div>
        </div>
      </div>
    `;
  }).join('');
  
  // Pagination
  const totalPages = Math.ceil(priceList.length / pageSize);
  const paginationEl = qs('price-grid-pagination');
  if (paginationEl) {
    if (totalPages > 1) {
      let paginationHtml = '<nav><ul class="pagination pagination-sm mb-0">';
      for (let i = 0; i < totalPages; i++) {
        paginationHtml += `<li class="page-item ${i === priceGridPage ? 'active' : ''}">
          <a class="page-link" href="#" onclick="setPriceGridPage(${i}); return false;">${i + 1}</a>
        </li>`;
      }
      paginationHtml += '</ul></nav>';
      paginationEl.innerHTML = paginationHtml;
    } else {
      paginationEl.innerHTML = '';
    }
  }
}

function setPriceGridPage(page) {
  priceGridPage = page;
  renderPriceGrid();
}

function bindPriceGridEvents() {
  qs('price-grid-per-page')?.addEventListener('change', () => {
    priceGridPage = 0;
    renderPriceGrid();
  });
}

// ============================================================
// Quick Trade Functions
