function selectMarketForTrade(market) {
  const qtMarket = qs('qt-market');
  if (qtMarket) qtMarket.value = market;
  updateQuickTradePrice(market);
}

// 2026-03-10: Quick Trade 드롭다운에 활동 중인 코인 + ALL 옵션 채우기
let _qtLastKeys = '';
function populateQuickTradeMarkets() {
  const sel = document.getElementById('qt-market');
  if (!sel) return;

  // 활동 중인 마켓 수집 (renderActiveMarkets와 동일 기준: ACTIVE/RECOVERY만)
  const validStrategies = ['AUTOLOOP', 'PINGPONG', 'CONTRARIAN', 'SNIPER', 'GAZUA', 'LADDER', 'LIGHTNING', 'WHALE'];
  const activeMarkets = (state.managedMarkets || []).filter(m => {
    const st = String(m.state || '').toUpperCase();
    if (st !== 'ACTIVE' && st !== 'RECOVERY') return false;
    const posQty = m.position?.qty || m.context?.position?.qty || 0;
    const strategy = (m.strategy || '').toUpperCase();
    return posQty > 0 || validStrategies.includes(strategy);
  });

  // 변경 없으면 스킵 (드롭다운 열려있을 때 닫히는 것 방지)
  const keys = activeMarkets.map(m => m.market).join(',');
  if (keys === _qtLastKeys) return;
  _qtLastKeys = keys;

  const prev = sel.value;
  let html = '<option value="">코인 선택</option>';
  activeMarkets.forEach(m => {
    const base = m.market.replace(/USDT$/i,'');
    const posQty = m.position?.qty || m.context?.position?.qty || 0;
    const strat = m.strategy ? ` [${m.strategy}]` : '';
    const pnl = posQty > 0 && m.pnl_pct != null ? ` ${m.pnl_pct >= 0 ? '+' : ''}${m.pnl_pct.toFixed(1)}%` : '';
    html += `<option value="${m.market}">${base}${strat}${pnl}</option>`;
  });
  if (activeMarkets.length > 0) {
    html += '<option value="__ALL__">── ALL (전체 매도) ──</option>';
  }
  sel.innerHTML = html;

  if (prev && sel.querySelector(`option[value="${prev}"]`)) {
    sel.value = prev;
  }
}

async function updateQuickTradePrice(market) {
  if (!market || market === '__ALL__') {
    const priceEl = qs('qt-price');
    if (priceEl) priceEl.textContent = market === '__ALL__' ? '전체 매도' : '$—';
    return;
  }
  const priceEl = qs('qt-price');
  if (!priceEl) return;

  const price = state.prices[market];
  if (price) {
    priceEl.textContent = '$' + formatNumber(typeof price === 'object' ? price.price : price);
  } else {
    priceEl.textContent = '$—';
  }
}

async function executeQuickTrade(side) {
  const rawVal = qs('qt-market')?.value || '';

  // 2026-03-10: ALL 선택 시 전체 매도
  if (rawVal === '__ALL__' && side === 'sell') {
    return executeQuickSellAll();
  }

  const market = normMarket(rawVal);
  const mode = qs('qt-mode')?.value || 'immediate';
  const guard = qs('qt-guard')?.value || 'global';
  const amountMode = qs('qt-amount-mode')?.value || 'quote';
  const amount = parseFloat(qs('qt-amount')?.value) || 0;

  if (!market) {
    showToast('Market is required', 'error');
    return;
  }
  if (amount <= 0) {
    showToast('Amount is required', 'error');
    return;
  }

  const msgEl = qs('qt-msg');
  if (msgEl) msgEl.textContent = 'Processing...';

  try {
    const params = {
      market: market,
      side: side,
      amount_mode: amountMode,
      amount: amount,
      guard_policy: guard
    };

    if (mode === 'conditional') {
      params.conditional = true;
      params.trigger = qs('qt-cond-trigger')?.value || 'near_low';
      params.lookback_min = parseInt(qs('qt-cond-lookback')?.value) || 15;
      params.threshold = parseFloat(qs('qt-cond-threshold')?.value) || 0.2;
      params.expiry_min = parseInt(qs('qt-cond-expiry')?.value) || 30;
    }

    const res = await authFetch('/api/engine/manual/order', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params)
    });
    const data = await res.json();

    if (data.ok) {
      if (msgEl) msgEl.textContent = `✓ ${side.toUpperCase()} order placed`;
      msgEl.className = 'text-center mt-2 small text-success';
      // 전량 매도 시 슬롯 해제
      if (side === 'sell' && amountMode === 'percent' && amount >= 100) {
        try { await authFetch(API.managerSet(market, 'DISABLED', null, 'quick_sell_full'), { method: 'POST' }); } catch (e) {}
      }
    } else {
      if (msgEl) msgEl.textContent = '✗ ' + (data.error || data.msg || 'Failed');
      msgEl.className = 'text-center mt-2 small text-danger';
    }
  } catch (err) {
    if (msgEl) msgEl.textContent = '✗ Error: ' + err.message;
    msgEl.className = 'text-center mt-2 small text-danger';
  }
}

// 2026-03-10: Quick Trade ALL — 포지션 보유 전 마켓 일괄 시장가 매도 + 슬롯 해제
async function executeQuickSellAll() {
  const msgEl = qs('qt-msg');
  const activeWithPos = (state.managedMarkets || []).filter(m => {
    const st = String(m.state || '').toUpperCase();
    const posQty = m.position?.qty || m.context?.position?.qty || 0;
    return (st === 'ACTIVE' || st === 'RECOVERY') && posQty > 0;
  });

  if (!activeWithPos.length) {
    showToast('매도할 포지션이 없습니다', 'warning');
    if (msgEl) { msgEl.textContent = '매도할 포지션이 없습니다'; msgEl.className = 'text-center mt-2 small text-warning'; }
    return;
  }

  const names = activeWithPos.map(m => m.market.replace(/USDT$/i,'')).join(', ');
  if (!confirm(`[긴급 전체 매도]\n대상: ${activeWithPos.length}개 (${names})\n진행하시겠습니까?`)) return;

  if (msgEl) { msgEl.textContent = `전체 매도 진행중 (${activeWithPos.length}개)...`; msgEl.className = 'text-center mt-2 small text-info'; }

  let okCount = 0, failCount = 0;
  for (const m of activeWithPos) {
    try {
      const res = await authFetch('/api/engine/manual/order', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ market: m.market, side: 'sell', mode: 'all', value: 100 })
      });
      const data = await res.json();
      if (data.ok) okCount++; else failCount++;
    } catch (e) {
      failCount++;
    }
    // 매도 후 즉시 슬롯 해제 (DISABLED)
    try {
      await authFetch(API.managerSet(m.market, 'DISABLED', null, 'quick_sell_all'), { method: 'POST' });
    } catch (e) {}
  }

  if (msgEl) {
    msgEl.textContent = `✓ 전체 매도: ${okCount}/${activeWithPos.length} 완료` + (failCount ? ` (${failCount} 실패)` : '');
    msgEl.className = `text-center mt-2 small ${failCount ? 'text-warning' : 'text-success'}`;
  }
  await fetchActiveMarkets();
}

function bindQuickTradeEvents() {
  // Mode toggle
  qs('qt-mode')?.addEventListener('change', (e) => {
    const condConfig = qs('qt-cond-config');
    if (condConfig) {
      condConfig.style.display = e.target.value === 'conditional' ? 'block' : 'none';
    }
  });
  
  // 2026-02-02: Amount mode toggle ($/%) - 버튼 레이블 변경
  qs('qt-amount-mode')?.addEventListener('change', (e) => {
    updateQuickAmountButtons();
  });
  
  // 2026-02-02: Quick amount buttons - 배수 기능 추가
  qsa('.qt-quick').forEach(btn => {
    btn.addEventListener('click', () => {
      const amountMode = qs('qt-amount-mode')?.value || 'quote';
      const amountInput = qs('qt-amount');
      if (!amountInput) return;
      
      const btnVal = parseFloat(btn.dataset.val) || 0;
      const currentVal = parseFloat(amountInput.value) || 0;
      
      if (amountMode === 'percent') {
        // % 모드: 10%, 50%, 100%
        const pctVal = parseFloat(btn.dataset.pct) || 0;
        if (currentVal === pctVal) {
          // 같은 버튼 재클릭 시 배수 (최대 300%)
          amountInput.value = Math.min(currentVal * 2, 300);
        } else {
          amountInput.value = pctVal;
        }
      } else {
        // $ 모드: 2만, 5만, 10만
        if (currentVal === btnVal) {
          // 같은 버튼 재클릭 시 배수
          amountInput.value = currentVal * 2;
        } else {
          amountInput.value = btnVal;
        }
      }
    });
  });
  
  // Buy/Sell buttons
  qs('btn-qt-buy')?.addEventListener('click', () => executeQuickTrade('buy'));
  qs('btn-qt-sell')?.addEventListener('click', () => executeQuickTrade('sell'));
  
  // Market select change
  qs('qt-market')?.addEventListener('change', (e) => {
    const val = e.target.value;
    updateQuickTradePrice(val);
    // ALL 선택 시 BUY 비활성화
    const buyBtn = qs('btn-qt-buy');
    if (buyBtn) buyBtn.disabled = (val === '__ALL__');
  });
  
  // 초기화
  updateQuickAmountButtons();
}

// 2026-02-02: Quick Trade 금액 버튼 레이블 업데이트
function updateQuickAmountButtons() {
  const amountMode = qs('qt-amount-mode')?.value || 'quote';
  const buttons = qsa('.qt-quick');
  
  if (amountMode === 'percent') {
    // % 모드
    const pctVals = [10, 50, 100];
    buttons.forEach((btn, i) => {
      if (pctVals[i] !== undefined) {
        btn.textContent = pctVals[i] + '%';
        btn.dataset.pct = pctVals[i];
      }
    });
  } else {
    // $ 모드
    const usdtVals = [20, 50, 100];
    const labels = [t('quick.20', '$20'), t('quick.50', '$50'), t('quick.100', '$100')];
    buttons.forEach((btn, i) => {
      if (usdtVals[i] !== undefined) {
        btn.textContent = labels[i];
        btn.dataset.val = usdtVals[i];
        delete btn.dataset.pct;
      }
    });
  }
}

