async function executeQuickTrade2(side) {
  const market = normMarket(qs('qt2-market')?.value || '');
  const mode = qs('qt2-mode')?.value || 'immediate';
  const guard = qs('qt2-guard')?.value || 'global';
  const amountMode = qs('qt2-amount-mode')?.value || 'quote';
  const amount = parseFloat(qs('qt2-amount')?.value) || 0;
  const msgEl = qs('qt2-msg');
  
  if (!market) {
    if (msgEl) msgEl.innerHTML = `<span class="text-danger">${t('error.enter_market', 'Please enter a market')}</span>`;
    return;
  }
  if (amount <= 0) {
    if (msgEl) msgEl.innerHTML = `<span class="text-danger">${t('error.enter_amount', 'Please enter an amount')}</span>`;
    return;
  }
  
  // executeQuickTrade와 동일한 API 호출 로직 재사용
  const body = {
    market,
    side,
    mode,
    guard_policy: guard,
    amount_mode: amountMode,
    amount,
  };
  
  if (mode === 'conditional') {
    body.conditional = {
      trigger: qs('qt2-cond-trigger')?.value || 'near_low',
      lookback_min: parseInt(qs('qt2-cond-lookback')?.value) || 15,
      threshold_pct: parseFloat(qs('qt2-cond-threshold')?.value) || 0.2,
      expiry_min: parseInt(qs('qt2-cond-expiry')?.value) || 30,
    };
  }
  
  try {
    if (msgEl) msgEl.innerHTML = `<span class="text-muted">${t('status.processing', 'Processing...')}</span>`;
    const res = await authFetch('/api/quick-trade/execute', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const data = await res.json();
    if (data.ok) {
      if (msgEl) msgEl.innerHTML = `<span class="text-success">${tf('status.side_completed', '{side} completed', { side: side.toUpperCase() })}</span>`;
      fetchActiveMarkets();
    } else {
      if (msgEl) msgEl.innerHTML = `<span class="text-danger">${data.error || t('status.failed', 'Failed')}</span>`;
    }
  } catch (err) {
    if (msgEl) msgEl.innerHTML = `<span class="text-danger">${t('label.error', 'Error')}: ${err.message}</span>`;
  }
}

// ============================================================
// Kimchi Premium (김프)
// ============================================================
let binancePrices = {};
let exchangeRate = 1450;

async function fetchBinancePrices() {
  try {
    // Binance API 백엔드 프록시 호출 (CORS 우회)
    const res = await authFetch('/api/system/binance-tickers');
    const json = await res.json();
    
    if (!json.ok || !Array.isArray(json.tickers)) return;
    
    json.tickers.forEach(t => {
      if (t.symbol.endsWith('USDT')) {
        const base = t.symbol.replace('USDT', '');
        binancePrices[base] = parseFloat(t.price);
      }
    });
    
    // Get exchange rate
    try {
      const rateRes = await authFetch('/api/system/exchange-rate');
      const rateData = await rateRes.json();
      if (rateData.ok && rateData.rate) {
        exchangeRate = rateData.rate;
        // 김프 비교 환율 입력란 자동 업데이트
        const kimchiRateInput = qs('kimchi-rate');
        if (kimchiRateInput && !kimchiRateInput.dataset.userEdited) {
          kimchiRateInput.value = Math.round(exchangeRate);
          const _kMainSync = qs('kimchi-rate-main');  // 중복 id fix: 메인 김프 패널 입력칸도 동기화
          if (_kMainSync) _kMainSync.value = Math.round(exchangeRate);
        }
      }
    } catch (e) {
      // Use default
    }
    
    if (qs('kimchi-rate-label')) {
      qs('kimchi-rate-label').textContent = tf('label.exchange_rate_dynamic', 'Rate: {rate}', { rate: exchangeRate.toLocaleString() });
    }
  } catch (err) {
    console.error('Binance prices fetch failed:', err);
  }
}

function renderKimchiList(filter = '') {
  const container = qs('kimchi-list');
  if (!container) return;
  
  const markets = Object.keys(state.prices).filter(m => {
    if (!filter) return true;
    return m.toLowerCase().includes(filter.toLowerCase()) || 
           extractBase(m).toLowerCase().includes(filter.toLowerCase());
  });
  
  if (!markets.length) {
    container.innerHTML = `<div class="text-muted text-center p-3">${t('empty.no_data', 'No data')}</div>`;
    return;
  }
  
  container.innerHTML = markets.slice(0, 15).map(market => {
    const base = extractBase(market);
    const bybitPrice = typeof state.prices[market] === 'object' ? state.prices[market].price : state.prices[market];
    const binancePrice = binancePrices[base];

    if (!bybitPrice || !binancePrice) {
      return `<div class="d-flex justify-content-between p-2 border-bottom small">
        <span>${base}</span>
        <span class="text-muted">-</span>
      </div>`;
    }

    const diff = ((bybitPrice / binancePrice) - 1) * 100;
    const diffClass = diff > 0 ? 'text-danger' : 'text-primary';

    return `<div class="d-flex justify-content-between p-2 border-bottom small">
      <span><strong>${base}</strong></span>
      <span>
        <span class="text-muted me-2">By:${formatNumber(bybitPrice)}</span>
        <span class="text-muted me-2">Bn:${formatNumber(binancePrice)}</span>
        <span class="${diffClass}">${diff >= 0 ? '+' : ''}${diff.toFixed(2)}%</span>
      </span>
    </div>`;
  }).join('');
}

function updateKimchiDatalist() {
  const datalist = qs('kimchi-coin-list');
  if (!datalist) return;
  
  const coins = new Set();
  Object.keys(state.prices).forEach(m => coins.add(extractBase(m)));
  Object.keys(binancePrices).forEach(c => coins.add(c));
  
  const sorted = Array.from(coins).sort();
  datalist.innerHTML = sorted.map(c => `<option value="${c}">`).join('');
}

function bindKimchiEvents() {
  qs('btn-refresh-kimchi')?.addEventListener('click', async () => {
    await fetchBinancePrices();
    updateKimchiDatalist();
    renderKimchiList(qs('kimchi-search')?.value);
  });
  
  qs('kimchi-search')?.addEventListener('input', (e) => {
    renderKimchiList(e.target.value);
  });
  
  qs('kimchi-rate')?.addEventListener('change', (e) => {
    const rate = parseFloat(e.target.value);
    if (rate > 0) {
      exchangeRate = rate;
      renderKimchiList(qs('kimchi-search')?.value);
    }
  });
}

// ============================================================
// OMA Market List
// ============================================================
let omaMarketPage = 0;
const OMA_PAGE_SIZE = 10;

function renderOmaMarketList(markets) {
  const tbody = qs('oma-market-tbody');
  if (!tbody) return;
  
  // 2026-01-30: 포지션이 있거나 전략이 설정된 마켓 표시
  const filteredMarkets = markets.filter(m => {
    const posQty = m.position?.qty || m.context?.position?.qty || 0;
    const hasPosition = posQty > 0;
    const strategy = (m.strategy || '').toUpperCase();
    const validStrategies = ['AUTOLOOP', 'PINGPONG', 'CONTRARIAN', 'SNIPER', 'GAZUA', 'LADDER', 'LIGHTNING'];
    const hasValidStrategy = validStrategies.includes(strategy);
    return hasPosition || hasValidStrategy;
  });
  
  if (!filteredMarkets.length) {
    tbody.innerHTML = '<tr><td colspan="7" class="text-muted text-center p-3">No managed markets with positions</td></tr>';
    return;
  }
  
  const start = omaMarketPage * OMA_PAGE_SIZE;
  const pageItems = filteredMarkets.slice(start, start + OMA_PAGE_SIZE);
  
  tbody.innerHTML = markets.map(m => {
    const pnlClass = getPnlClass(m.pnl_pct || 0);
    const strategyBadge = getStrategyBadgeClass(m.strategy);
    return `
      <tr>
        <td><strong>${extractBase(m.market)}</strong></td>
        <td><span class="badge bg-${m.active ? 'success' : 'secondary'}">${m.active ? 'RUNNING' : m.state}</span></td>
        <td>${m.next_step || 0}/${m.params?.max_steps || '-'}</td>
        <td>${m.position?.usdt > 0 ? formatAmount(m.position.usdt) : '-'}</td>
        <td>${m.params?.tp || '-'}%${m.budget > 0 && m.params?.tp > 0 ? ` <span class="text-muted small">(+${formatNumber(Math.round(m.budget * m.params.tp / 100))})</span>` : ''}</td>
        <td class="${pnlClass}">${formatAmount(m.pnl?.amount || 0)} (${(m.pnl?.pct || m.pnl_pct || 0).toFixed(2)}%)</td>
        <td>
          <button class="btn btn-outline-secondary btn-sm" onclick="showLadderStepModal('${m.market}')"><i class="ti ti-list-details"></i> Steps</button>
          <button class="btn btn-outline-success btn-sm ms-1" onclick="showLadderStepExpandedPanel('${m.market}')"><i class="ti ti-expand"></i> ${t('action.manage', 'Manage')}</button>
        </td>
      </tr>
    `;
  }).join('');

  // Pagination (use filteredMarkets count)
  const totalPages = Math.ceil(filteredMarkets.length / OMA_PAGE_SIZE);
  const paginationEl = qs('oma-market-pagination');
  if (paginationEl) {
    if (totalPages > 1) {
      let html = '<nav><ul class="pagination pagination-sm mb-0">';
      for (let i = 0; i < totalPages; i++) {
        html += `<li class="page-item ${i === omaMarketPage ? 'active' : ''}">
          <a class="page-link" href="#" onclick="setOmaMarketPage(${i}); return false;">${i + 1}</a>
        </li>`;
      }
      html += '</ul></nav>';
      paginationEl.innerHTML = html;
    } else {
      paginationEl.innerHTML = '';
    }
  }
}

// ====== OUTSIDE: Expanded Ladder Step Panel Logic ======
window.showLadderStepExpandedPanel = async function(market) {
  const panel = qs('ladder-step-expanded-panel');
  if (!panel) return;
  panel.classList.remove('d-none');
  qs('ladder-step-expanded-market').textContent = market;
  try {
    const res = await authFetch(`/api/strategy/ladder/steps?market=${encodeURIComponent(market)}`);
    const data = await res.json();
    renderLadderStepExpandedList(data.steps || [], market, data.profit_summary || {});
  } catch (err) {
    qs('ladder-step-expanded-list').innerHTML = `<tr><td colspan="8" class="text-danger text-center">Error: ${err.message}</td></tr>`;
  }
};

window.hideLadderStepExpandedPanel = function() {
  const panel = qs('ladder-step-expanded-panel');
  if (panel) panel.classList.add('d-none');
};

function renderLadderStepExpandedList(steps, market, profitSummary) {
  const tbody = qs('ladder-step-expanded-list');
  if (!tbody) return;
  if (!steps.length) {
    tbody.innerHTML = '<tr><td colspan="8" class="text-center text-muted">No steps</td></tr>';
    return;
  }
  tbody.innerHTML = steps.map((step, idx) => {
    const statusClass = step.status === 'active' ? 'bg-success' : (step.status === 'paused' ? 'bg-warning' : 'bg-secondary');
    const typeBadge = step.type === 'buy' ? '<span class="badge bg-success">Buy</span>' : '<span class="badge bg-danger">Sell</span>';
    const priceClass = step.is_current ? 'bg-info text-white' : '';
    return `<tr>
        <td>${idx + 1}</td>
        <td>${typeBadge}</td>
        <td class="${priceClass}">${formatAmount(step.price)}</td>
        <td>${step.amount}</td>
        <td><span class="badge ${statusClass}">${step.status}</span></td>
        <td>${step.filled ? '✓' : '-'}</td>
        <td>${step.profit != null ? formatAmount(step.profit) : '-'}</td>
        <td>
          <button class="btn btn-outline-warning btn-sm" onclick="updateLadderStepStatus('${market}', '${step.uuid}', 'paused')">Pause</button>
          <button class="btn btn-outline-success btn-sm ms-1" onclick="updateLadderStepStatus('${market}', '${step.uuid}', 'active')">Resume</button>
          <button class="btn btn-outline-danger btn-sm ms-1" onclick="deleteLadderStep('${market}', '${step.uuid}')">Delete</button>
        </td>
      </tr>`;
  }).join('');
  qs('ladder-step-expanded-profit-summary').innerHTML = profitSummary && profitSummary.realized != null
    ? `<span class="text-success">Realized Profit: ${formatAmount(profitSummary.realized)}</span>`
    : '';
}

// ====== OUTSIDE: Grid Steps Visualization Logic (ICAG V3) ======
window.showGridStepsPanel = async function(market) {
  const panel = qs('grid-steps-panel');
  if (!panel) return;
  panel.classList.remove('d-none');
  qs('grid-steps-market').textContent = market + ' (ICAG)';
  qs('grid-steps-list').innerHTML = `<tr><td colspan="8" class="text-center text-muted">${t('label.loading', 'Loading...')}</td></tr>`;
  try {
    const res = await authFetch(`/api/ladder/grid/state?market=${encodeURIComponent(market)}`);
    const data = await res.json();
    // Show ICAG diagnostics header if available
    const icag = data.icag || {};
    const headerEl = qs('grid-steps-market');
    if (headerEl && icag.zone) {
      headerEl.innerHTML = `${market} <span class="badge ${({'CORE':'bg-success','EXPANSION':'bg-warning','RISK_CUT':'bg-danger'})[icag.zone]||'bg-secondary'} ms-1">${icag.zone}</span> <span class="badge ${({'BUY':'bg-primary','SELL':'bg-warning','BALANCED':'bg-info'})[icag.bias]||'bg-secondary'} ms-1">${icag.bias||''}</span> <small class="text-muted ms-2">Anchor: ${icag.anchor_price ? formatAmount(icag.anchor_price) : '-'} | ATR: ${icag.atr ? icag.atr.toFixed(1) : '-'} | Inv: ${icag.inv_ratio != null ? (icag.inv_ratio*100).toFixed(1)+'%' : '-'}</small>`;
    }
    renderGridStepsList(data.steps || [], market, {}, data.current_price || 0);
  } catch (err) {
    qs('grid-steps-list').innerHTML = `<tr><td colspan="8" class="text-danger text-center">Error: ${err.message}</td></tr>`;
  }
};

window.hideGridStepsPanel = function() {
  const panel = qs('grid-steps-panel');
  if (panel) panel.classList.add('d-none');
};

function renderGridStepsList(steps, market, profitSummary, currentPrice) {
  const tbody = qs('grid-steps-list');
  if (!tbody) return;
  if (!steps.length) {
    tbody.innerHTML = `<tr><td colspan="8" class="text-center text-muted">${t('empty.ladder_no_steps_sync', 'No steps - Run Grid Sync')}</td></tr>`;
    return;
  }
  let closestIdx = -1, minDiff = Infinity;
  steps.forEach((s, i) => {
    const diff = Math.abs((s.price || 0) - currentPrice);
    if (diff < minDiff) { minDiff = diff; closestIdx = i; }
  });
  tbody.innerHTML = steps.map((step, idx) => {
    const st = step.status || 'pending';
    const statusMap = {
      active: 'bg-success', filled: 'bg-primary', paused: 'bg-warning',
      skipped: 'bg-dark', pending: 'bg-secondary'
    };
    const statusLabel = {
      active: t('badge.active', 'Active'),
      filled: t('badge.filled', 'Filled'),
      paused: t('badge.paused', 'Paused'),
      skipped: t('badge.skipped', 'Skipped'),
      pending: t('badge.waiting', 'Waiting')
    };
    const side = step.side || 'buy';
    const typeBadge = side === 'buy'
      ? '<span class="badge bg-success">Buy</span>'
      : '<span class="badge bg-danger">Sell</span>';
    const isClosest = idx === closestIdx;
    const priceClass = isClosest ? 'bg-info text-white fw-bold' : '';
    const rowClass = st === 'filled' ? 'table-success' : (st === 'paused' ? 'table-warning' : (isClosest ? 'table-info' : ''));
    const ctrlBtns = st === 'filled' ? '-' : `
      <button class="btn btn-xs btn-outline-warning" onclick="gridAction('${market}',${step.price},'pause')" title="${t('action.pause', 'Pause')}">⏸</button>
      <button class="btn btn-xs btn-outline-danger" onclick="gridAction('${market}',${step.price},'delete')" title="${t('action.delete', 'Delete')}">🗑</button>`;
    return `<tr class="${rowClass}">
        <td>${idx + 1}</td>
        <td>${typeBadge}</td>
        <td class="${priceClass}">${formatAmount(step.price)}${isClosest ? ' ◀' : ''}</td>
        <td>${formatAmount(step.amount || 0)}</td>
        <td><span class="badge ${statusMap[st] || 'bg-secondary'}">${statusLabel[st] || st}</span></td>
        <td>${step.filled ? '<span class="text-success">✓</span>' : '-'}</td>
        <td>-</td>
        <td>${ctrlBtns}</td>
      </tr>`;
  }).join('');
}

// ============================================================
// Ladder Auto-Tuner UI
// ============================================================
async function runLadderAutoTune(dryRun = false) {
  const btn = document.getElementById('btn-ladder-auto-tune');
  if (btn) btn.disabled = true;
  try {
    const res = await authFetch(`/api/ladder/tune/run?dry_run=${dryRun}`, {method: 'POST'});
    const data = await res.json();
    if (!data.ok) { showToast('Auto-tune 실패', 'error'); return; }

    const panel = document.getElementById('ladder-tune-result');
    const tbody = document.getElementById('ladder-tune-result-body');
    panel.classList.remove('d-none');

    const results = data.results || (data.result ? {[data.result.market]: data.result} : {});
    tbody.innerHTML = '';
    for (const [mk, r] of Object.entries(results)) {
      const regimeBadge = {
        'QUIET': 'bg-info', 'NORMAL': 'bg-success', 'ACTIVE': 'bg-warning',
        'EXTREME': 'bg-danger', 'CRASH': 'bg-dark'
      }[r.regime] || 'bg-secondary';
      const cbIcon = r.circuit_breaker ? '🛑' : '✅';
      const adjs = (r.adjustments || []).join(', ') || '-';
      tbody.innerHTML += `<tr>
        <td><strong>${mk.replace(/USDT$/i,'')}</strong></td>
        <td><span class="badge ${regimeBadge}">${r.regime}</span></td>
        <td>${(r.step_pct||0).toFixed(2)}%</td>
        <td>${r.max_steps||0}</td>
        <td>${formatAmount(r.order_usdt||0)}</td>
        <td>×${(r.martingale||1).toFixed(2)}</td>
        <td>${(r.tp_pct||0).toFixed(2)}%</td>
        <td>${(r.trailing_stop_pct||0).toFixed(2)}%</td>
        <td>${cbIcon}</td>
        <td class="small text-muted">${adjs}</td>
      </tr>`;
    }
    showToast(dryRun ? 'Dry Run 완료 (미적용)' : `Auto-tune 적용 완료 (${Object.keys(results).length}개)`, 'success');
  } catch (err) {
    showToast(`Auto-tune 오류: ${err.message}`, 'error');
  } finally {
    if (btn) btn.disabled = false;
  }
}

async function loadTuneHistory() {
  try {
    const res = await authFetch('/api/ladder/tune/history?limit=50');
    const data = await res.json();
    if (!data.ok) return;

    const panel = document.getElementById('ladder-tune-history');
    const tbody = document.getElementById('ladder-tune-history-body');
    panel.classList.remove('d-none');
    tbody.innerHTML = '';

    for (const h of (data.items || [])) {
      const ts = h.timestamp ? new Date(h.timestamp * 1000).toLocaleString('ko-KR', {hour12:false, month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit'}) : '-';
      const regimeBadge = {
        'QUIET': 'bg-info', 'NORMAL': 'bg-success', 'ACTIVE': 'bg-warning',
        'EXTREME': 'bg-danger', 'CRASH': 'bg-dark'
      }[h.regime] || 'bg-secondary';
      tbody.innerHTML += `<tr>
        <td class="small">${ts}</td>
        <td>${(h.market||'').replace(/USDT$/i,'')}</td>
        <td><span class="badge ${regimeBadge} badge-sm">${h.regime||'-'}</span></td>
        <td>${(h.step_pct||0).toFixed(2)}%</td>
        <td>${(h.tp_pct||0).toFixed(2)}%</td>
        <td>${formatAmount(h.order_usdt||0)}</td>
        <td class="small text-muted">${h.reason||'-'}</td>
      </tr>`;
    }
  } catch (err) {
    console.error('Tune history error:', err);
  }
}

async function toggleMarketMode(market) {
  try {
    const m = state.managedMarkets.find(x => x.market === market);
    const currentlyManual = m?.manual_enabled || false;
    const newMode = currentlyManual ? 'auto' : 'manual';
    
    const res = await authFetch(`/api/engine/controls/set?market=${encodeURIComponent(market)}&manual=${newMode === 'manual' ? '1' : '0'}`, { method: 'POST' });
    const data = await res.json();
    if (data.ok) {
      showToast(`${market}: ${newMode.toUpperCase()} mode`, 'success');
      await fetchActiveMarkets();
    } else {
      showToast(data.error || 'Failed', 'error');
    }
  } catch (err) {
    showToast('Mode change failed', 'error');
  }
}

async function disableMarket(market) {
  if (!confirm(tf('confirm.disable_market', 'Disable {market}?', { market }))) return;
  try {
    const res = await authFetch(API.managerSet(market, 'DISABLED', null, 'UI_DISABLE'), { method: 'POST' });
    const data = await res.json();
    if (data.ok) {
      showToast(`${market} disabled`, 'success');
      await fetchActiveMarkets();
    } else {
      showToast(data.error || 'Failed', 'error');
    }
  } catch (err) {
    showToast('Disable failed', 'error');
  }
}

function fillAdminMarket(market) {
  const input = qs('admin-market');
  if (input) input.value = market;
  const panel = qs('oma-admin-panel');
  if (panel) panel.scrollIntoView({ behavior: 'smooth' });
}

function setOmaMarketPage(page) {
  omaMarketPage = page;
  renderOmaMarketList(state.managedMarkets);
}

// ============================================================
// UI Update Functions
// ============================================================

function updateHeaderStats(data) {
  const sys = data.system || data;
  
  // Engine state
  const engineState = sys.engine || 'STOPPED';
  if (qs('stat-engine')) qs('stat-engine').textContent = engineState.toUpperCase();
  
  // Counts
  const activeCount = sys.oma?.active?.length || 0;
  let readyCount = 0;
  if (sys.coordinator) {
    for (const k in sys.coordinator) {
      if (sys.coordinator[k].readiness?.ready) readyCount++;
    }
  }
  if (qs('stat-active')) qs('stat-active').textContent = activeCount;
  if (qs('stat-ready')) qs('stat-ready').textContent = readyCount;
  if (qs('nav-active-count')) qs('nav-active-count').textContent = activeCount;
  if (qs('card-active-count')) qs('card-active-count').textContent = activeCount;
  if (qs('active-count-badge')) qs('active-count-badge').textContent = activeCount;
  
  // Equity
  const equity = sys.equity?.equity_usdt || 0;
  const free = sys.equity?.cash_usdt || 0;
  const deployed = sys.equity?.deployed_usdt || 0;
  const deployRatio = sys.equity?.deploy_ratio || 0.5;
  const available = Math.max(0, equity * deployRatio - deployed);
  
  if (qs('stat-total')) qs('stat-total').textContent = formatAmount(equity);
  if (qs('stat-free')) qs('stat-free').textContent = formatAmount(free);
  if (qs('stat-avail')) qs('stat-avail').textContent = formatAmount(available);
  if (qs('card-total-asset')) qs('card-total-asset').textContent = formatAmount(equity);
  refreshEquitySnapshotCurrentFields(equity);
  recalcEquitySnapshot();
  
  // PnL
  const pnl = sys.session_pnl || 0;
  const pnlEl = qs('stat-pnl');
  if (pnlEl) {
    pnlEl.textContent = (pnl >= 0 ? '+' : '') + formatAmount(pnl);
    pnlEl.className = pnl >= 0 ? 'text-success' : 'text-danger';
  }
  // ★ [2026-05-31 부모] PnL 기산점 표시 — '(vs $XXX)' 형태로 baseline 명시.
  const sinceEl = qs('stat-pnl-since');
  if (sinceEl) {
    const baseline = Number(sys.pnl_baseline || 0);
    sinceEl.textContent = baseline > 0 ? `(vs $${baseline.toFixed(0)})` : '';
  }
  // ★ [2026-05-31 부모 "보기에 좋은 떡이 맛도 좋다"] 📍 한 클릭 baseline reset 핸들러.
  const resetBtn = qs('stat-pnl-reset');
  if (resetBtn && !resetBtn._handlerAttached) {
    resetBtn._handlerAttached = true;
    resetBtn.addEventListener('click', async (e) => {
      e.preventDefault();
      const cur = Number(sys.pnl_baseline || 0);
      const eq = Number(sys.equity?.equity_usdt || 0);  // ★ [2026-05-31 부모] 네스팅 구조 fix
      if (!confirm(`PnL 기산점 reset?\n\n옛 baseline: $${cur.toFixed(2)}\n새 baseline: $${eq.toFixed(2)} (현재 잔액)\n\n→ PnL 0 부터 다시 시작.`)) return;
      try {
        const res = await authFetch('/api/system/pnl-baseline/reset', { method: 'POST' }).then(r => r.json());
        if (res.ok) {
          if (typeof showToast === 'function') showToast(`✅ PnL baseline reset → $${res.baseline.toFixed(2)} (${res.reset_iso})`, 'success');
          else alert(`✅ Reset OK: $${res.baseline.toFixed(2)}`);
        } else {
          alert(`❌ Reset 실패: ${res.message || res.error}`);
        }
      } catch (err) { alert(`❌ Network error: ${err.message}`); }
    });
  }
  const cardPnlEl = qs('card-session-pnl');
  if (cardPnlEl) {
    cardPnlEl.textContent = (pnl >= 0 ? '+' : '') + formatAmount(pnl);
    cardPnlEl.className = 'h2 mb-0 ' + (pnl >= 0 ? 'text-success' : 'text-danger');
  }
  
  // Performance — tick counter + heartbeat dot
  const tickDur = (sys.performance?.tick_duration || 0) * 1000;
  const tickCount = sys.performance?.tick_count || 0;
  const tickEl = qs('stat-tick');
  const tickDotEl = qs('stat-tick-dot');
  if (tickEl) {
    const countStr = tickCount > 0 ? tickCount.toLocaleString() + ' · ' : '';
    tickEl.textContent = countStr + (tickDur < 10 ? tickDur.toFixed(1) : tickDur.toFixed(0)) + 'ms';
    tickEl.className = tickDur > 1000 ? 'text-danger' : (tickDur > 500 ? 'text-warning' : 'text-success');
  }
  if (tickDotEl && tickCount > 0) {
    // 하트비트: 틱 카운트가 바뀌면 녹색으로 깜빡이고 4초간 점등 유지
    const prevCount = parseInt(tickDotEl.dataset.prevCount || '0');
    if (tickCount !== prevCount) {
      const dotColor = tickDur > 1000 ? '#dc3545' : (tickDur > 500 ? '#ffc107' : '#28a745');
      const glowColor = tickDur > 1000 ? 'rgba(220,53,69,0.6)' : (tickDur > 500 ? 'rgba(255,193,7,0.5)' : 'rgba(40,167,69,0.5)');
      tickDotEl.style.background = dotColor;
      tickDotEl.style.boxShadow = `0 0 6px 2px ${glowColor}`;
      // 펄스 애니메이션 트리거
      tickDotEl.classList.remove('tick-dot-on');
      void tickDotEl.offsetWidth; // reflow 강제
      tickDotEl.classList.add('tick-dot-on');
      tickDotEl.dataset.prevCount = tickCount;
      clearTimeout(tickDotEl._dimTimer);
      tickDotEl._dimTimer = setTimeout(() => {
        tickDotEl.style.background = '#6c757d';
        tickDotEl.style.boxShadow = 'none';
        tickDotEl.classList.remove('tick-dot-on');
      }, 4000);
    }
  }
  
  const apiCalls = sys.api_stats?.calls_per_min || 0;
  if (qs('stat-api')) {
    qs('stat-api').textContent = apiCalls;
    qs('stat-api').className = apiCalls > 800 ? 'text-danger' : (apiCalls > 500 ? 'text-warning' : 'text-success');
  }
}

function updateEngineStatus(data) {
  const sys = data.system || data;
  const dot = qs('engine-status-dot');
  const text = qs('engine-status-text');
  const envBadge = qs('env-badge');

  if (dot && text) {
    if (sys.engine_running || sys.engine === 'RUNNING' || sys.engine) {
      dot.className = 'status-dot live';
      text.textContent = 'Running';
    } else if (sys.emergency_stop) {
      dot.className = 'status-dot stopped';
      text.textContent = 'E-STOP';
    } else {
      dot.className = 'status-dot dry';
      text.textContent = 'Stopped';
    }
  }

  if (envBadge) {
    const isLive = sys.is_live || (sys.trading_mode && sys.trading_mode.toUpperCase() === 'LIVE');
    if (isLive) {
      envBadge.className = 'badge bg-danger';
      envBadge.textContent = 'LIVE';
    } else {
      envBadge.className = 'badge bg-warning';
      envBadge.textContent = 'DRY';
    }
  }

  // [TRIAGE MODE] 패널 업데이트
  const triage = (data.triage) || (sys.triage) || {};
  const triagePanelRow = qs('triage-panel-row');
  if (triagePanelRow) {
    const active = !!triage.active;
    triagePanelRow.style.setProperty('display', active ? 'flex' : 'none', 'important');
    if (active) {
      const stateBadge = qs('triage-state-badge');
      if (stateBadge) stateBadge.textContent = triage.state || 'TRIAGE';
      const focusEl = qs('triage-focus-market');
      if (focusEl) {
        const targets = triage.active_targets || [];
        if (targets.length > 0) {
          focusEl.textContent = targets.map(t => {
            const m = (t.market || '?').replace(/USDT$/i,'');
            const s = (t.state || 'DCA').charAt(0);
            return `${m}(${s})`;
          }).join(', ');
        } else if (triage.current_target) {
          // 하위 호환
          const ct = triage.current_target;
          focusEl.textContent = typeof ct === 'object' ? (ct.market || '-') : ct;
        } else {
          focusEl.textContent = 'SCAN';
        }
      }
      const recEl = qs('triage-recovered-count');
      if (recEl) recEl.textContent = (triage.recovered || []).length;
      const skipEl = qs('triage-skipped-count');
      if (skipEl) skipEl.textContent = (triage.skipped || []).length;
      const elapsedEl = qs('triage-elapsed');
      if (elapsedEl && triage.elapsed_sec != null) {
        const s = Math.round(triage.elapsed_sec);
        elapsedEl.textContent = s < 60 ? `${s}s` : `${Math.floor(s/60)}m${s%60}s`;
      }
      // Emergency Exit 상태 표시
      const emInfo = triage.emergency_exit;
      if (stateBadge && emInfo && emInfo.severity && emInfo.severity !== 'normal') {
        const sev = emInfo.severity.startsWith('emergency') ? 'EMG' : 'MOD';
        stateBadge.textContent = `${triage.state || 'TRIAGE'} [${sev}]`;
      }
    }
  }
}

async function triageSkip() {
  try {
    const res = await authFetch('/api/triage/skip', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ reason: 'manual skip from dashboard' }) });
    const d = await res.json();
    showToast(d.success ? `Skipped: ${d.skipped_market}` : (d.message || 'Skip failed'), d.success ? 'success' : 'warning');
    await fetchSystemStatus();
  } catch (err) { showToast('Triage skip failed', 'error'); }
}

async function triageExit() {
  if (!confirm('트리아지 모드를 수동 종료합니다. 계속하시겠습니까?')) return;
  try {
    const res = await authFetch('/api/triage/exit', { method: 'POST' });
    const d = await res.json();
    showToast(d.success ? 'Triage mode exited' : (d.message || 'Exit failed'), d.success ? 'success' : 'warning');
    await fetchSystemStatus();
  } catch (err) { showToast('Triage exit failed', 'error'); }
}

function renderActiveMarkets(markets) {
  const container = qs('active-market-list');
  if (!container) return;

  // 2026-03-25: OMA ACTIVE/RECOVERY 상태면 무조건 표시 (예산 배정 후 매수 대기 중인 마켓도 포함)
  const filteredMarkets = markets.filter(m => {
    const st = String(m.state || '').toUpperCase();
    return st === 'ACTIVE' || st === 'RECOVERY';
  });

  // 2026-04-04: FOCUS 포지션을 Active 리스트에 병합
  try {
    const focusStatus = state._focusStatus;
    if (focusStatus && focusStatus.enabled) {
      const focusPositions = focusStatus.positions || [];
      const focusState = focusStatus.state || 'DORMANT';
      if (focusPositions.length > 0) {
        focusPositions.forEach(fp => {
          if (fp.market && !filteredMarkets.find(m => m.market === fp.market && m.strategy === 'FOCUS')) {
            const pnl = fp.entry_price > 0
              ? ((fp.direction === 'SHORT' ? -1 : 1) * ((state.prices?.[fp.market]?.price || fp.entry_price) / fp.entry_price - 1) * 100)
              : 0;
            filteredMarkets.push({
              market: fp.market,
              state: 'ACTIVE',
              strategy: 'FOCUS',
              current_price: state.prices?.[fp.market]?.price || fp.entry_price,
              entry_price: fp.entry_price,
              pnl_pct: pnl,
              position: { entry: fp.entry_price, qty: fp.qty },
            });
          }
        });
      } else if (focusState !== 'DORMANT' && focusState !== 'DISABLED' && focusStatus.selected_market) {
        // FOCUS가 코인 탐색/감시 중이면 표시
        if (!filteredMarkets.find(m => m.market === focusStatus.selected_market && m.strategy === 'FOCUS')) {
          filteredMarkets.push({
            market: focusStatus.selected_market,
            state: 'ACTIVE',
            strategy: 'FOCUS',
            current_price: 0,
            entry_price: 0,
            pnl_pct: 0,
            position: null,
          });
        }
      }
    }
  } catch (e) { /* FOCUS merge error — non-blocking */ }

  if (!filteredMarkets.length) {
    container.innerHTML = `<div class="empty-state"><i class="ti ti-inbox"></i>${t('empty.active_markets', 'No active markets')}</div>`;
    return;
  }

  container.innerHTML = filteredMarkets.slice(0, 20).map(m => {
    const pnlPct = m.pnl_pct || 0;
    const pnlClass = getPnlClass(pnlPct);
    const strategyBadge = getStrategyBadgeClass(m.strategy);
    
    // 2026-02-02: 트렌드 표시 (상승중/하락중/보합중)
    const trendText = pnlPct > 0.5
      ? t('trend.up', 'Uptrend')
      : pnlPct < -0.5
        ? t('trend.down', 'Downtrend')
        : t('trend.flat', 'Sideways');
    const trendIcon = pnlPct > 0.5 ? 'ti-trending-up' : pnlPct < -0.5 ? 'ti-trending-down' : 'ti-minus';
    const trendColor = pnlPct > 0.5 ? 'text-success' : pnlPct < -0.5 ? 'text-danger' : 'text-muted';
    
    // 2026-02-02: PnL USDT 계산
    const entryPrice = m.entry_price || m.position?.entry || 0;
    const posQty = m.position?.qty || 0;
    const currentPrice = m.current_price || 0;
    const pnlUsdt = posQty > 0 && entryPrice > 0 ? (currentPrice - entryPrice) * posQty : 0;
    
    return `
      <div class="market-item ${state.selectedMarket === m.market ? 'selected' : ''}" 
           onclick="selectMarket('${m.market}')" style="cursor:pointer;">
        <div class="d-flex justify-content-between align-items-center w-100">
          <div>
            <strong>${extractBase(m.market)}</strong>
            <span class="badge ${strategyBadge} badge-strategy ms-1">${m.strategy || '-'}</span>
            <span class="small ${trendColor} ms-1"><i class="ti ${trendIcon}"></i> ${trendText}</span>
          </div>
          <div class="text-end">
            <div class="${pnlClass} fw-bold">${formatPercent(pnlPct)}</div>
            <div class="small ${pnlUsdt >= 0 ? 'text-success' : 'text-danger'}">${pnlUsdt >= 0 ? '+' : ''}${formatAmount(pnlUsdt)}</div>
          </div>
        </div>
      </div>
    `;
  }).join('');
}

