// 2026-02-02: Reserved 클릭 시 Quick Trade 마켓 선택
function fillQuickTradeMarket(market) {
  const qtMarket = qs('qt-market');
  if (qtMarket) {
    // select에 해당 옵션이 없으면 임시 추가
    if (!qtMarket.querySelector(`option[value="${market}"]`)) {
      const opt = document.createElement('option');
      opt.value = market;
      opt.textContent = market.replace(/USDT$/i,'');
      qtMarket.insertBefore(opt, qtMarket.querySelector('option[value="__ALL__"]'));
    }
    qtMarket.value = market;
    updateQuickTradePrice(market);
  }
}

function inferAutoManualMode(omaReason, ctx) {
  const reasons = (omaReason || []).map(r => String(r).toLowerCase());
  const has = (tokens) => reasons.some(r => tokens.some(t => r.includes(t)));
  
  // Manual hints first (explicit)
  if (has(['manual', 'ui', 'api', 'debug'])) return 'M';
  
  // Auto hints (reserved/autopilot/rebalance/etc)
  if (has([
    'autopilot',
    'autoapprove',
    'reserved_approve',
    'strategy_recommendations',
    'perf_rebalance',
    'graduation',
    'signal_miss',
    'idle',
    'candidate',
    'queue',
  ])) return 'A';
  
  // Strategy-specific manual/auto hint (LADDER tune_mode)
  const tuneMode = ctx?.controls?.strategy?.params?.tune_mode;
  if (tuneMode) {
    return String(tuneMode).toUpperCase() === 'AUTO' ? 'A' : 'M';
  }
  
  return '-';
}

function renderMarketsTable(markets) {
  const tbody = qs('markets-table-body');
  if (!tbody) return;
  
  // 2026-01-30: 포지션이 있거나 전략이 설정된 마켓 표시
  const filteredMarkets = markets.filter(m => {
    const posQty = m.position?.qty || m.context?.position?.qty || 0;
    const hasPosition = posQty > 0;
    const strategy = (m.strategy || '').toUpperCase();
    const validStrategies = ['AUTOLOOP', 'PINGPONG', 'CONTRARIAN', 'SNIPER', 'GAZUA', 'LADDER', 'LIGHTNING', 'WHALE'];
    const hasValidStrategy = validStrategies.includes(strategy);
    return hasPosition || hasValidStrategy;
  });
  
  if (!filteredMarkets.length) {
    tbody.innerHTML = '<tr><td colspan="11" class="text-center text-muted">No active markets</td></tr>';
    return;
  }
  
  tbody.innerHTML = filteredMarkets.map(m => {
    const pnlClass = getPnlClass(m.pnl_pct || 0);
    const strategyBadge = getStrategyBadgeClass(m.strategy);
    const amMode = m.origin_mode || inferAutoManualMode(m.oma_reason, m.context);
    const amBadge = amMode === 'A'
      ? '<span class="badge bg-primary-lt">A</span>'
      : (amMode === 'M' ? '<span class="badge bg-warning-lt">M</span>' : '<span class="text-muted">-</span>');
    const h = m.hold_hours;
    const holdText = h != null ? (h >= 24 ? `${(h/24).toFixed(1)}d` : `${h.toFixed(1)}h`) : '-';
    const holdClass = h != null && h >= 24 ? 'text-warning' : '';
    const holdTitle = h != null && h >= 24 ? '24시간 이상 보유 중' : '';
    return `
      <tr>
        <td><input type="checkbox" class="form-check-input market-checkbox" data-market="${m.market}"></td>
        <td><a href="/ui/market_detail.html?market=${m.market}" target="_blank">${extractBase(m.market)}</a></td>
        <td><span class="badge ${strategyBadge}">${m.strategy || '-'}</span></td>
        <td>${m.state || 'ACTIVE'}</td>
        <td>${amBadge}</td>
        <td>${formatAmount(m.entry_price)}</td>
        <td>${formatAmount(m.current_price)}</td>
        <td class="${pnlClass}">${formatPercent(m.pnl_pct || 0)}</td>
        <td class="${holdClass}" title="${holdTitle}">${holdText}</td>
        <td>${formatAmount(m.budget_usdt)}</td>
        <td>
          <button class="btn btn-ghost-danger btn-sm" onclick="deactivateMarket('${m.market}')">
            <i class="ti ti-x"></i>
          </button>
        </td>
      </tr>
    `;
  }).join('');
}

function renderReservedTable(items) {
  const tbody = qs('reserved-table-body');
  if (!tbody) return;
  
  if (!items.length) {
    tbody.innerHTML = `<tr><td colspan="9" class="text-center text-muted">${t('empty.no_recommendations', 'No recommendations')}</td></tr>`;
    return;
  }
  
    tbody.innerHTML = items.map(c => {
      const strategyBadge = getStrategyBadgeClass(c.strategy);
      const metrics = c.metrics || {};
      const rsi = metrics.rsi || 50;
      const change24h = metrics.change_24h || 0;
      const price = metrics.price || 0;
      const activeStrategy = c.active_strategy || null;
      const isManagedLocally = state.managedMarkets.some(m => m.market === c.market);
      const usedStrategy = activeStrategy || (isManagedLocally ? state.managedMarkets.find(m => m.market === c.market)?.strategy : null);
      const isInUse = !!usedStrategy;
      const inUseTitle = tf('status.market_in_use_title', 'Already in use by {strategy}', { strategy: usedStrategy || '-' });
      const inUseBadge = isInUse ? `<span class="badge bg-warning text-dark ms-1" title="${inUseTitle}">⚠️ ${usedStrategy}</span>` : '';
    
    // RSI 색상: 30 미만=초록(과매도), 70 초과=빨강(과매수)
    const rsiClass = rsi < 30 ? 'text-success' : (rsi > 70 ? 'text-danger' : '');
    // 24h 변동률 색상
    const changeClass = change24h > 0 ? 'text-success' : (change24h < 0 ? 'text-danger' : '');
    
      const rowClass = isInUse ? 'table-secondary' : '';
      const approveAttrs = isInUse
        ? `disabled title="${t('status.market_in_use_other_strategy', 'Already in use by another strategy')}"`
        : `title="${t('action.approve', 'Approve')}"`;
      return `
        <tr class="${rowClass}">
          <td>${extractBase(c.market)}${inUseBadge ? ` ${inUseBadge}` : ''}</td>
          <td><span class="badge ${strategyBadge}">${c.strategy || '-'}</span></td>
          <td class="${changeClass}">${formatAmount(price)}</td>
          <td class="${rsiClass}">${rsi.toFixed(1)}</td>
          <td class="${changeClass}">${change24h >= 0 ? '+' : ''}${change24h.toFixed(2)}%</td>
          <td>${c.ai_score ? (c.ai_score * 100).toFixed(0) + '%' : '-'}</td>
          <td>${formatAmount(c.suggested_budget_usdt)}</td>
          <td class="small text-muted">${c.reason || '-'}</td>
          <td>
            <button class="btn btn-success btn-sm" onclick="approveReserved('${c.id || c.rid}')" ${approveAttrs}>
              <i class="ti ti-check"></i>
            </button>
          <button class="btn btn-ghost-danger btn-sm" onclick="rejectReserved('${c.id || c.rid}')">
            <i class="ti ti-x"></i>
          </button>
        </td>
      </tr>
    `;
  }).join('');
}

