function updateMarketDatalist(markets) {
  const datalist = qs('market-datalist');
  if (!datalist) return;
  
  const allMarkets = new Set(markets.map(m => m.market));
  state.allKnownMarkets.forEach(m => allMarkets.add(m));
  
  datalist.innerHTML = Array.from(allMarkets).map(m => `<option value="${m}">`).join('');
}

