function getKimchiPremium(market) {
  if (!state.kimchiData || !market) return null;
  const m = market.toUpperCase();
  return state.kimchiData[m] || state.kimchiData[m.replace(/USDT$/i,'')] || null;
}

function renderKimchiBadge(market, compact = false) {
  const data = getKimchiPremium(market);
  if (!data || data.premium_pct == null) return '';
  
  const pct = data.premium_pct;
  const cls = pct > 5 ? 'bg-danger' : (pct > 2 ? 'bg-warning' : (pct < -2 ? 'bg-success' : 'bg-secondary'));
  const sign = pct >= 0 ? '+' : '';
  
  if (compact) {
    return `<span class="badge ${cls} badge-sm" title="${t('label.kimchi', 'Kimchi')} ${sign}${pct.toFixed(1)}%">${sign}${pct.toFixed(1)}%</span>`;
  }
  return `<span class="badge ${cls}">${t('label.kimchi', 'Kimchi')} ${sign}${pct.toFixed(1)}%</span>`;
}

