// ============================================================
// Market Datalist Ensure
// ============================================================

function ensureMarketDatalist() {
  let datalist = document.getElementById('market-datalist');
  if (!datalist) {
    datalist = document.createElement('datalist');
    datalist.id = 'market-datalist';
    document.body.appendChild(datalist);
  }
  
  const markets = new Set();
  
  (state.managedMarkets || []).forEach(m => {
    if (typeof m === 'string') markets.add(m);
    else if (m.market) markets.add(m.market);
  });
  
  Object.keys(state.prices || {}).forEach(m => markets.add(m));
  
  datalist.innerHTML = Array.from(markets).sort().map(m => 
    `<option value="${m}">`
  ).join('');
}

// ============================================================
// PnL Panel Detail Rendering
// ============================================================

function getPnlBaselineMap() {
  try {
    const data = localStorage.getItem(LS_PNL_BASELINES);
    return data ? JSON.parse(data) : {};
  } catch (e) {
    return {};
  }
}

function setPnlBaselineMap(map) {
  try {
    localStorage.setItem(LS_PNL_BASELINES, JSON.stringify(map));
  } catch (e) {}
}

function setPnlBaseline(market, equity) {
  const map = getPnlBaselineMap();
  map[market] = { equity, ts: new Date().toISOString() };
  setPnlBaselineMap(map);
}

function renderPnlByCoin(rows) {
  const container = qs('pnl-coin-table');
  if (!container) return;
  
  if (!rows.length) {
    container.innerHTML = `<div class="text-muted text-center py-3">${t('empty.no_pnl_data', 'No PnL data')}</div>`;
    return;
  }
  
  container.innerHTML = `
    <div class="table-responsive" style="max-height: 350px; overflow-y: auto;">
      <table class="table table-sm table-hover">
        <thead>
          <tr>
            <th>${t('table.market_kr', 'Market')}</th>
            <th>${t('table.strategy_kr', 'Strategy')}</th>
            <th class="text-end">${t('table.allocated', 'Allocated')}</th>
            <th class="text-end">${t('table.current', 'Current')}</th>
            <th class="text-end">${t('table.pnl_usdt', 'PnL')}</th>
            <th class="text-end">%</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          ${rows.map(r => `
            <tr>
              <td><strong>${extractBase(r.market)}</strong></td>
              <td>${renderStrategyBadge(r.strategy)}</td>
              <td class="text-end">${fmtUsdt(r.allocated_usdt)}</td>
              <td class="text-end">${fmtUsdt(r.equity_usdt)}</td>
              <td class="text-end ${r.pnl_usdt >= 0 ? 'text-success' : 'text-danger'}">
                ${r.pnl_usdt >= 0 ? '+' : ''}${fmtUsdt(r.pnl_usdt)}
              </td>
              <td class="text-end ${r.pnl_pct >= 0 ? 'text-success' : 'text-danger'}">
                ${fmtPct(r.pnl_pct)}
              </td>
              <td>
                <button class="btn btn-ghost-secondary btn-sm p-0" onclick="resetPnlBaseline('${r.market}')" title="${t('action.reset_baseline', 'Reset baseline')}">
                  <i class="ti ti-refresh"></i>
                </button>
              </td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    </div>
  `;
}

function renderPnlByStrategy(rows) {
  const container = qs('pnl-strategy-table');
  if (!container) return;
  
  // 전략별로 그룹화
  const byStrategy = {};
  rows.forEach(r => {
    const strat = r.strategy || 'UNKNOWN';
    if (!byStrategy[strat]) byStrategy[strat] = { pnl: 0, count: 0, allocated: 0 };
    byStrategy[strat].pnl += r.pnl_usdt || 0;
    byStrategy[strat].count += 1;
    byStrategy[strat].allocated += r.allocated_usdt || 0;
  });
  
  const stratRows = Object.entries(byStrategy).map(([strat, data]) => ({
    strategy: strat,
    ...data,
    pnl_pct: data.allocated > 0 ? (data.pnl / data.allocated) * 100 : 0
  })).sort((a, b) => b.pnl - a.pnl);
  
  if (!stratRows.length) {
    container.innerHTML = `<div class="text-muted text-center py-3">${t('empty.no_pnl_data', 'No PnL data')}</div>`;
    return;
  }
  
  container.innerHTML = `
    <div class="table-responsive">
      <table class="table table-sm">
        <thead>
          <tr>
            <th>${t('table.strategy_kr', 'Strategy')}</th>
            <th class="text-center">${t('table.market_count', 'Markets')}</th>
            <th class="text-end">${t('table.allocated', 'Allocated')}</th>
            <th class="text-end">${t('table.pnl_usdt', 'PnL')}</th>
            <th class="text-end">%</th>
          </tr>
        </thead>
        <tbody>
          ${stratRows.map(r => `
            <tr>
              <td>${renderStrategyBadge(r.strategy)}</td>
              <td class="text-center">${r.count}</td>
              <td class="text-end">${fmtUsdt(r.allocated)}</td>
              <td class="text-end ${r.pnl >= 0 ? 'text-success' : 'text-danger'}">
                ${r.pnl >= 0 ? '+' : ''}${fmtUsdt(r.pnl)}
              </td>
              <td class="text-end ${r.pnl_pct >= 0 ? 'text-success' : 'text-danger'}">
                ${fmtPct(r.pnl_pct)}
              </td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    </div>
  `;
}

async function renderPnlPanels() {
  const coinContainer = qs('pnl-coin-table');
  const stratContainer = qs('pnl-strategy-table');
  if (!coinContainer && !stratContainer) return;
  
  const sys = state.system || {};
  const coord = sys.coordinator || state.coordinator || {};
  const prices = state.prices || {};
  
  // Get active markets
  const oma = sys.oma || state.oma || {};
  const activeArr = (Array.isArray(oma.active) ? oma.active : []).map(x => typeof x === 'string' ? x : x.market).filter(Boolean);
  const recoveryArr = (Array.isArray(oma.recovery) ? oma.recovery : []).map(x => typeof x === 'string' ? x : x.market).filter(Boolean);
  const markets = [...new Set([...activeArr, ...recoveryArr])];
  
  const baselineMap = getPnlBaselineMap();
  const rows = [];
  
  for (const market of markets) {
    const ctx = coord[market] || {};
    const mkt = state.managedMarkets.find(m => m.market === market) || {};
    
    let allocated = parseFloat(ctx.allocated_capital) || mkt.budget_usdt || 0;
    const cash = parseFloat(ctx.usable_capital) || 0;
    const pos = ctx.position || mkt.position || null;
    const qty = pos ? parseFloat(pos.qty) || 0 : 0;
    const px = parseFloat(prices[market]?.price || prices[market] || 0);
    const posValue = qty > 0 && px > 0 ? qty * px : 0;
    const equity = posValue > 0 ? posValue : cash;
    
    if (!allocated && !equity) continue;
    
    const base = baselineMap[market];
    const denom = base?.equity > 0 ? base.equity : allocated;
    const pnl = base?.equity > 0 ? (equity - base.equity) : (equity - allocated);
    const pnlPct = denom > 0 ? (pnl / denom) * 100 : 0;
    
    rows.push({
      market,
      state: mkt.state || 'ACTIVE',
      strategy: mkt.strategy || ctx.strategy || '-',
      allocated_usdt: allocated,
      equity_usdt: equity,
      pnl_usdt: pnl,
      pnl_pct: pnlPct,
      manualEnabled: mkt.manual_enabled || ctx.controls?.manual?.enabled || false,
      hasPosition: qty > 0
    });
  }
  
  // Sort by PnL (worst first)
  rows.sort((a, b) => a.pnl_usdt - b.pnl_usdt);
  
  // Calculate totals
  const totalAlloc = rows.reduce((s, r) => s + r.allocated_usdt, 0);
  const totalEquity = rows.reduce((s, r) => s + r.equity_usdt, 0);
  const totalPnl = totalEquity - totalAlloc;
  const totalPct = totalAlloc > 0 ? (totalPnl / totalAlloc) * 100 : 0;
  
  const summaryEl = qs('pnl-summary');
  if (summaryEl) {
    const pnlClass = totalPnl >= 0 ? 'text-success' : 'text-danger';
    summaryEl.innerHTML = `Total: <span class="${pnlClass} fw-bold">${formatAmount(totalPnl)} (${totalPct >= 0 ? '+' : ''}${totalPct.toFixed(2)}%)</span>`;
  }
  
  // 상단 PnL 헤더에도 반영
  const statPnlEl = qs('stat-pnl');
  if (statPnlEl && totalPnl !== 0) {
    statPnlEl.textContent = (totalPnl >= 0 ? '+' : '') + formatAmount(totalPnl);
    statPnlEl.className = totalPnl >= 0 ? 'text-success' : 'text-danger';
  }
  
  // Render both views
  renderPnlByCoin(rows);
  renderPnlByStrategy(rows);
}

function resetPnlBaseline(market) {
  const mkt = state.managedMarkets.find(m => m.market === market);
  const ctx = (state.system?.coordinator || state.coordinator || {})[market] || {};
  const pos = ctx.position || mkt?.position || null;
  const qty = pos ? parseFloat(pos.qty) || 0 : 0;
  const px = parseFloat(state.prices[market]?.price || state.prices[market] || 0);
  const cash = parseFloat(ctx.usable_capital || 0);
  const equity = qty > 0 && px > 0 ? qty * px : cash;
  
  setPnlBaseline(market, equity);
  showToast(`PnL baseline reset: ${market}`, 'success');
  renderPnlPanels();
}

function resetAllPnlBaselines() {
  const map = {};
  state.managedMarkets.forEach(mkt => {
    const ctx = (state.system?.coordinator || state.coordinator || {})[mkt.market] || {};
    const pos = ctx.position || mkt.position || null;
    const qty = pos ? parseFloat(pos.qty) || 0 : 0;
    const px = parseFloat(state.prices[mkt.market]?.price || state.prices[mkt.market] || 0);
    const cash = parseFloat(ctx.usable_capital || 0);
    const equity = qty > 0 && px > 0 ? qty * px : cash;
    map[mkt.market] = { equity, ts: new Date().toISOString() };
  });
  setPnlBaselineMap(map);
  showToast('All PnL baselines reset', 'success');
  renderPnlPanels();
}

function bindPnlEvents() {
  qs('btn-refresh-pnl')?.addEventListener('click', renderPnlPanels);
  qs('btn-refresh-am-report')?.addEventListener('click', () => fetchAutoManualReport());
  qs('am-detail-mode')?.addEventListener('change', () => renderAutoManualDetails(state.autoManualReport));
  qs('am-detail-strategy')?.addEventListener('change', () => renderAutoManualDetails(state.autoManualReport));
  qs('am-detail-limit')?.addEventListener('change', () => renderAutoManualDetails(state.autoManualReport));
  qs('btn-reset-pnl-all')?.addEventListener('click', () => {
    if (!confirm(t('confirm.reset_all_pnl_baselines', 'Reset all market PnL baselines to current values?'))) return;
    resetAllPnlBaselines();
  });
}

