async function loadSectorMap() {
  try {
    const res = await authFetch(API.sectorMap);
    const data = await res.json();
    if (data.ok) {
      renderSectorList(data.sectors || {});
    }
  } catch (err) {
    console.error('Sector Map 로드 실패:', err);
  }
}

function renderSectorList(sectors) {
  const container = qs('sector-list');
  const select = qs('sector-select');
  if (!container) return;
  
  const sectorIds = Object.keys(sectors);
  
  if (!sectorIds.length) {
    container.innerHTML = `<div class="text-muted">${t('empty.no_sector_data', 'No sector data')}</div>`;
    return;
  }
  
  container.innerHTML = sectorIds.map(sid => {
    const s = sectors[sid];
    const coins = (s.coins || []).join(', ');
    return `
      <div class="card card-sm mb-2">
        <div class="card-body py-2">
          <div class="d-flex justify-content-between align-items-center mb-1">
            <strong>${s.name || sid}</strong>
            <span class="text-muted small">${sid}</span>
          </div>
          <div class="d-flex gap-3 align-items-center">
            <label class="small">
              Cap: <input type="number" class="form-control form-control-sm d-inline-block sector-cap-input" 
                data-sector="${sid}" value="${((s.cap || 0.4) * 100).toFixed(0)}" min="5" max="100" step="5" style="width: 60px;"> %
            </label>
            <span class="small text-muted flex-grow-1">${coins || '(no coins)'}</span>
          </div>
        </div>
      </div>
    `;
  }).join('');
  
  if (select) {
    select.innerHTML = sectorIds.map(sid => 
      `<option value="${sid}">${sectors[sid].name || sid}</option>`
    ).join('') + '<option value="OTHERS">OTHERS</option>';
  }
  
  state.sectorData = sectors;
}

async function saveSectorMap() {
  const msgEl = qs('sector-modal-msg');
  
  const updatedSectors = JSON.parse(JSON.stringify(state.sectorData || {}));
  document.querySelectorAll('.sector-cap-input').forEach(el => {
    const sid = el.dataset.sector;
    const cap = parseFloat(el.value) / 100;
    if (updatedSectors[sid]) {
      updatedSectors[sid].cap = Math.max(0.05, Math.min(1.0, cap));
    }
  });
  
  try {
    const res = await authFetch(API.sectorMap, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sectors: updatedSectors,
        default_sector: 'OTHERS',
        default_cap: 0.4
      })
    });
    const result = await res.json();
    if (result.ok) {
      if (msgEl) msgEl.textContent = `✅ ${tf('status.save_complete_with_count', 'Saved ({count} sectors)', { count: result.sectors_count })}`;
      showToast('Sector Map saved', 'success');
    } else {
      if (msgEl) msgEl.textContent = `❌ ${t('label.error', 'Error')}: ${result.error}`;
    }
  } catch (err) {
    if (msgEl) msgEl.textContent = `❌ ${t('label.error', 'Error')}: ${err.message}`;
  }
}

async function setCoinSector() {
  const coin = qs('sector-coin-input')?.value.trim().toUpperCase();
  const sector = qs('sector-select')?.value;
  const msgEl = qs('sector-modal-msg');
  
  if (!coin) {
    if (msgEl) msgEl.textContent = t('error.enter_coin_code_example', 'Enter symbol (e.g. BTCUSDT)');
    return;
  }
  
  try {
    const res = await authFetch(API.sectorMapCoin(coin, sector), { method: 'POST' });
    const result = await res.json();
    if (result.ok) {
      if (msgEl) msgEl.textContent = `✅ ${tf('status.coin_sector_set', '{coin} -> {sector} set', { coin, sector })}`;
      if (qs('sector-coin-input')) qs('sector-coin-input').value = '';
    } else {
      if (msgEl) msgEl.textContent = `❌ ${t('label.error', 'Error')}: ${result.error}`;
    }
  } catch (err) {
    if (msgEl) msgEl.textContent = `❌ ${t('label.error', 'Error')}: ${err.message}`;
  }
}

function bindSettingsEvents() {
  qs('btn-refresh-settings')?.addEventListener('click', fetchSettingsInfo);
  
  qs('btn-reconcile')?.addEventListener('click', async () => {
    if (!confirm(t('confirm.reconcile_exchange_oma', 'Sync Bybit balances with OMA state?'))) return;
    try {
      showToast('Reconciling...', 'info');
      const res = await authFetch(API.systemReconcile, { method: 'POST' });
      const data = await res.json();
      if (data.ok) {
        showToast('Reconcile complete', 'success');
        await fetchActiveMarkets();
      } else {
        showToast(data.error || 'Reconcile failed', 'error');
      }
    } catch (err) {
      showToast('Reconcile failed: ' + err.message, 'error');
    }
  });
  
  qs('btn-open-sector-map')?.addEventListener('click', () => {
    loadSectorMap();
    const modal = new bootstrap.Modal(document.getElementById('sector-map-modal'));
    modal.show();
  });
  
  qs('btn-save-sector-map')?.addEventListener('click', saveSectorMap);
  qs('btn-set-coin-sector')?.addEventListener('click', setCoinSector);
  
  qs('btn-settings-clear-dust')?.addEventListener('click', async () => {
    if (!confirm(t('confirm.clear_small_balances', 'Clear small balances?'))) return;
    try {
      const res = await authFetch(API.clearDust, { method: 'POST' });
      const data = await res.json();
      if (data.ok) {
        showToast(`Cleared ${data.count || 0} dust positions`, 'success');
      } else {
        showToast(data.error || 'Clear failed', 'error');
      }
    } catch (err) {
      showToast('Clear failed: ' + err.message, 'error');
    }
  });
  
  // ============================================================
  // [2026-02-01] Dust Vacuum (Real Cleanup)
  // ============================================================
  let dustList = [];
  
  qs('btn-scan-dust')?.addEventListener('click', async () => {
    const btn = qs('btn-scan-dust');
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Scanning...';
    
    try {
      const res = await authFetch(API.dustScan);
      const data = await res.json();
      
      if (data.ok && data.dust?.length > 0) {
        dustList = data.dust;
        const totalValue = dustList.reduce((sum, d) => sum + d.value_usdt, 0);
        const totalNeedBuy = dustList.reduce((sum, d) => sum + d.need_buy_usdt, 0);
        
        showToast(`Found ${data.count} dust coins ($${totalValue.toFixed(0)}). Need $${totalNeedBuy.toFixed(0)} to vacuum.`, 'warning');
        qs('btn-vacuum-dust').disabled = false;
        qs('btn-adopt-dust').disabled = false;
      } else if (data.ok) {
        showToast('No dust found! 🎉', 'success');
        dustList = [];
        qs('btn-vacuum-dust').disabled = true;
        qs('btn-adopt-dust').disabled = true;
      } else {
        showToast('Scan failed: ' + (data.error || 'Unknown'), 'error');
      }
    } catch (err) {
      showToast('Scan failed: ' + err.message, 'error');
    } finally {
      btn.disabled = false;
      btn.innerHTML = '<i class="ti ti-search me-1"></i>Scan Dust';
    }
  });
  
  qs('btn-vacuum-dust')?.addEventListener('click', async () => {
    if (dustList.length === 0) {
      showToast('No dust to vacuum. Scan first.', 'warning');
      return;
    }
    
    const totalNeedBuy = dustList.reduce((sum, d) => sum + d.need_buy_usdt, 0);
    if (!confirm(tf('confirm.vacuum_dust',
        'Run dust vacuum now?\n\n🪙 {count} coins\n💸 Required budget: ${budget}\n\n⚠️ Buy at least 5 USDT for each coin then sell all.\n\nContinue?',
        { count: dustList.length, budget: totalNeedBuy.toLocaleString() }))) {
      return;
    }
    
    const btn = qs('btn-vacuum-dust');
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Vacuuming...';
    
    try {
      const res = await authFetch(API.dustVacuumAll(false, 10), { method: 'POST' });
      const data = await res.json();
      
      if (data.ok) {
        const successCount = data.results?.filter(r => r.result?.ok).length || 0;
        showToast(`Vacuumed ${successCount}/${data.vacuumed_count} dust coins! 🧹`, 'success');
        dustList = [];
        
        // Refresh PnL
        setTimeout(() => loadPnL(), 2000);
      } else {
        showToast('Vacuum failed: ' + (data.error || 'Unknown'), 'error');
      }
    } catch (err) {
      showToast('Vacuum failed: ' + err.message, 'error');
    } finally {
      btn.disabled = true;
      btn.innerHTML = '<i class="ti ti-vacuum me-1"></i>Vacuum All';
    }
  });
  
  // btn-adopt-dust: 먼지를 LongHold로 입양
  qs('btn-adopt-dust')?.addEventListener('click', async () => {
    if (dustList.length === 0) {
      showToast('No dust to adopt. Scan first.', 'warning');
      return;
    }
    
    const totalNeedBuy = dustList.reduce((sum, d) => sum + 6, 0);  // 6 USDT fixed
    if (!confirm(tf('confirm.adopt_dust_longhold',
        'Adopt dust coins into LongHold?\n\n🪙 {count} coins\n💸 Required budget: ${budget} ($6 each)\n\n📈 Accumulate near lows and register to LongHold\n🎯 Target: +100% (2x)\n\nContinue?',
        { count: dustList.length, budget: totalNeedBuy.toLocaleString() }))) {
      return;
    }
    
    const btn = qs('btn-adopt-dust');
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> Adopting...';
    
    try {
      const res = await authFetch(`/api/engine/dust/adopt_all?dry_run=false&max_coins=10&buy_amount_usdt=6`, { method: 'POST' });
      const data = await res.json();
      
      if (data.ok) {
        const successCount = data.results?.filter(r => r.result?.ok).length || 0;
        showToast(`Adopted ${successCount}/${data.adopted_count} dust coins as LongHold! 🏠`, 'success');
        dustList = [];
        qs('btn-adopt-dust').disabled = true;
        qs('btn-vacuum-dust').disabled = true;
        
        // Refresh
        setTimeout(() => loadPnL(), 2000);
      } else {
        showToast('Adopt failed: ' + (data.error || 'Unknown'), 'error');
      }
    } catch (err) {
      showToast('Adopt failed: ' + err.message, 'error');
    } finally {
      btn.disabled = true;
      btn.innerHTML = '<i class="ti ti-home-heart me-1"></i>Adopt All';
    }
  });
  
  // btn-clear-dust (system clear, not vacuum)
  qs('btn-clear-dust')?.addEventListener('click', async () => {
    if (!confirm(t('confirm.clear_dust_records', 'Clean dust position records from system?\n(Actual balances are unchanged)'))) return;
    try {
      const res = await authFetch('/api/engine/clear_dust?threshold=1000', { method: 'POST' });
      const data = await res.json();
      if (data.ok) {
        showToast(`System cleared ${data.count || 0} dust records`, 'success');
      } else {
        showToast(data.error || 'Clear failed', 'error');
      }
    } catch (err) {
      showToast('Clear failed: ' + err.message, 'error');
    }
  });
  
  // Dust auto cleanup settings save
  qs('btn-save-dust-settings')?.addEventListener('click', async () => {
    const enabled = qs('dust-auto-enabled')?.checked || false;
    const dailyRaw = parseInt(qs('dust-auto-daily')?.value || '1', 10);
    const daily = Math.max(1, Number.isFinite(dailyRaw) ? dailyRaw : 1);

    try {
      const params = new URLSearchParams();
      params.set('dust_vacuum_enabled', enabled ? 'true' : 'false');
      params.set('dust_vacuum_daily_count', String(daily));
      const res = await authFetch(`${API.systemGuards}?${params.toString()}`, { method: 'POST' });
      const data = await res.json();
      if (data.ok) {
        showToast(tf('status.auto_dust_cleanup', 'Auto dust cleanup: {state} ({daily}/day)', {
          state: enabled ? t('status.enabled', 'ON') : t('status.disabled', 'OFF'),
          daily
        }), 'success');
      } else {
        showToast(t('error.save_settings_failed', 'Failed to save settings'), 'error');
      }
    } catch (err) {
      showToast(`${t('error.save_settings_failed', 'Failed to save settings')}: ${err.message}`, 'error');
    }
  });
  
  qs('btn-settings-retrain')?.addEventListener('click', async () => {
    if (!confirm(t('confirm.ai_retrain', 'Retrain AI model? This may take some time.'))) return;
    try {
      showToast('Retraining...', 'info');
      const res = await authFetch(API.aiRetrain, { method: 'POST' });
      const json = await res.json();
      if (json.ok) {
        const acc = json.accuracy ? (json.accuracy * 100).toFixed(1) + '%' : 'N/A';
        const auc = json.auc ? json.auc.toFixed(3) : 'N/A';
        showToast(`Retrain complete! Accuracy: ${acc}, AUC: ${auc}`, 'success');
      } else {
        showToast('Retrain failed: ' + (json.error || 'Unknown'), 'error');
      }
    } catch (err) {
      showToast('Retrain failed: ' + err.message, 'error');
    }
  });
  
  // Server Control Buttons (2026-02-02: graceful shutdown with configurable delay)
  qs('btn-server-restart')?.addEventListener('click', async () => {
    const delaySec = parseInt(qs('server-shutdown-delay')?.value) || 15;
    const cleanup = qs('server-cleanup-toggle')?.checked ? 1 : 0;
    const cleanupText = cleanup
      ? t('status.cleanup_on', 'Cleanup: ON (cancel/sync orders)')
      : t('status.cleanup_off', 'Cleanup: OFF');
    if (!confirm(tf('confirm.server_restart',
      'Restart server?\n\nCleanup wait: {delay} sec\n{cleanup}\nIf there are active trades, restart after completion.',
      { delay: delaySec, cleanup: cleanupText }))) return;
    try {
      showToast(tf('status.server_restart_requesting', 'Requesting server restart... (after {delay}s)', { delay: delaySec }), 'warning');
      const res = await authFetch(`/api/system/restart?delay_sec=${delaySec}&cleanup=${cleanup}`, { method: 'POST' });
      const json = await res.json();
      showToast(json.message || t('status.restart_requested', 'Restart requested'), 'info');
      // Stop all polling to avoid hitting a closing server
      try { stopAutoSync(); } catch (_) {}
      try { stopPrecisionScope(); } catch (_) {}
      try { stopAutoScan(); } catch (_) {}
      try { if (window._ladderPollTimer) { clearInterval(window._ladderPollTimer); window._ladderPollTimer = null; } } catch (_) {}
      _authLost = true;
      setTimeout(() => {
        showToast(t('status.server_restarting', 'Server restarting... page will auto-refresh.'), 'warning');
      }, delaySec * 500);
      setTimeout(() => { _authLost = false; location.reload(); }, (delaySec + 3) * 1000);
    } catch (err) {
      showToast(`${t('error.restart_failed', 'Restart failed')}: ${err.message}`, 'error');
    }
  });
  
  qs('btn-server-stop')?.addEventListener('click', async () => {
    const delaySec = parseInt(qs('server-shutdown-delay')?.value) || 15;
    const cleanup = qs('server-cleanup-toggle')?.checked ? 1 : 0;
    const cleanupText = cleanup
      ? t('status.cleanup_on', 'Cleanup: ON (cancel/sync orders)')
      : t('status.cleanup_off', 'Cleanup: OFF');
    if (!confirm(tf('confirm.server_stop',
      'Stop server completely?\n\nCleanup wait: {delay} sec\n{cleanup}\nTo start again, run run.ps1 in PowerShell.',
      { delay: delaySec, cleanup: cleanupText }))) return;
    try {
      showToast(tf('status.server_stop_requesting', 'Requesting server stop... (after {delay}s)', { delay: delaySec }), 'warning');
      const res = await authFetch(`/api/system/stop?delay_sec=${delaySec}&cleanup=${cleanup}`, { method: 'POST' });
      const json = await res.json();
      showToast(json.message || t('status.stop_requested', 'Stop requested'), 'info');
      // Stop all polling immediately to avoid hitting a closing server
      try { stopAutoSync(); } catch (_) {}
      try { stopPrecisionScope(); } catch (_) {}
      try { stopAutoScan(); } catch (_) {}
      try { if (window._ladderPollTimer) { clearInterval(window._ladderPollTimer); window._ladderPollTimer = null; } } catch (_) {}
      try { if (typeof chartRefreshTimer !== 'undefined') clearInterval(chartRefreshTimer); } catch (_) {}
      // Disable further authFetch calls
      _authLost = true;
    } catch (err) {
      showToast(`${t('error.stop_failed', 'Stop failed')}: ${err.message}`, 'error');
    }
  });
  
  // Exchange API Settings
  bindExchangeApiEvents();
}

