async function loadExchangeApiStatus() {
  const statusEl = qs('exchange-api-status');
  try {
    const res = await authFetch('/api/system/exchange-api/status');
    const data = await res.json();
    if (data.ok) {
      if (data.has_keys) {
        statusEl.className = 'badge bg-success';
        statusEl.textContent = t('status.configured', 'Configured');
        if (data.access_key_masked) {
          qs('exchange-access-key').placeholder = data.access_key_masked;
        }
      } else {
        statusEl.className = 'badge bg-warning';
        statusEl.textContent = t('status.unconfigured', 'Not configured');
      }
    }
  } catch (e) {
    statusEl.className = 'badge bg-danger';
    statusEl.textContent = t('label.error', 'Error');
  }
}

async function detectPublicIp() {
  const ipEl = qs('exchange-allowed-ip');
  if (!ipEl) return;
  
  ipEl.value = t('status.detecting', 'Detecting...');
  try {
    const res = await authFetch('/api/system/exchange-api/detect-ip');
    const data = await res.json();
    if (data.ok && data.ip) {
      ipEl.value = data.ip;
      showToast(tf('status.ip_public', 'Public IP: {ip}', { ip: data.ip }), 'success');
    } else {
      ipEl.value = t('status.detect_failed', 'Detect failed');
      showToast(data.error || t('error.ip_detect_failed', 'IP detection failed'), 'error');
    }
  } catch (e) {
    ipEl.value = t('label.error', 'Error');
    showToast(t('error.ip_detect_error', 'IP detection error'), 'error');
  }
}

async function testExchangeApi() {
  const accessKey = qs('exchange-access-key')?.value?.trim();
  const secretKey = qs('exchange-secret-key')?.value?.trim();
  const resultEl = qs('exchange-api-test-result');
  
  if (!accessKey || !secretKey) {
    if (resultEl) resultEl.innerHTML = `<span class="text-warning">${t('error.enter_access_secret', 'Enter Access Key and Secret Key')}</span>`;
    return;
  }
  
  if (resultEl) resultEl.innerHTML = `<span class="text-muted">${t('status.testing', 'Testing...')}</span>`;
  
  try {
    const res = await authFetch('/api/system/exchange-api/test', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ access_key: accessKey, secret_key: secretKey })
    });
    const data = await res.json();
    
    if (data.ok) {
      resultEl.innerHTML = `<span class="text-success">✅ ${tf('status.test_success_usdt_coin', '{message} | Balance: {balance} | Coins: {count}', {
        message: data.message || 'OK',
        balance: `${(data.usdt_balance || 0)?.toLocaleString()} ${t('unit.quote_currency', 'USDT')}`,
        count: data.coin_count
      })}</span>`;
    } else {
      resultEl.innerHTML = `<span class="text-danger">❌ ${data.error}</span>`;
    }
  } catch (e) {
    resultEl.innerHTML = `<span class="text-danger">❌ ${t('label.error', 'Error')}: ${e.message}</span>`;
  }
}

async function saveExchangeApi() {
  const accessKey = qs('exchange-access-key')?.value?.trim();
  const secretKey = qs('exchange-secret-key')?.value?.trim();
  const resultEl = qs('exchange-api-test-result');
  
  if (!accessKey || !secretKey) {
    showToast(t('error.enter_access_secret', 'Enter Access Key and Secret Key'), 'warning');
    return;
  }
  
  // Admin 인증 확인
  const adminToken = getAdminToken();
  if (!adminToken) {
    showToast(t('error.admin_login_required', 'Admin login is required'), 'warning');
    return;
  }
  
  if (!confirm(t('confirm.save_api_keys_env', 'Save API keys to .env file?'))) return;
  
  try {
    const res = await authFetch('/api/system/exchange-api/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ access_key: accessKey, secret_key: secretKey, admin_token: adminToken })
    });
    const data = await res.json();
    
    if (data.ok) {
      showToast(data.message, 'success');
      if (resultEl) resultEl.innerHTML = `<span class="text-success">✅ ${data.message}</span>`;
      await loadExchangeApiStatus();
    } else {
      showToast(data.error || t('error.save_failed', 'Save failed'), 'error');
      if (resultEl) resultEl.innerHTML = `<span class="text-danger">❌ ${data.error}</span>`;
    }
  } catch (e) {
    showToast(`${t('error.save_failed', 'Save failed')}: ${e.message}`, 'error');
  }
}

function bindExchangeApiEvents() {
  qs('btn-detect-ip')?.addEventListener('click', detectPublicIp);
  qs('btn-copy-ip')?.addEventListener('click', () => {
    const ip = qs('exchange-allowed-ip')?.value;
    if (ip && ip !== t('status.detecting', 'Detecting...') && ip !== t('status.detect_failed', 'Detect failed')) {
      navigator.clipboard.writeText(ip);
      showToast(t('status.ip_copied', 'IP copied'), 'success');
    }
  });
  qs('btn-test-exchange-api')?.addEventListener('click', testExchangeApi);
  qs('btn-save-exchange-api')?.addEventListener('click', saveExchangeApi);
  
  // Telegram
  qs('btn-test-telegram')?.addEventListener('click', testTelegram);
  qs('btn-save-telegram')?.addEventListener('click', saveTelegram);
  
  // Admin 버튼
  qs('btn-admin-login')?.addEventListener('click', adminLogin);
  qs('btn-admin-logout')?.addEventListener('click', adminLogout);
  
  // 페이지 로드 시 상태 확인
  loadExchangeApiStatus();
  detectPublicIp();
  loadTelegramStatus();
  initAdminAuth();
}

