// ============================================================
// Admin Authentication
// ============================================================

function getAdminToken() {
  return localStorage.getItem(LS_ADMIN_TOKEN) || '';
}

function setAdminToken(token) {
  if (token) {
    localStorage.setItem(LS_ADMIN_TOKEN, token);
  } else {
    localStorage.removeItem(LS_ADMIN_TOKEN);
  }
}

async function checkAdminAuth() {
  const token = getAdminToken();
  if (!token) return false;
  
  try {
    const res = await authFetch(`/api/system/admin/verify?token=${token}`);
    const data = await res.json();
    return data.ok && data.valid;
  } catch (e) {
    return false;
  }
}

async function adminLogin() {
  const password = prompt(t('prompt.enter_admin_password', 'Enter Admin password:'));
  if (!password) return false;
  
  try {
    const res = await authFetch(`/api/system/admin/login?password=${encodeURIComponent(password)}`, { method: 'POST' });
    const data = await res.json();
    
    if (data.ok && data.token) {
      setAdminToken(data.token);
      showToast(t('status.admin_login_success', 'Admin login successful'), 'success');
      updateAdminUI(true);
      return true;
    } else {
      showToast(data.error || t('error.login_failed', 'Login failed'), 'error');
      return false;
    }
  } catch (e) {
    showToast(`${t('error.login_error', 'Login error')}: ${e.message}`, 'error');
    return false;
  }
}

async function adminLogout() {
  const token = getAdminToken();
  if (token) {
    try {
      await authFetch(`/api/system/admin/logout?token=${token}`, { method: 'POST' });
    } catch (e) {}
  }
  setAdminToken('');
  updateAdminUI(false);
  showToast(t('status.logged_out', 'Logged out'), 'info');
}

function updateAdminUI(isLoggedIn) {
  const loginBtn = qs('btn-admin-login');
  const logoutBtn = qs('btn-admin-logout');
  const protectedEls = qsa('.admin-protected');
  
  if (loginBtn) loginBtn.style.display = isLoggedIn ? 'none' : 'inline-block';
  if (logoutBtn) logoutBtn.style.display = isLoggedIn ? 'inline-block' : 'none';
  
  protectedEls.forEach(el => {
    el.style.display = isLoggedIn ? '' : 'none';
  });
  
  // 상태 표시
  const statusEl = qs('admin-status');
  if (statusEl) {
    if (isLoggedIn) {
      statusEl.className = 'badge bg-success';
      statusEl.textContent = 'Admin';
    } else {
      statusEl.className = 'badge bg-secondary';
      statusEl.textContent = t('status.guest', 'Guest');
    }
  }
}

async function initAdminAuth() {
  const isLoggedIn = await checkAdminAuth();
  updateAdminUI(isLoggedIn);
}

