  authFetch('/api/triage/status')
    .then(r => r.ok ? r.json() : null)
    .then(d => { if (d && d.settings) _applyTriageSettingsToUI(d.settings); })
    .catch(() => {});
  const trState = sysTriage.state || 'NORMAL';
  const trActive = sysTriage.active || false;
  const stateBadge = qs('triage-settings-state-badge');
  if (stateBadge) {
    stateBadge.textContent = trActive ? trState : 'OFF';
    stateBadge.className = `badge ${trActive ? 'bg-danger' : 'bg-secondary'}`;
  }
  if (qs('tr-enabled')) qs('tr-enabled').checked = tr.enabled ?? false;
  if (qs('tr-trigger-pnl')) qs('tr-trigger-pnl').value = tr.trigger_pnl_pct ?? -5;
