  if (qs('tr-coin-timeout')) qs('tr-coin-timeout').value = tr.coin_timeout_hours ?? 48;
  if (qs('tr-max-duration')) qs('tr-max-duration').value = tr.max_duration_hours ?? 168;
  if (qs('tr-recovery-target')) qs('tr-recovery-target').value = tr.recovery_target ?? 'ALL';
  if (qs('tr-notify')) qs('tr-notify').checked = tr.notify ?? true;
