  if (qs('tr-emergency-severe')) qs('tr-emergency-severe').value = tr.emergency_severe_avg_loss_pct ?? -30;
  if (qs('tr-buy-mode')) qs('tr-buy-mode').value = tr.buy_mode ?? 'block_all';
