function updateEstProfit(prefix) {
  const budgetEl = qs(`${prefix}-budget`);
  const tpEl = qs(`${prefix}-tp`);
  const estEl = qs(`${prefix}-est-profit`);
  
  if (!budgetEl || !tpEl || !estEl) return;
  
  const budget = parseFloat(budgetEl.value) || 0;
  const tp = parseFloat(tpEl.value) || 0;
  
  if (budget > 0 && tp > 0) {
    const est = Math.round(budget * (tp / 100));
    estEl.value = est;
    estEl.className = 'form-control form-control-sm text-success fw-bold text-center';
  } else {
    estEl.value = '';
    estEl.className = 'form-control form-control-sm text-muted text-center';
  }
}

// 목표 이익 입력 시 Budget 역계산
function reverseCalcBudget(prefix) {
  const budgetEl = qs(`${prefix}-budget`);
  const tpEl = qs(`${prefix}-tp`);
  const estEl = qs(`${prefix}-est-profit`);
  
  if (!budgetEl || !tpEl || !estEl) return;
  
  const targetProfit = parseFloat(estEl.value) || 0;
  const tp = parseFloat(tpEl.value) || 0;
  
  if (targetProfit > 0 && tp > 0) {
    // Budget = 목표이익 / (TP% / 100)
    const newBudget = Math.round(targetProfit / (tp / 100));
    budgetEl.value = newBudget;
    console.log(`[reverseCalcBudget] ${prefix}: 목표이익=${targetProfit}, TP=${tp}% → Budget=${newBudget}`);
  }
}

function bindEstProfitEvents(prefix) {
  qs(`${prefix}-budget`)?.addEventListener('input', () => updateEstProfit(prefix));
  qs(`${prefix}-tp`)?.addEventListener('input', () => updateEstProfit(prefix));
  // 목표 이익 입력 시 Budget 역계산
  const estEl = qs(`${prefix}-est-profit`);
  if (estEl) {
    estEl.addEventListener('input', () => reverseCalcBudget(prefix));
    // 키보드 단축키가 동작하지 않도록 이벤트 버블링 방지
    estEl.addEventListener('keydown', (e) => e.stopPropagation());
  }
}

// [2026-02-02] SNIPER 예상 이윤/손실 계산 (badge 표시용)
function updateSniperEstProfit() {
  const budgetEl = qs('sn-budget');
  const tpEl = qs('sn-tp');
  const slEl = qs('sn-sl');
  const profitEl = qs('sn-est-profit');
  const lossEl = qs('sn-est-loss');
  
  if (!budgetEl || !tpEl || !slEl || !profitEl || !lossEl) return;
  
  const budget = parseFloat(budgetEl.value) || 0;
  const tp = parseFloat(tpEl.value) || 0;
  const sl = parseFloat(slEl.value) || 0;
  
  if (budget > 0) {
    const estProfit = Math.round(budget * (tp / 100));
    const estLoss = Math.round(budget * (sl / 100));
    profitEl.textContent = `+$${formatNumber(estProfit)}`;
    lossEl.textContent = `-$${formatNumber(estLoss)}`;
  } else {
    profitEl.textContent = '+$0';
    lossEl.textContent = '-$0';
  }
}

// [2026-02-02] SNIPER 고가/저가 조회 (버튼 클릭으로 수동 호출)
async function fetchSniperHighlowAndUpdate() {
  const marketEl = qs('sn-market');
  const lookbackEl = qs('sn-entry-lookback');
  const unitEl = qs('sn-entry-unit');
  const tpEl = qs('sn-tp');
  const slEl = qs('sn-sl');
  const thresholdEl = qs('sn-entry-threshold');
  const highlowInfoEl = qs('sn-highlow-info');
  const fetchBtn = qs('btn-sn-fetch-highlow');
  
  if (!marketEl || !lookbackEl || !unitEl) return;
  
  const market = marketEl.value?.trim();
  if (!market) {
    if (highlowInfoEl) {
      highlowInfoEl.innerHTML = `<small class="text-danger">${t('hint.select_market_first', 'Select a market first')}</small>`;
    }
    return;
  }
  
  const lookbackVal = parseFloat(lookbackEl.value) || 15;
  const unit = unitEl.value || 'min';
  
  // 분 단위로 변환
  let lookbackMin = lookbackVal;
  if (unit === 'hour') lookbackMin = lookbackVal * 60;
  else if (unit === 'day') lookbackMin = lookbackVal * 1440;
  
  // 버튼 로딩 상태
  if (fetchBtn) {
    fetchBtn.disabled = true;
    fetchBtn.innerHTML = '<span class="spinner-border spinner-border-sm"></span>';
  }
  if (highlowInfoEl) {
    highlowInfoEl.innerHTML = `<small class="text-muted">${t('status.loading_data', 'Loading...')}</small>`;
  }
  
  // API 호출
  try {
    const resp = await authFetch(`/api/strategy/sniper/highlow?market=${encodeURIComponent(market)}&lookback_min=${lookbackMin}`);
    const data = await resp.json();
    
    if (data.ok) {
      // 고가/저가 정보 표시
      const high = formatNumber(Math.round(data.high));
      const low = formatNumber(Math.round(data.low));
      const curr = formatNumber(Math.round(data.current));
      const distLow = data.distance_from_low_pct;
      const rangePct = data.range_pct;
      
      const timeLabel = lookbackMin >= 1440
        ? (lookbackMin/1440).toFixed(0) + t('unit.day', 'd')
        : (lookbackMin >= 60 ? (lookbackMin/60).toFixed(0) + t('unit.hour', 'h') : lookbackMin + t('unit.minute', 'm'));
      
      if (highlowInfoEl) {
        highlowInfoEl.innerHTML = `
          <div class="small">
            <span class="badge bg-info-subtle text-info">${timeLabel}</span>
            ${t('label.low', 'Low')} <strong class="text-success">$${low}</strong> ~ 
            ${t('label.high', 'High')} <strong class="text-danger">$${high}</strong>
            <span class="text-muted">(${t('label.range', 'Range')} ${rangePct.toFixed(1)}%)</span>
          </div>
          <div class="small text-muted">
            ${t('label.current_price', 'Current Price')} $${curr} · ${t('label.current_vs_low', 'vs low')} <strong class="${distLow < 30 ? 'text-success' : 'text-warning'}">+${distLow.toFixed(1)}%</strong>
          </div>
        `;
      }
      
      // TP/SL/Threshold 자동 업데이트 (사용자가 직접 수정하지 않은 경우)
      if (tpEl && !tpEl.dataset.userModified) {
        tpEl.value = data.suggested_tp_pct;
      }
      if (slEl && !slEl.dataset.userModified) {
        slEl.value = data.suggested_sl_pct;
      }
      // Threshold도 자동 계산 (범위의 20%)
      if (thresholdEl && !thresholdEl.dataset.userModified) {
        thresholdEl.value = Math.max(0.3, Math.min(2.5, rangePct * 0.20)).toFixed(1);
      }
      
      // 예상 이윤 재계산
      updateSniperEstProfit();
    } else {
      if (highlowInfoEl) {
        highlowInfoEl.innerHTML = `<small class="text-danger">${t('status.fetch_failed', 'Fetch failed')}: ${data.error || t('label.api_error', 'API error')}</small>`;
      }
    }
  } catch (e) {
    console.warn('[SNIPER] highlow fetch failed:', e);
    if (highlowInfoEl) {
      highlowInfoEl.innerHTML = `<small class="text-danger">${t('label.network_error', 'Network error')}</small>`;
    }
  } finally {
    // 버튼 복구
    if (fetchBtn) {
      fetchBtn.disabled = false;
      fetchBtn.innerHTML = '<i class="ti ti-refresh"></i>';
    }
  }
}

