// ============================================================
// Guard Matrix
// ============================================================

async function fetchGuards() {
  try {
    const res = await authFetch(API.systemGuards);
    const data = await res.json();
    state.guards = data;
    renderGlobalGuards(data);
    if (data && data.guards) {
      const g = data.guards;
      const _set = (id, val) => { const el = qs(id); if (el) el.checked = !!val; };
      _set('guard-entry-enabled', g.entry_ob_guard_enabled);
      _set('guard-exit-enabled', g.exit_profit_guard);
      _set('guard-gap-enabled', g.entry_ceiling_guard);
      _set('guard-cooldown-enabled', g.entry_qty_guard);
      _set('guard-limit-enabled', g.entry_limit_buy_enabled);
      _set('guard-position-enabled', g.drawdown_guard);
    }
  } catch (err) {
    console.error('Guards 조회 실패:', err);
  }
}

function renderGlobalGuards(data) {
  const container = qs('global-guards');
  if (!container) return;
  
  if (!data || !data.guards) {
    container.innerHTML = '<div class="text-muted small">No guard data</div>';
    return;
  }
  
  const guards = data.guards;
  const items = Object.entries(guards).map(([key, value]) => {
    const lampClass = value === true ? 'pass' : (value === false ? 'block' : 'off');
    return `<span class="me-2 small"><span class="guard-lamp ${lampClass}"></span>${key}</span>`;
  });
  
  container.innerHTML = items.join('');
}

function renderMarketGuards(market) {
  const container = qs('market-guards');
  if (!container) return;
  
  if (!state.guards || !state.guards.coordinator || !state.guards.coordinator[market]) {
    container.innerHTML = '<div class="text-muted small">No market-specific guards</div>';
    return;
  }
  
  const guards = state.guards.coordinator[market];
  const items = Object.entries(guards).map(([key, value]) => {
    const lampClass = value === true ? 'pass' : (value === false ? 'block' : 'off');
    return `<span class="me-2 small"><span class="guard-lamp ${lampClass}"></span>${key}</span>`;
  });
  
  container.innerHTML = items.join('');
  
  if (qs('market-guards-summary')) {
    qs('market-guards-summary').textContent = market;
  }
}

function renderGuardGrid() {
  const container = qs('guard-grid');
  if (!container || !state.managedMarkets.length) return;
  
  let html = '<table class="table table-compact table-hover small mb-0">';
  html += '<thead><tr><th>Market</th><th>Entry</th><th>Exit</th><th>Status</th></tr></thead>';
  html += '<tbody>';
  
  state.managedMarkets.slice(0, 20).forEach(m => {
    const guards = state.guards?.markets?.[m.market] || {};
    const entryOk = guards.entry !== false;
    const exitOk = guards.exit !== false;
    
    html += `<tr onclick="renderMarketGuards('${m.market}')" style="cursor:pointer;">
      <td>${extractBase(m.market)}</td>
      <td><span class="guard-lamp ${entryOk ? 'pass' : 'block'}"></span></td>
      <td><span class="guard-lamp ${exitOk ? 'pass' : 'block'}"></span></td>
      <td class="text-muted">${m.state || 'ACTIVE'}</td>
    </tr>`;
  });
  
  html += '</tbody></table>';
  container.innerHTML = html;
}

