async function loadRsCandidates(strategy) {
  const containerId = strategy === 'PINGPONG' ? 'rs-pp-candidates' : 'rs-al-candidates';
  const container = qs(containerId);
  if (!container) return;
  
  container.innerHTML = `<div class="text-muted text-center p-2">${t('label.loading', 'Loading...')}</div>`;
  
  try {
    const res = await authFetch(API.recommendations(strategy, 5));
    const data = await res.json();
    
    if (!data.ok || !data.items?.length) {
      container.innerHTML = `<div class="text-muted text-center p-2">${t('empty.no_recommendations', 'No recommendations')}</div>`;
      return;
    }
    
    container.innerHTML = data.items.map(c => {
      const conf = c.confidence != null ? c.confidence.toFixed(0) : null;
      const confClass = conf >= 50 ? 'text-success' : conf >= 30 ? 'text-warning' : 'text-danger';
      return `
      <div class="d-flex justify-content-between p-2 border-bottom">
        <span><strong>${extractBase(c.market)}</strong></span>
        <span class="small">
          ${conf != null ? `<span class="${confClass}" title="신뢰도 (${c.stages_passed || 0}/6)"><b>${conf}%</b></span> · ` : ''}
          <span class="text-muted">${c.ai_score ? (c.ai_score * 100).toFixed(0) + '% AI' : '-'}</span>
        </span>
      </div>`;
    }).join('');
  } catch (err) {
    container.innerHTML = '<div class="text-danger text-center p-2">Error</div>';
  }
}

