// ============================================================
// AI Top Pick
// ============================================================

async function fetchAITopPick() {
  const tbody = qs('toppick-body');
  if (!tbody) return;
  
  try {
    const [r1, r2, r3] = await Promise.all([
      authFetch(API.recommendations('GAZUA', 5)),
      authFetch(API.recommendations('LADDER', 5)),
      authFetch(API.recommendations('LIGHTNING', 5))
    ]);
    
    const j1 = await r1.json();
    const j2 = await r2.json();
    const j3 = await r3.json();
    
    let items = [];
    if (j1.ok && j1.items) items = items.concat(j1.items.map(i => ({...i, strat: 'GAZUA'})));
    if (j2.ok && j2.items) items = items.concat(j2.items.map(i => ({...i, strat: 'LADDER'})));
    if (j3.ok && j3.items) items = items.concat(j3.items.map(i => ({...i, strat: 'LIGHTNING'})));
    
    const marketMap = new Map();
    items.forEach(i => {
      const m = i.market;
      if (!marketMap.has(m)) marketMap.set(m, []);
      marketMap.get(m).push(i);
    });
    
    const rows = [];
    marketMap.forEach((strats, m) => {
      strats.sort((a, b) => (b.ai_score || 0) - (a.ai_score || 0));
      const best = strats[0];
      const second = strats.length > 1 ? strats[1] : null;
      rows.push({
        market: m,
        bestStrat: best.strat,
        bestScore: best.ai_score,
        secondStrat: second ? second.strat : null,
        active_strategy: best.active_strategy
      });
    });
    
    rows.sort((a, b) => (b.bestScore || 0) - (a.bestScore || 0));
    const top = rows.slice(0, 5);
    
    if (top.length === 0) {
      tbody.innerHTML = `<tr><td colspan="4" class="text-muted text-center">${t('empty.no_recommendations', 'No recommendations')}</td></tr>`;
      return;
    }
    
    tbody.innerHTML = top.map(item => {
      const scoreClass = item.bestScore >= 0.6 ? 'text-success' : (item.bestScore <= 0.4 ? 'text-danger' : '');
      const stratDisplay = item.secondStrat ? `${item.bestStrat} <small class="text-muted">+${item.secondStrat.substr(0,3)}</small>` : item.bestStrat;
      const useBadge = item.active_strategy ? `<span class="badge bg-warning-lt">Use</span>` : '-';
      
      return `<tr>
        <td><a href="/ui/market_detail.html?market=${item.market}" target="_blank" class="text-primary">${extractBase(item.market)}</a></td>
        <td><span class="badge ${getStrategyBadgeClass(item.bestStrat)}">${stratDisplay}</span></td>
        <td class="${scoreClass} fw-bold">${(item.bestScore || 0).toFixed(2)}</td>
        <td>${useBadge}</td>
      </tr>`;
    }).join('');
  } catch (err) {
    tbody.innerHTML = `<tr><td colspan="4" class="text-danger text-center">Error: ${err.message}</td></tr>`;
  }
}

// ============================================================
// LongHold Functions
// ============================================================

async function fetchLongHold() {
  const tbody = qs('longhold-table-body');
  if (!tbody) return;
  
  try {
    // 2026-01-30: /api/ladder/longhold/snapshot 사용 (qty, pnl 포함)
    const res = await authFetch('/api/ladder/longhold/snapshot');
    const data = await res.json();
    
    if (!data.ok || !data.items?.length) {
      tbody.innerHTML = `<tr><td colspan="5" class="text-muted text-center">${t('empty.no_longhold_markets', 'No LongHold markets')}</td></tr>`;
      return;
    }
    
    tbody.innerHTML = data.items.map(item => {
      // profit_pct 사용 (snapshot API에서 반환)
      const pnlPct = item.profit_pct ?? item.pnl ?? 0;
      const pnlClass = getPnlClass(pnlPct);
      return `<tr>
        <td><strong>${extractBase(item.market)}</strong></td>
        <td><span class="badge ${getStrategyBadgeClass(item.strategy)}">${item.strategy || '-'}</span></td>
        <td>${item.qty ? item.qty.toFixed(4) : '-'}</td>
        <td class="${pnlClass}">${pnlPct ? formatPercent(pnlPct) : '-'}</td>
        <td>
          <button class="btn btn-ghost-danger btn-sm" onclick="removeLongHold('${item.market}')"><i class="ti ti-x"></i></button>
        </td>
      </tr>`;
    }).join('');
  } catch (err) {
    tbody.innerHTML = `<tr><td colspan="5" class="text-danger text-center">Error</td></tr>`;
  }
}

async function fetchLongHoldRecommendations() {
  const container = qs('longhold-recommend-list');
  if (!container) return;
  
  try {
    // 2026-01-30: 올바른 API 경로
    const res = await authFetch('/api/ladder/longhold/candidates?n=10');
    const data = await res.json();
    
    if (!data.ok || !data.items?.length) {
      container.innerHTML = `<div class="text-muted text-center p-3">${t('empty.no_recommendations', 'No recommendations')}</div>`;
      return;
    }
    
    // 캐시 상태 표시
    const cacheInfo = data.cached
      ? `<div class="text-muted small text-end mb-1">${t('status.cached_5m', 'Cached (5m)')}</div>`
      : `<div class="text-muted small text-end mb-1">${t('status.new_scanned', 'Newly scanned')}</div>`;
    
    // 2026-01-30: 추천 지표 상세 표시 (score, momentum, volatility, trend)
    // 점수 정규화: 최고 점수 대비 상대 %
    const maxScore = Math.max(...data.items.map(i => i.score ?? 0), 0.01);
    const minScore = Math.min(...data.items.map(i => i.score ?? 0), 0);
    const scoreRange = maxScore - minScore || 1;
    
    container.innerHTML = cacheInfo + data.items.map(item => {
      const score = item.score ?? 0;
      // 상대적 점수 (최고=100%, 최저=20%)
      const relativeScore = ((score - minScore) / scoreRange) * 80 + 20;
      const scoreWidth = Math.min(100, Math.max(0, relativeScore));
      const momentum = item.momentum ?? 0;
      const volatility = item.volatility ?? 0;
      const trend = item.trend_slope ?? 0;
      
      // 점수에 따른 색상
      const scoreColor = score >= 0.7 ? 'bg-success' : (score >= 0.5 ? 'bg-info' : 'bg-secondary');
      // 모멘텀 색상 (양수=상승, 음수=하락)
      const momClass = momentum > 0 ? 'text-success' : (momentum < 0 ? 'text-danger' : 'text-muted');
      const trendClass = trend > 0 ? 'text-success' : (trend < 0 ? 'text-danger' : 'text-muted');
      
      return `
        <div class="p-2 border-bottom cursor-pointer" onclick="setLongHoldMarket('${item.market}')" style="cursor:pointer;">
          <div class="d-flex justify-content-between align-items-center mb-1">
            <strong>${extractBase(item.market)}</strong>
            <span class="badge ${scoreColor}">${tf('ranking.score_point', '{score} pt', { score: (score * 100).toFixed(0) })}</span>
          </div>
          <div class="progress mb-1" style="height: 4px;">
            <div class="progress-bar ${scoreColor}" style="width: ${scoreWidth}%"></div>
          </div>
          <div class="d-flex gap-2 small">
            <span class="${momClass}" title="${t('label.momentum', 'Momentum')}">M:${momentum > 0 ? '+' : ''}${(momentum * 100).toFixed(1)}%</span>
            <span class="text-warning" title="${t('label.volatility', 'Volatility')}">V:${(volatility * 100).toFixed(1)}%</span>
            <span class="${trendClass}" title="${t('label.trend', 'Trend')}">T:${trend > 0 ? '↑' : (trend < 0 ? '↓' : '→')}</span>
          </div>
        </div>
      `;
    }).join('');
  } catch (err) {
    container.innerHTML = '<div class="text-danger text-center p-3">Error</div>';
  }
}

function setLongHoldMarket(market) {
  const input = qs('lh-add-market');
  if (input) input.value = extractBase(market);
}

async function addLongHold() {
  let market = qs('lh-add-market')?.value?.trim().toUpperCase();
  const strategy = qs('lh-add-strategy')?.value;
  const budget = parseFloat(qs('lh-add-budget')?.value) || 100;
  
  if (!market) {
    showToast('Market is required', 'error');
    return;
  }
  
  if (!market.endsWith('USDT')) market = market + 'USDT';
  
  try {
    // 2026-01-30: 올바른 API 경로 (/api/ladder/longhold/deploy)
    const res = await authFetch('/api/ladder/longhold/deploy', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ market, strategy, budget_usdt: budget })
    });
    const data = await res.json();
    
    if (data.ok) {
      showToast(`LongHold added: ${market}`, 'success');
      await fetchLongHold();
      qs('lh-add-market').value = '';
    } else {
      showToast(data.error || 'Failed', 'error');
    }
  } catch (err) {
    showToast('Add failed: ' + err.message, 'error');
  }
}

async function removeLongHold(market) {
  if (!confirm(tf('confirm.remove_longhold', 'Remove {market} from LongHold?', { market }))) return;
  
  try {
    // 2026-01-30: 올바른 API 경로 사용
    const res = await authFetch(`/api/ladder/longhold/remove?market=${encodeURIComponent(market)}`, { method: 'POST' });
    const data = await res.json();
    
    if (data.ok) {
      showToast(`Removed: ${market}`, 'success');
      await fetchLongHold();
    } else {
      showToast(data.error || 'Failed', 'error');
    }
  } catch (err) {
    showToast('Remove failed', 'error');
  }
}

function bindLongHoldEvents() {
  qs('btn-refresh-longhold')?.addEventListener('click', fetchLongHold);
  qs('btn-refresh-lh-recommend')?.addEventListener('click', fetchLongHoldRecommendations);
  qs('btn-lh-add')?.addEventListener('click', addLongHold);
}

// ============================================================
// AI Stats Detail
// ============================================================

async function fetchAIStats() {
  try {
    const [histRes, infoRes] = await Promise.all([
      authFetch(API.aiHistory),
      authFetch(API.aiInfo)
    ]);
    
    const histData = await histRes.json();
    const infoData = await infoRes.json();
    
    // History-based stats (24h accuracy)
    if (histData.ok) {
      const hist = histData.history || [];
      const hcAcc = histData.high_conf_accuracy || 0;
      const hcCount = histData.high_conf_count || 0;
      
      const validHist = hist.filter(h => h.acc > 0);
      const avgAcc = validHist.length > 0 ? validHist.reduce((a, b) => a + b.acc, 0) / validHist.length : 0;
      
      const accEl = qs('ai-acc-24h');
      const hcEl = qs('ai-high-conf');
      const samplesEl = qs('ai-samples');
      
      if (hcCount === 0) {
    if (accEl) { accEl.textContent = '—'; accEl.title = t('status.collecting', 'Collecting...'); }
        if (hcEl) { hcEl.textContent = '—'; hcEl.className = 'h3 mb-0 text-muted'; }
      } else {
        if (accEl) accEl.textContent = (avgAcc * 100).toFixed(1) + '%';
        if (hcEl) {
          hcEl.textContent = (hcAcc * 100).toFixed(1) + '%';
          hcEl.className = `h3 mb-0 ${hcAcc >= 0.6 ? 'text-success' : hcAcc < 0.5 ? 'text-danger' : 'text-warning'}`;
        }
      }
      if (samplesEl) samplesEl.textContent = hcCount;
    }
    
    // Model info (training metadata)
    if (infoData.ok && infoData.info) {
      const info = infoData.info;
      
      // Model type badge
      const modelTypeEl = qs('ai-model-type');
      if (modelTypeEl && info.model_type) {
        modelTypeEl.textContent = info.model_type.replace('_', ' ');
      }
      
      // Last train timestamp & age
      const ts = info.ts;
      if (ts) {
        const d = new Date(ts * 1000);
        const ds = `${d.getMonth()+1}/${d.getDate()} ${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
        if (qs('ai-last-train')) qs('ai-last-train').textContent = ds;
        
        const limitHrs = info.retrain_interval_hours || 6.0;
        const now = Date.now() / 1000;
        const age = Math.max(0, now - ts);
        const hrs = (age / 3600).toFixed(1);
        
        const ageEl = qs('ai-model-age');
        if (ageEl) {
          ageEl.textContent = `${hrs}h`;
          ageEl.className = `h4 mb-0 ${age > limitHrs * 3600 ? 'text-danger' : age > (limitHrs - 1) * 3600 ? 'text-warning' : ''}`;
        }
      }
      
      // Horizon metrics table
      renderHorizonMetrics(info.horizon_metrics || {});
      
      // Feature importance chart (TOP 10)
      renderImportanceChart(info.importance || {});
      
      // Feature list
      renderFeatureList(info.features || []);
      
      // Strategy distribution
      renderStrategyDistribution(info.strategy_distribution || {});
      
      if (qs('ai-model-info')) qs('ai-model-info').textContent = t('status.updated', 'Updated');
    }
  } catch (err) {
    console.error('AI stats fetch error:', err);
  }
}

function renderHorizonMetrics(metrics) {
  const tbody = qs('ai-horizon-table');
  const totalRowsEl = qs('ai-total-rows');
  if (!tbody) return;
  
  const horizonLabels = {
    '60': t('horizon.1m', '1m'),
    '300': t('horizon.5m', '5m'),
    '900': t('horizon.15m', '15m'),
  };
  const entries = Object.entries(metrics);
  
  if (entries.length === 0) {
    tbody.innerHTML = `<tr><td colspan="4" class="text-center text-muted">${t('empty.no_data', 'No data')}</td></tr>`;
    return;
  }
  
  let totalRows = 0;
  const rows = entries.map(([h, m]) => {
    totalRows += m.rows || 0;
    const acc = (m.accuracy * 100).toFixed(1);
    const auc = (m.auc * 100).toFixed(1);
    const aucClass = m.auc >= 0.55 ? 'text-success' : m.auc < 0.5 ? 'text-danger' : 'text-warning';
    const accClass = m.accuracy >= 0.55 ? 'text-success' : m.accuracy < 0.5 ? 'text-danger' : '';
    return `
      <tr>
        <td class="text-center"><span class="badge bg-azure-lt">${horizonLabels[h] || h + 's'}</span></td>
        <td class="text-center ${accClass}">${acc}%</td>
        <td class="text-center fw-bold ${aucClass}">${auc}%</td>
        <td class="text-center text-muted">${(m.rows || 0).toLocaleString()}</td>
      </tr>
    `;
  }).join('');
  
  tbody.innerHTML = rows;
  if (totalRowsEl) totalRowsEl.textContent = tf('label.total_rows', 'Total: {rows} rows', { rows: totalRows.toLocaleString() });
}

function renderImportanceChart(importance) {
  const container = qs('ai-importance-chart');
  const noteEl = qs('ai-importance-note');
  if (!container) return;
  
  const sorted = Object.entries(importance).sort((a, b) => b[1] - a[1]).slice(0, 10);
  
  if (sorted.length === 0) {
    container.innerHTML = `<div class="text-muted text-center py-4"><i class="ti ti-info-circle me-2"></i>${t('hint.retrain_to_display', 'Displayed after retrain')}</div>`;
    if (noteEl) noteEl.textContent = '';
    return;
  }
  
  if (noteEl) noteEl.textContent = tf('label.top10_of_total', 'TOP 10 of {count}', { count: Object.keys(importance).length });
  
  const maxVal = sorted[0][1];
  const bars = sorted.map(([name, val], idx) => {
    const pct = (val / maxVal) * 100;
    const valPct = (val * 100).toFixed(2);
    const colors = ['#206bc4', '#2fb344', '#f76707', '#d63939', '#ae3ec9', '#0ca678', '#4263eb', '#f59f00', '#74b816', '#1098ad'];
    const color = colors[idx % colors.length];
    return `
      <div class="mb-2">
        <div class="d-flex justify-content-between mb-1">
          <span class="small text-truncate" style="max-width: 180px;" title="${name}">${name}</span>
          <span class="small fw-bold" style="color:${color}">${valPct}%</span>
        </div>
        <div class="progress" style="height: 8px;">
          <div class="progress-bar" style="width: ${pct}%; background-color: ${color};"></div>
        </div>
      </div>
    `;
  }).join('');
  
  container.innerHTML = bars;
}

function renderFeatureList(features) {
  const container = qs('ai-features');
  const countEl = qs('ai-feature-count');
  if (!container) return;
  
  if (features.length === 0) {
    container.innerHTML = `<span class="text-muted small">${t('empty.no_features', 'No features')}</span>`;
    return;
  }
  
  if (countEl) countEl.textContent = tf('label.features_count', '{count} features', { count: features.length });
  
  // Group features by category
  const categories = {
    price: ['price', 'ret_', 'ema_', 'atr', 'bb_', 'realized_vol', 'vol_pct', 'momentum', 'dev_'],
    indicator: ['rsi', 'macd', 'anchor', 'z', 'pb_slope'],
    volume: ['volume', 'notional', 'vol_base'],
    regime: ['regime_'],
    strategy: ['strategy_'],
    meta: ['bar_sec', 'bars', 'has_pos', 'btc_', 'coin_vs_']
  };
  
  const badges = features.map(f => {
    let cat = 'meta';
    for (const [c, patterns] of Object.entries(categories)) {
      if (patterns.some(p => f.startsWith(p) || f.includes(p))) { cat = c; break; }
    }
    const catColors = {
      price: 'bg-blue-lt', indicator: 'bg-green-lt', volume: 'bg-yellow-lt',
      regime: 'bg-purple-lt', strategy: 'bg-pink-lt', meta: 'bg-secondary-lt'
    };
    return `<span class="badge ${catColors[cat]} small" title="${cat}">${f}</span>`;
  }).join('');
  
  container.innerHTML = badges;
}

function renderStrategyDistribution(distribution) {
  const container = qs('ai-strategy-dist');
  if (!container) return;
  
  const entries = Object.entries(distribution);
  if (entries.length === 0) {
    container.innerHTML = `<span class="text-muted small">${t('empty.no_strategy_data', 'No strategy data')}</span>`;
    return;
  }
  
  const total = entries.reduce((acc, [, v]) => acc + v, 0);
  const stratColors = {
    pingpong: '#206bc4', autoloop: '#2fb344', ladder: '#f76707',
    lightning: '#d63939', gazua: '#ae3ec9', contrarian: '#9c27b0'
  };
  
  const badges = entries.map(([strat, count]) => {
    const pct = total > 0 ? ((count / total) * 100).toFixed(1) : 0;
    const color = stratColors[strat.toLowerCase()] || '#6c757d';
    return `
      <div class="d-flex align-items-center gap-1 px-2 py-1 rounded" style="background: ${color}22; border: 1px solid ${color}44;">
        <span class="badge" style="background: ${color};">${strat.toUpperCase()}</span>
        <span class="small fw-bold">${count.toLocaleString()}</span>
        <span class="small text-muted">(${pct}%)</span>
      </div>
    `;
  }).join('');
  
  container.innerHTML = badges;
}

// ============================================================
// Manual / Batch Trade
// ============================================================

function getManualSide() {
  return document.querySelector('input[name="manual-side"]:checked')?.value || 'buy';
}
function getManualUnit() {
  return document.querySelector('input[name="manual-unit"]:checked')?.value || 'pct';
}
function getBatchSide() {
  return document.querySelector('input[name="batch-side"]:checked')?.value || 'buy';
}
function getBatchUnit() {
  return document.querySelector('input[name="batch-unit"]:checked')?.value || 'pct';
}

function updateManualHints() {
  const side = getManualSide();
  const sellAllBtn = qs('btn-manual-sell-all');
  if (sellAllBtn) {
    sellAllBtn.style.display = side === 'sell' ? '' : 'none';
  }
  
  const hintEl = qs('manual-hint');
  if (!hintEl) return;
  
  const market = qs('manual-market-select')?.value;
  const unit = getManualUnit();
  const value = parseFloat(qs('manual-value')?.value) || 0;
  
  if (!market || !value) {
    hintEl.textContent = '';
    return;
  }
  
  const m = market.endsWith('USDT') ? market : `${market}USDT`;
  const price = state.prices?.[m] || 0;
  
  if (!price) {
    hintEl.textContent = t('hint.no_price_info', 'No price data');
    return;
  }
  
  const mktData = state.managedMarkets.find(x => x.market === m);
  const allocUsdt = mktData?.allocated_usdt || mktData?.budget_usdt || 0;
  const holding = mktData?.holding_qty || mktData?.qty || 0;
  
  if (side === 'buy') {
    if (unit === 'usdt') {
      const qty = value / price;
      hintEl.textContent = tf('hint.estimated_qty_symbol', 'Estimated qty: {qty} {symbol}', {
        qty: qty.toFixed(8),
        symbol: extractBase(m),
      });
    } else {
      const amount = allocUsdt * (value / 100);
      const qty = amount / price;
      hintEl.textContent = tf('hint.estimated_amount_to_qty', 'Estimated: {amount} -> {qty} {symbol}', {
        amount: fmtUsdt(amount),
        qty: qty.toFixed(6),
        symbol: extractBase(m),
      });
    }
  } else {
    if (unit === 'usdt') {
      const qty = value / price;
      hintEl.textContent = tf('hint.estimated_sell_qty_symbol', 'Estimated sell: {qty} {symbol}', {
        qty: qty.toFixed(8),
        symbol: extractBase(m),
      });
    } else {
      const qty = holding * (value / 100);
      const usdtAmt = qty * price;
      hintEl.textContent = tf('hint.estimated_qty_to_amount', 'Estimated: {qty} {symbol} -> {amount}', {
        qty: qty.toFixed(6),
        symbol: extractBase(m),
        amount: fmtUsdt(usdtAmt),
      });
    }
  }
}

function updateBatchHints() {
  const side = getBatchSide();
  const sellAllBtn = qs('btn-batch-sell-all');
  if (sellAllBtn) {
    sellAllBtn.style.display = side === 'sell' ? '' : 'none';
  }
  
  const markets = pickBatchMarkets();
  const hintEl = qs('batch-hint');
  if (!hintEl) return;
  
  if (!markets.length) {
    hintEl.textContent = t('hint.no_target_markets', 'No target markets');
    return;
  }
  
  const unit = getBatchUnit();
  const value = parseFloat(qs('batch-value')?.value) || 0;
  
  let totalEstUsdt = 0;
  markets.forEach(m => {
    const mkt = state.managedMarkets.find(x => x.market === m);
    const price = state.prices?.[m] || 0;
    const allocUsdt = mkt?.allocated_usdt || mkt?.budget_usdt || 0;
    const holding = mkt?.holding_qty || mkt?.qty || 0;
    
    if (side === 'buy') {
      if (unit === 'usdt') {
        totalEstUsdt += value;
      } else {
        totalEstUsdt += allocUsdt * (value / 100);
      }
    } else {
      if (unit === 'usdt') {
        totalEstUsdt += value;
      } else {
        totalEstUsdt += holding * price * (value / 100);
      }
    }
  });
  
  const actionLabel = side === 'buy' ? t('word.buy', 'Buy') : t('word.sell', 'Sell');
  hintEl.textContent = tf('hint.batch_estimate', 'Target: {count} markets · Estimated {action}: {amount}', {
    count: markets.length,
    action: actionLabel,
    amount: fmtUsdt(totalEstUsdt),
  });
}

function pickBatchMarkets() {
  const activeOnly = qs('batch-active-only')?.checked ?? true;
  const skipManual = qs('batch-skip-manual')?.checked ?? false;
  
  let markets = [];
  if (activeOnly) {
    const active = state.oma?.active || [];
    markets = active.map(x => typeof x === 'string' ? x : x.market).filter(Boolean);
  } else {
    markets = state.managedMarkets.map(m => m.market);
  }
  
  if (skipManual) {
    markets = markets.filter(m => {
      const mkt = state.managedMarkets.find(x => x.market === m);
      return !mkt?.manual_enabled;
    });
  }
  
  return [...new Set(markets)];
}

function setManualMsg(msg, ok) {
  const el = qs('manual-trade-msg');
  if (!el) return;
  el.textContent = msg;
  el.className = `small mt-2 ${ok ? 'text-success' : 'text-danger'}`;
}

async function submitManualOrder(payload) {
  const res = await authFetch(API.engineManualOrder, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  });
  return await res.json();
}

async function submitManualBatch(payload) {
  const res = await authFetch(API.engineManualBatch, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  });
  return await res.json();
}

async function doReconcile(reason = 'ui_manual') {
  const res = await authFetch(`${API.systemReconcile}?reason=${encodeURIComponent(reason)}`, { method: 'POST' });
  return await res.json();
}

function bindManualTradeEvents() {
  // Side toggle
  document.querySelectorAll('input[name="manual-side"]').forEach(el => {
    el.addEventListener('change', updateManualHints);
  });
  document.querySelectorAll('input[name="batch-side"]').forEach(el => {
    el.addEventListener('change', updateBatchHints);
  });
  qs('batch-active-only')?.addEventListener('change', updateBatchHints);
  qs('batch-skip-manual')?.addEventListener('change', updateBatchHints);
  
  // Manual hints: market, value, unit changes
  qs('manual-market-select')?.addEventListener('change', updateManualHints);
  qs('manual-value')?.addEventListener('input', updateManualHints);
  document.querySelectorAll('input[name="manual-unit"]').forEach(el => {
    el.addEventListener('change', updateManualHints);
  });
  
  // Batch hints: value, unit changes
  qs('batch-value')?.addEventListener('input', updateBatchHints);
  document.querySelectorAll('input[name="batch-unit"]').forEach(el => {
    el.addEventListener('change', updateBatchHints);
  });
  
  // Manual Sync
  qs('btn-manual-sync')?.addEventListener('click', async () => {
    try {
      setManualMsg(t('status.syncing', 'Syncing...'), true);
      await doReconcile('ui_manual_sync');
      await fetchActiveMarkets();
      setManualMsg(t('status.sync_complete', 'Sync complete'), true);
    } catch (e) {
      setManualMsg(`${t('status.sync_failed', 'Sync failed')}: ${e.message}`, false);
    }
  });
  
  // Manual Submit
  qs('btn-manual-submit')?.addEventListener('click', async () => {
    const market = qs('manual-market-select')?.value;
    if (!market) {
      setManualMsg(t('error.select_market', 'Please select a market'), false);
      return;
    }
    
    const side = getManualSide();
    const unit = getManualUnit();
    const value = parseFloat(qs('manual-value')?.value) || 0;
    
    if (value <= 0) {
      setManualMsg(t('error.enter_value', 'Please enter a value'), false);
      return;
    }
    
    const reconcileAfter = qs('manual-reconcile-after')?.checked ?? true;
    let mode = unit === 'pct' ? (side === 'buy' ? 'pct_alloc' : 'pct_pos') : 'usdt';
    
    const what = side === 'buy' ? 'BUY' : 'SELL';
    const confirmMsg = tf(
      'confirm.manual_trade',
      '[Manual Trade]\n{what} {value}\nMarket: {market}\nProceed?',
      {
        what,
        value: unit === 'pct' ? `${value}%` : formatAmount(value),
        market,
      },
    );
    if (!confirm(confirmMsg)) return;
    
    try {
      setManualMsg(t('status.processing', 'Processing...'), true);
      const r = await submitManualOrder({ market, side, mode, value, reconcile_after: reconcileAfter });
      if (r && r.ok) {
        setManualMsg(tf('status.manual_submitted', '{what} submitted: {market}', { what, market }), true);
        if (reconcileAfter) await doReconcile(`ui_manual_${what.toLowerCase()}`);
        await fetchActiveMarkets();
      } else {
        setManualMsg(tf('status.manual_failed', '{what} failed: {error}', { what, error: r?.error || 'unknown' }), false);
      }
    } catch (e) {
      setManualMsg(tf('status.manual_failed', '{what} failed: {error}', { what, error: e.message }), false);
    }
  });
  
  // Manual Sell All
  qs('btn-manual-sell-all')?.addEventListener('click', async () => {
    const market = qs('manual-market-select')?.value;
    if (!market) {
      setManualMsg(t('error.select_market', 'Please select a market'), false);
      return;
    }
    
    const confirmMsg = tf(
      'confirm.manual_sell_all',
      '[Manual Trade]\nSELL ALL (100%)\nMarket: {market}\nProceed?',
      { market },
    );
    if (!confirm(confirmMsg)) return;
    
    const reconcileAfter = qs('manual-reconcile-after')?.checked ?? true;
    
    try {
      setManualMsg(t('status.processing', 'Processing...'), true);
      const r = await submitManualOrder({ market, side: 'sell', mode: 'all', value: 100, reconcile_after: reconcileAfter });
      if (r && r.ok) {
        setManualMsg(t('status.sell_all_submitted', 'SELL ALL submitted'), true);
        if (reconcileAfter) await doReconcile('ui_manual_sell_all');
        await fetchActiveMarkets();
      } else {
        setManualMsg(tf('status.sell_all_failed', 'SELL ALL failed: {error}', { error: r?.error || 'unknown' }), false);
      }
    } catch (e) {
      setManualMsg(tf('status.sell_all_failed', 'SELL ALL failed: {error}', { error: e.message }), false);
    }
  });
  
  // Batch Submit
  qs('btn-batch-submit')?.addEventListener('click', async () => {
    const markets = pickBatchMarkets();
    if (!markets.length) {
      setManualMsg(t('error.no_target_markets', 'No target markets'), false);
      return;
    }
    
    const side = getBatchSide();
    const unit = getBatchUnit();
    const value = parseFloat(qs('batch-value')?.value) || 0;
    
    if (value <= 0) {
      setManualMsg(t('error.enter_value', 'Please enter a value'), false);
      return;
    }
    
    const what = side === 'buy' ? 'BUY' : 'SELL';
    const confirmMsg = tf(
      'confirm.batch_trade',
      '[Batch Trade]\n{what} {value}\nTarget: {count} markets\nProceed?',
      {
        what,
        value: unit === 'pct' ? `${value}%` : formatAmount(value),
        count: markets.length,
      },
    );
    if (!confirm(confirmMsg)) return;
    
    let mode = unit === 'pct' ? (side === 'buy' ? 'pct_alloc' : 'pct_pos') : 'usdt';
    
    try {
      setManualMsg(t('status.processing_batch', 'Processing batch...'), true);
      const r = await submitManualBatch({ markets, side, mode, value });
      if (r && r.ok) {
        const ok = r.results?.filter(x => x.ok).length || 0;
        const fail = r.results?.filter(x => !x.ok).length || 0;
        setManualMsg(tf('status.batch_complete', 'Batch complete: {ok} ok, {fail} failed', { ok, fail }), ok > 0);
        await fetchActiveMarkets();
      } else {
        setManualMsg(tf('status.batch_failed', 'Batch failed: {error}', { error: r?.error || 'unknown' }), false);
      }
    } catch (e) {
      setManualMsg(tf('status.batch_failed', 'Batch failed: {error}', { error: e.message }), false);
    }
  });
  
  // Batch Sell All
  qs('btn-batch-sell-all')?.addEventListener('click', async () => {
    const markets = pickBatchMarkets();
    if (!markets.length) {
      setManualMsg(t('error.no_target_markets', 'No target markets'), false);
      return;
    }
    
    const confirmMsg = tf(
      'confirm.batch_sell_all',
      '[Batch Trade]\nSELL ALL (100%)\nTarget: {count} markets\nProceed?',
      { count: markets.length },
    );
    if (!confirm(confirmMsg)) return;
    
    try {
      setManualMsg(t('status.processing_batch_sell_all', 'Processing batch SELL ALL...'), true);
      const r = await submitManualBatch({ markets, side: 'sell', mode: 'all', value: 100 });
      if (r && r.ok) {
        const ok = r.results?.filter(x => x.ok).length || 0;
        setManualMsg(tf('status.batch_sell_all_complete', 'Batch SELL ALL: {ok} completed', { ok }), true);
        await fetchActiveMarkets();
      } else {
        setManualMsg(tf('status.batch_sell_all_failed', 'Batch SELL ALL failed: {error}', { error: r?.error || 'unknown' }), false);
      }
    } catch (e) {
      setManualMsg(tf('status.batch_sell_all_failed', 'Batch SELL ALL failed: {error}', { error: e.message }), false);
    }
  });
  
  // Update market select with managed markets
  updateManualMarketSelect();
  updateManualHints();
  updateBatchHints();
}

function updateManualMarketSelect() {
  const select = qs('manual-market-select');
  if (!select) return;
  
  const current = select.value;
  select.innerHTML = `<option value="">${t('placeholder.select_market_option', '-- Select Market --')}</option>`;
  
  state.managedMarkets.forEach(m => {
    const opt = document.createElement('option');
    opt.value = m.market;
    opt.textContent = extractBase(m.market);
    select.appendChild(opt);
  });
  
  if (current && state.managedMarkets.find(m => m.market === current)) {
    select.value = current;
  }
}

// ============================================================
// Reserved Queue Detail Render
// ============================================================

function renderReservedTable(items) {
  const queueEl = qs('rs-queue');
  if (!queueEl) return;
  
  if (!items.length) {
    queueEl.innerHTML = '<div class="text-muted text-center p-3">(empty)</div>';
    return;
  }
  
  const toState = qs('rs-promote-active')?.checked ? 'ACTIVE' : 'WATCH';
  const applyBudget = qs('rs-apply-budget')?.checked ?? true;
  
  queueEl.innerHTML = items.map(it => {
    const m = it.metrics || {};
    const ai = it.ai_features || {};
    const rec = it.recommended_params || {};
    const strat = (it.strategy || '').toUpperCase();
    
    const spreadBps = m.spread_bps != null ? m.spread_bps.toFixed(1) : '-';
    const depth = Math.min(m.depth_ask_usdt || 0, m.depth_bid_usdt || 0);
    const vol24 = m.vol24_usdt || 0;
    const rangeRatio = m.range_ratio_24h != null ? (m.range_ratio_24h * 100).toFixed(1) : '-';
    
    const trend = ai.trend || 0;
    const momentum = ai.momentum || 0;
    const volatility = ai.volatility || 0;
    const aiScore = it.ai_score || 0.5;
    const trendIcon = trend > 0.1 ? '📈' : (trend < -0.1 ? '📉' : '➡️');
    const aiIcon = aiScore >= 0.8 ? '🔥' : (aiScore < 0.4 ? '⚠️' : '');
    
    let recHtml = '';
    if (strat === 'LADDER' && rec.tp_pct) {
      recHtml = `<span class="text-info">Steps ${rec.steps || '-'} Gap ${rec.step_pct || '-'}% TP ${rec.tp_pct}%</span>`;
    } else if (strat === 'LIGHTNING' && rec.tp_pct) {
      recHtml = `<span class="text-info">TP ${rec.tp_pct}% SL ${rec.sl_pct}%</span>`;
    } else if (strat === 'GAZUA' && rec.tp_pct) {
      recHtml = `<span class="text-info">TP ${rec.tp_pct}% SL ${rec.sl_pct}%</span>`;
    }
    
    return `
      <div class="p-2 border-bottom">
        <div class="d-flex justify-content-between align-items-center mb-1">
          <div>
            <strong>${extractBase(it.market)}</strong>
            <span class="badge ${getStrategyBadgeClass(strat)} ms-2">${strat}</span>
            ${it.names?.kr ? `<span class="text-muted small ms-1">(${it.names.kr})</span>` : ''}
          </div>
          <div class="btn-group btn-group-sm">
            <button class="btn btn-ghost-secondary" onclick="alert(JSON.stringify(${JSON.stringify(it).replace(/"/g, '&quot;')}, null, 2))">Details</button>
            <button class="btn btn-outline-danger" onclick="rejectReserved('${it.id}')">Reject</button>
            <button class="btn btn-success" onclick="approveReserved('${it.id}', '${toState}', ${applyBudget})">Approve→${toState}</button>
          </div>
        </div>
        <div class="small text-muted mb-1">
          Budget <b>${formatAmount(it.suggested_budget_usdt)}</b> · 
          Spread <b>${spreadBps} bps</b> · 
          Depth <b>${formatAmount(depth)}</b> · 
          Vol24 <b>${formatAmount(vol24)}</b> · 
          Range <b>${rangeRatio}%</b>
          ${it.drop_counts ? ` · <span class="badge bg-secondary-lt small" title="Drop counts">${summarizeDropCounts(it.drop_counts)}</span>` : ''}
        </div>
        <div class="small">
          ${it.confidence != null ? `<span class="badge ${it.confidence >= 50 ? 'bg-success-lt' : it.confidence >= 30 ? 'bg-warning-lt' : 'bg-danger-lt'}" title="전략 신뢰도 (${it.stages_passed || 0}/6 stages)">신뢰 <b>${it.confidence.toFixed(1)}%</b></span> · ` : ''}
          AI <b>${aiIcon} ${(aiScore * 100).toFixed(0)}%</b> ·
          Trend <b>${trendIcon} ${(trend * 100).toFixed(1)}%</b> ·
          Vol <b>${(volatility).toFixed(2)}%</b>
          ${m.risk_score != null ? ` · Risk <b>${m.risk_score.toFixed(1)}</b>` : ''}
          ${recHtml ? ` · ${t('table.recommendation', 'Recommendation')}: ` + recHtml : ''}
        </div>
      </div>
    `;
  }).join('');
}

function renderReservedHistory(history) {
  const tbody = qs('reserved-history-body');
  if (!tbody) return;
  
  if (!history.length) {
    tbody.innerHTML = '<tr><td colspan="5" class="text-muted text-center">No history</td></tr>';
    return;
  }
  
  const maxShow = parseInt(qs('rs-history-max')?.value) || 10;
  const sorted = [...history].sort((a, b) => (b.ts || 0) - (a.ts || 0)).slice(0, maxShow);
  
  const kindBadge = (kind, status) => {
    const k = (kind || '').toUpperCase();
    const s = (status || '').toUpperCase();
    
    // Use status badge if available
    if (s && s !== k) {
      const statusClass = getReservedStatusBadge(s);
      return `<span class="badge ${statusClass}">${k || s}</span>`;
    }
    
    if (k === 'PROMOTE' || k === 'APPROVE' || k === 'APPROVED') return `<span class="badge bg-success-lt">${k}</span>`;
    if (k === 'DEMOTE' || k === 'DEMOTED') return `<span class="badge bg-warning-lt">${k}</span>`;
    if (k === 'REJECT' || k === 'REJECTED') return `<span class="badge bg-danger-lt">${k}</span>`;
    if (k === 'AUTOPILOT_SKIP') return `<span class="badge bg-dark-lt">SKIP</span>`;
    if (k === 'PROMOTED') return `<span class="badge bg-info-lt">${k}</span>`;
    if (k === 'PENDING') return `<span class="badge bg-warning-lt">${k}</span>`;
    return `<span class="badge bg-secondary-lt">${k || 'EV'}</span>`;
  };
  
  tbody.innerHTML = sorted.map(ev => {
    const ts = ev.ts ? new Date(ev.ts * 1000).toLocaleString() : '-';
    const stateChange = ev.from_state || ev.to_state 
      ? `${ev.from_state || '-'}→${ev.to_state || '-'}` 
      : '';
    
    return `<tr>
      <td class="small">${ts}</td>
      <td><strong>${extractBase(ev.market || '')}</strong></td>
      <td><span class="badge ${getStrategyBadgeClass(ev.strategy)}">${ev.strategy || '-'}</span></td>
      <td>${kindBadge(ev.kind, ev.status)}</td>
      <td class="small">${stateChange}${ev.reason ? ` (${ev.reason.slice(0, 30)})` : ''}</td>
    </tr>`;
  }).join('');
}

// ============================================================
// Market Rankings
// ============================================================

async function loadRankings(tab, apiUrl, force = false) {
  const contentEl = qs('ranking-content');
  if (!contentEl) return;
  
  state.currentRankingTab = tab;
  
  // Check cache
  if (!force && state.rankingsCache[tab]) {
    renderRankingContent(tab, state.rankingsCache[tab]);
    return;
  }
  
  contentEl.innerHTML = renderListSkeleton(5);
  
  try {
    const res = await authFetch(apiUrl + '?top_n=10&min_volume_usdt=1000000');
    const data = await res.json();
    
    if (data.ok || data.rankings) {
      state.rankingsCache[tab] = data;
      renderRankingContent(tab, data);
    } else {
      contentEl.innerHTML = `<div class="text-muted text-center p-3">${t('empty.no_data', 'No data')}</div>`;
    }
  } catch (e) {
    console.error('loadRankings error:', e);
    contentEl.innerHTML = `<div class="text-danger text-center p-3">Error: ${e.message}</div>`;
  }
}

function renderRankingContent(tab, data) {
  const contentEl = qs('ranking-content');
  if (!contentEl) return;
  
  const rankings = data.rankings || [];
  if (!rankings.length) {
    const emptyMsgs = {
      rebound: t('ranking.empty.rebound', 'No fallen coins (market stable)'),
      rsi: t('ranking.empty.rsi', 'No oversold coins'),
      tech: t('ranking.empty.tech', 'No buy signals'),
      upside: t('ranking.empty.upside', 'No data')
    };
    contentEl.innerHTML = `<div class="text-muted text-center p-4">${emptyMsgs[tab] || t('empty.no_data', 'No data')}</div>`;
    return;
  }
  
  const formatPrice = (p) => {
    if (!p || p <= 0) return '-';
    if (p >= 1000) return '$' + Math.round(p).toLocaleString();
    return '$' + p.toFixed(2);
  };
  
  contentEl.innerHTML = rankings.slice(0, 10).map((r, i) => {
    const medal = ['🥇', '🥈', '🥉', '4️⃣', '5️⃣', '6️⃣', '7️⃣', '8️⃣', '9️⃣', '🔟'][i] || `${i+1}`;
    const market = r.market || r.symbol || '';
    const currency = r.currency || extractBase(market);
    const price = r.current_price || r.price || 0;
    const changeRate = r.change_rate ?? r.change_pct ?? 0;
    const changeColor = changeRate >= 0 ? 'text-success' : 'text-danger';
    const score = r.rebound_score ?? r.total_score ?? r.upside_score ?? r.rsi ?? 0;
    
    let scoreLabel = '';
    let scoreBadge = '';
    if (tab === 'rsi') {
      const rsiColor = r.rsi < 30 ? 'bg-danger-lt' : (r.rsi < 40 ? 'bg-warning-lt' : 'bg-secondary-lt');
      scoreBadge = `<span class="badge ${rsiColor}">RSI ${r.rsi || '-'}</span>`;
      scoreLabel = r.rsi_status || '';
    } else if (tab === 'tech') {
      const signalRaw = String(r.signal || '').trim();
      const signalLower = signalRaw.toLowerCase();
      const isStrongBuy = signalLower.includes('strong') || signalRaw.includes('\uac15\ub825');
      const isBuy = signalLower.includes('buy') || signalRaw.includes('\ub9e4\uc218');
      const emoji = isStrongBuy ? '🚀' : (isBuy ? '📈' : '➡️');
      scoreBadge = `<span class="badge bg-primary-lt">${emoji} ${tf('ranking.score_point', '{score} pt', { score })}</span>`;
      scoreLabel = isStrongBuy
        ? t('signal.strong_buy', 'Strong Buy')
        : (isBuy ? t('signal.buy', 'Buy') : (signalRaw || ''));
    } else if (tab === 'rebound') {
      const sevRaw = String(r.decline_severity || '').trim();
      const sevLower = sevRaw.toLowerCase();
      let sevIcon = '⚪';
      if (sevLower.includes('crash') || sevRaw.includes('\ud3ed\ub77d')) sevIcon = '🔴';
      else if (sevLower.includes('sharp') || sevRaw.includes('\uae09\ub77d')) sevIcon = '🟠';
      else if (sevLower.includes('down') || sevRaw.includes('\ud558\ub77d')) sevIcon = '🟡';
      else if (sevLower.includes('pullback') || sevRaw.includes('\uc870\uc815')) sevIcon = '🟢';
      scoreBadge = `<span class="badge bg-info-lt">${sevIcon} ${tf('ranking.score_point', '{score} pt', { score })}</span>`;
      scoreLabel = `${changeRate.toFixed(1)}%`;
    } else {
      scoreBadge = `<span class="badge bg-success-lt">${tf('ranking.score_label', 'Score {score}', { score })}</span>`;
    }
    
    return `
      <div class="d-flex justify-content-between align-items-center p-2 border-bottom ranking-item" 
           style="cursor:pointer" onclick="window.open('/ui/market_detail.html?market=${encodeURIComponent(market)}','_blank')">
        <div class="d-flex align-items-center gap-2">
          <span style="font-size:1.1rem;min-width:24px">${medal}</span>
          <strong>${currency}</strong>
          <span class="text-success small">${formatPrice(price)}</span>
        </div>
        <div class="d-flex align-items-center gap-2">
          ${scoreBadge}
          <span class="${changeColor} small">${changeRate >= 0 ? '+' : ''}${changeRate.toFixed(1)}%</span>
        </div>
      </div>
    `;
  }).join('');
}

function bindRankingEvents() {
  // Tab clicks
  document.querySelectorAll('.ranking-tab').forEach(tab => {
    tab.addEventListener('click', (e) => {
      e.preventDefault();
      document.querySelectorAll('.ranking-tab').forEach(t => t.classList.remove('active'));
      tab.classList.add('active');
      loadRankings(tab.dataset.tab, tab.dataset.api);
    });
  });
  
  // Refresh button
  const refreshBtn = qs('btn-refresh-rankings');
  if (refreshBtn) {
    refreshBtn.addEventListener('click', () => {
      const activeTab = document.querySelector('.ranking-tab.active');
      if (activeTab) {
        state.rankingsCache = {};
        loadRankings(activeTab.dataset.tab, activeTab.dataset.api, true);
      }
    });
  }
}

// ============================================================
// Kimchi Premium (김프 비교)
// ============================================================

async function loadKimchiPremium() {
  // Disabled: binance-compare endpoint removed (Bybit-only)
  return;
  
  const marketInput = qs('kimchi-market');
  const rateInput = qs('kimchi-rate');
  
  const markets = marketInput?.value.trim() || '';
  const rate = parseFloat(rateInput?.value) || 0;
  
  tbody.innerHTML = `<tr><td colspan="4" class="text-muted text-center">${t('label.loading', 'Loading...')}</td></tr>`;
  
  try {
    const url = API.binanceCompare(markets, rate > 0 ? rate : undefined);
    const res = await authFetch(url);
    const data = await res.json();
    
    if (data.exchange_rate) {
      state.exchangeRate = data.exchange_rate;
      if (rateDisplay) {
        rateDisplay.innerHTML = tf('label.exchange_rate_usd', 'Rate: <b class="text-success">{rate}</b> USD rate', {
          rate: data.exchange_rate.toLocaleString()
        });
      }
      if (rateInput && !rateInput.value) {
        rateInput.value = data.exchange_rate;
      }
    }
    
    if (!data.ok || !data.data || !data.data.length) {
      tbody.innerHTML = `<tr><td colspan="4" class="text-muted text-center">${t('empty.no_data', 'No data')}</td></tr>`;
      return;
    }
    
    tbody.innerHTML = data.data.map(item => {
      const premiumColor = item.premium_pct > 0 ? 'text-danger' : (item.premium_pct < 0 ? 'text-success' : '');
      const hasBinance = item.has_binance && item.binance_usdt > 0;
      const bybitFmt = item.bybit_usdt >= 1000 ? '$' + Math.round(item.bybit_usdt).toLocaleString() : '$' + item.bybit_usdt.toFixed(2);
      const binanceFmt = hasBinance ? '$' + (item.binance_usdt >= 1 ? item.binance_usdt.toLocaleString(undefined, {maximumFractionDigits: 2}) : item.binance_usdt.toFixed(6)) : '-';
      const premiumFmt = hasBinance ? (item.premium_pct > 0 ? '+' : '') + item.premium_pct + '%' : '-';
      
      return `<tr>
        <td><strong>${item.coin}</strong></td>
        <td class="text-end">${bybitFmt}</td>
        <td class="text-end text-warning">${binanceFmt}</td>
        <td class="text-end ${premiumColor}"><strong>${premiumFmt}</strong></td>
      </tr>`;
    }).join('');
  } catch (e) {
    console.error('loadKimchiPremium error:', e);
    tbody.innerHTML = `<tr><td colspan="4" class="text-danger text-center">Error: ${e.message}</td></tr>`;
  }
}

async function loadKimchiTop10() {
  // Disabled: binance-compare endpoint removed (Bybit-only)
  return;
  
  if (modeLabel) modeLabel.textContent = t('kimchi.top10', 'Kimchi TOP 10');
  tbody.innerHTML = `<tr><td colspan="4" class="text-muted text-center">${t('label.loading_top10', 'Loading TOP 10...')}</td></tr>`;
  
  try {
    // 주요 코인 50개 조회
    const topCoins = 'BTC,ETH,XRP,SOL,DOGE,ADA,AVAX,DOT,MATIC,LINK,UNI,ATOM,LTC,BCH,ETC,XLM,ALGO,VET,FIL,HBAR,SAND,MANA,AXS,ENJ,AAVE,CRV,SNX,COMP,MKR,YFI,SUSHI,1INCH,BAT,ZRX,LRC,IMX,APE,GMT,FLOW,NEAR,FTM,KLAY,THETA,EOS,XTZ,NEO,IOTA,EGLD,CELO,WAVES';
    const rate = parseFloat(qs('kimchi-rate')?.value) || 1450;
    
    const url = API.binanceCompare(topCoins, rate);
    const res = await authFetch(url);
    const data = await res.json();
    
    if (!data.ok || !data.data || !data.data.length) {
      tbody.innerHTML = `<tr><td colspan="4" class="text-muted text-center">${t('empty.no_data', 'No data')}</td></tr>`;
      return;
    }
    
    // 김프가 있는 코인만 필터링 후 절대값 기준 정렬
    const withPremium = data.data
      .filter(item => item.has_binance && item.binance_usdt > 0 && item.premium_pct !== 0)
      .sort((a, b) => Math.abs(b.premium_pct) - Math.abs(a.premium_pct))
      .slice(0, 10);
    
    if (!withPremium.length) {
      tbody.innerHTML = `<tr><td colspan="4" class="text-muted text-center">${t('empty.no_comparable_coins', 'No comparable coins')}</td></tr>`;
      return;
    }
    
    tbody.innerHTML = withPremium.map(item => {
      const premiumColor = item.premium_pct > 0 ? 'text-danger' : 'text-success';
      const bybitFmt = item.bybit_usdt >= 1000 ? '$' + Math.round(item.bybit_usdt).toLocaleString() : '$' + item.bybit_usdt.toFixed(2);
      const binanceFmt = '$' + (item.binance_usdt >= 1 ? item.binance_usdt.toLocaleString(undefined, {maximumFractionDigits: 2}) : item.binance_usdt.toFixed(6));
      const premiumFmt = (item.premium_pct > 0 ? '+' : '') + item.premium_pct.toFixed(1) + '%';
      
      return `<tr>
        <td><strong>${item.coin}</strong></td>
        <td class="text-end">${bybitFmt}</td>
        <td class="text-end text-warning">${binanceFmt}</td>
        <td class="text-end ${premiumColor}"><strong>${premiumFmt}</strong></td>
      </tr>`;
    }).join('');
  } catch (e) {
    console.error('loadKimchiTop10 error:', e);
    tbody.innerHTML = `<tr><td colspan="4" class="text-danger text-center">Error</td></tr>`;
  }
}

function bindKimchiPremiumEvents() {
  const loadBtn = qs('btn-kimchi-load');
  if (loadBtn) {
    loadBtn.addEventListener('click', () => {
      const modeLabel = qs('kimchi-mode-label');
      if (modeLabel) modeLabel.textContent = t('kimchi.selected_coin', 'Selected Coin');
      loadKimchiPremium();
    });
  }
  
  const topBtn = qs('btn-kimchi-top');
  if (topBtn) {
    topBtn.addEventListener('click', loadKimchiTop10);
  }
  
  const marketInput = qs('kimchi-market');
  if (marketInput) {
    marketInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') {
        const modeLabel = qs('kimchi-mode-label');
        if (modeLabel) modeLabel.textContent = t('kimchi.selected_coin', 'Selected Coin');
        loadKimchiPremium();
      }
    });
  }
  
  const rateInput = qs('kimchi-rate');
  if (rateInput) {
    rateInput.addEventListener('input', () => {
      rateInput.dataset.userEdited = 'true';  // 사용자가 수정하면 자동 업데이트 중지
    });
    rateInput.addEventListener('change', loadKimchiPremium);
  }

  // ★ [2026-05-31 형] 중복 id fix: kimchi-rate-main(메인 김프 패널) <-> kimchi-rate(canonical) 동기화.
  //   기존: 두 입력칸이 같은 id='kimchi-rate' → getElementById 가 첫째(상단 위젯)만 반환, 메인 패널 입력칸 죽음.
  //   fix: 메인 패널 id를 kimchi-rate-main 으로 분리 + 양방향 동기화 (편집 시 canonical 재계산 트리거).
  const _kMain = qs('kimchi-rate-main');
  if (_kMain && rateInput) {
    _kMain.addEventListener('input', () => {
      rateInput.value = _kMain.value;
      rateInput.dataset.userEdited = 'true';
      rateInput.dispatchEvent(new Event('change'));  // 재계산 트리거 (L6796/L15564 change 핸들러)
    });
    rateInput.addEventListener('input', () => { _kMain.value = rateInput.value; });  // 역방향 표시 동기화
  }
}

// ============================================================
// Market Alerts (상장폐지/신규상장/유의종목)
// ============================================================

async function loadMarketAlerts() {
  try {
    const res = await authFetch(API.marketStatusCheck);
    const data = await res.json();
    if (!data.ok) return;
    
    // Delisting
    const delistEl = qs('alert-delisting');
    if (delistEl) {
      if (data.delisting_alerts && data.delisting_alerts.length > 0) {
        delistEl.innerHTML = data.delisting_alerts.map(a => {
          const cls = a.severity === 'critical' ? 'text-danger fw-bold' : 'text-warning';
          return `<span class="${cls}">${a.korean_name || a.market} (${a.market}) - ${a.delisting_date || t('label.undecided', 'TBD')}</span>`;
        }).join('<br>');
      } else {
        delistEl.innerHTML = `<span class="text-muted">${t('label.none', 'None')}</span>`;
      }
    }
    
    // New listings
    const newEl = qs('alert-new-listing');
    if (newEl) {
      if (data.new_listings && data.new_listings.length > 0) {
        newEl.innerHTML = data.new_listings.map(a => 
          `<span class="text-success">${a.korean_name || a.market} (${a.market})</span>`
        ).join('<br>');
      } else {
        newEl.innerHTML = `<span class="text-muted">${t('label.none', 'None')}</span>`;
      }
    }
    
    // Preview (caution)
    const previewEl = qs('alert-preview');
    const previewCount = qs('alert-preview-count');
    if (previewCount) previewCount.textContent = data.preview_markets?.length || 0;
    if (previewEl) {
      if (data.preview_markets && data.preview_markets.length > 0) {
        previewEl.innerHTML = data.preview_markets.slice(0, 5).map(a => 
          `<span class="text-warning">${a.korean_name || a.market}</span>`
        ).join(', ') + (data.preview_markets.length > 5 ? tf('label.and_more_count', ' and {count} more', { count: data.preview_markets.length - 5 }) : '');
      } else {
        previewEl.innerHTML = `<span class="text-muted">${t('label.none', 'None')}</span>`;
      }
    }
  } catch (e) {
    console.error('loadMarketAlerts error:', e);
  }
}

function bindMarketAlertsEvents() {
  const btn = qs('btn-refresh-alerts');
  if (btn) btn.addEventListener('click', loadMarketAlerts);
}

// ============================================================
// Holdings Upside (보유 코인 상승여력)
// ============================================================

async function loadHoldingsUpside() {
  const listEl = qs('holdings-upside-list');
  if (!listEl) return;
  
  listEl.innerHTML = '<div class="text-muted text-center p-3"><i class="ti ti-loader ti-spin"></i></div>';
  
  try {
    const res = await authFetch(API.holdingsUpside + '?top_n=3');
    const data = await res.json();
    
    if (!data.ok && data.error) {
      listEl.innerHTML = `<div class="text-danger text-center p-3">${data.error}</div>`;
      return;
    }
    
    if (!data.rankings || !data.rankings.length) {
      listEl.innerHTML = `<div class="text-muted text-center p-3">${data.message || t('status.no_holdings', 'No holdings')}</div>`;
      return;
    }
    
    listEl.innerHTML = data.rankings.map((r, i) => {
      const medal = ['🥇', '🥈', '🥉'][i] || `${i+1}`;
      const pnlColor = r.pnl_pct >= 0 ? 'text-success' : 'text-danger';
      const scoreColor = r.upside_score >= 50 ? 'text-success' : (r.upside_score >= 30 ? 'text-warning' : 'text-muted');
      
      return `
        <div class="d-flex justify-content-between align-items-center p-2 border-bottom" 
             style="cursor:pointer" onclick="window.open('/ui/market_detail.html?market=${encodeURIComponent(r.market)}','_blank')">
          <div class="d-flex align-items-center gap-2">
            <span style="font-size:1.2rem">${medal}</span>
            <strong>${r.currency}</strong>
            <span class="${scoreColor} small">${tf('ranking.score_label', 'Score {score}', { score: r.upside_score })}</span>
          </div>
          <div class="text-end">
            <div class="${pnlColor} small">${r.pnl_pct >= 0 ? '+' : ''}${r.pnl_pct}%</div>
            <div class="text-muted small">${r.reason || t('status.analyzing', 'Analyzing')}</div>
          </div>
        </div>
      `;
    }).join('');
  } catch (e) {
    console.error('loadHoldingsUpside error:', e);
    listEl.innerHTML = `<div class="text-danger text-center p-3">Error</div>`;
  }
}

function bindHoldingsUpsideEvents() {
  const btn = qs('btn-refresh-upside');
  if (btn) btn.addEventListener('click', loadHoldingsUpside);
}

// ============================================================
// AI Gate Strictness
// ============================================================

async function loadAiGate() {
  try {
    const res = await authFetch(API.aiGate);
    const data = await res.json();
    if (!data || data.ok === false) return;
    
    const gate = data.gate || {};
    const stats = data.stats || {};
    
    const slider = qs('ai-gate-slider');
    const valueEl = qs('ai-gate-value');
    const eligibleEl = qs('ai-gate-eligible');
    
    const strictness = Number(gate.strictness);
    if (slider && Number.isFinite(strictness)) slider.value = strictness;
    if (valueEl) valueEl.textContent = Number.isFinite(strictness) ? strictness : '-';
    
    if (eligibleEl) {
      const eligible = stats.eligible;
      const total = stats.scoreboard_total;
      eligibleEl.textContent = (Number.isFinite(eligible) && Number.isFinite(total)) ? `${eligible}/${total}` : '-/-';
    }
  } catch (e) {
    console.error('loadAiGate error:', e);
  }
}

async function setAiGateStrictness(value) {
  try {
    const v = Math.max(0, Math.min(100, Number(value)));
    await authFetch(API.aiGate, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ strictness: v })
    });
    await loadAiGate();
  } catch (e) {
    console.error('setAiGateStrictness error:', e);
  }
}

function bindAiGateEvents() {
  const slider = qs('ai-gate-slider');
  const valueEl = qs('ai-gate-value');
  
  if (slider) {
    let debounce = null;
    slider.addEventListener('input', () => {
      if (valueEl) valueEl.textContent = slider.value;
    });
    slider.addEventListener('change', () => {
      clearTimeout(debounce);
      debounce = setTimeout(() => setAiGateStrictness(slider.value), 300);
    });
  }
}

// ============================================================
// Theme Management (Dark Mode)
// ============================================================

function initTheme() {
  const saved = localStorage.getItem(LS_THEME);
  const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
  const isDark = saved ? saved === 'dark' : prefersDark;
  
  applyTheme(isDark);
  
  const toggle = qs('theme-toggle');
  if (toggle) {
    toggle.checked = isDark;
    toggle.addEventListener('change', () => {
      applyTheme(toggle.checked);
      localStorage.setItem(LS_THEME, toggle.checked ? 'dark' : 'light');
    });
  }
}

function applyTheme(isDark) {
  document.documentElement.setAttribute('data-bs-theme', isDark ? 'dark' : 'light');
  
  const label = qs('theme-label');
  if (label) label.textContent = isDark ? 'Dark' : 'Light';
  
  // Tabler 특정 클래스
  document.body.classList.toggle('theme-dark', isDark);
}

// ============================================================
// Equity Snapshot Popup
// ============================================================

let equitySnapshotModal = null;
let equitySnapshotInitDone = false;

function nowDateString() {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}

function todayStartDateTimeLocalValue() {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}T00:00`;
}

function parseUsdtValue(v) {
  if (v == null) return 0;
  const s = String(v).replace(/[^0-9.-]/g, '');
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

function formatUsdtFull(n) {
  const num = Number(n) || 0;
  return `${Math.round(num).toLocaleString()}${t('unit.usdt', ' USDT')}`;
}

function getEquityFromSystem() {
  return Number(
    state?.system?.system?.equity?.equity_usdt ??
    state?.system?.equity?.equity_usdt ??
    0
  ) || 0;
}

function setEquitySnapshotSourceText(text, type = 'muted') {
  const el = qs('es-start-capital-source');
  if (!el) return;
  el.textContent = text || '';
  const map = {
    success: 'text-success',
    danger: 'text-danger',
    warning: 'text-warning',
    muted: 'text-muted',
  };
  el.className = `form-hint mt-1 ${map[type] || map.muted}`;
}

async function fetchStartCapitalFromDateTime(dtValue) {
  if (!dtValue) return false;
  try {
    setEquitySnapshotSourceText('기준 시각 금액 조회 중...', 'muted');
    const res = await authFetch(API.systemEquityAt(dtValue));
    const data = await res.json();
    if (!data?.ok || !Number.isFinite(Number(data.equity_usdt))) {
      setEquitySnapshotSourceText(data?.error || '기준 시각 금액을 찾지 못했습니다. 직접 입력하세요.', 'warning');
      return false;
    }

    const startCapitalEl = qs('es-start-capital');
    if (startCapitalEl) startCapitalEl.value = formatUsdtFull(Number(data.equity_usdt));
    setEquitySnapshotBaselineFromInputs();
    recalcEquitySnapshot();

    const at = data.actual_ts ? new Date(Number(data.actual_ts) * 1000).toLocaleString('ko-KR', { hour12: false }) : '-';
    const source = data.source_event || 'SNAPSHOT';
    const diffSec = Number(data.diff_sec || 0);
    setEquitySnapshotSourceText(`자동 조회: ${source} @ ${at} (오차 ${diffSec}초)`, 'success');
    return true;
  } catch (e) {
    setEquitySnapshotSourceText(`조회 실패: ${e.message}`, 'danger');
    return false;
  }
}

function loadEquitySnapshotBaseline() {
  try {
    const raw = localStorage.getItem(LS_EQUITY_SNAPSHOT_BASELINE);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== 'object') return null;
    return {
      start_datetime: parsed.start_datetime || '',
      start_capital: Number(parsed.start_capital) || 0,
      net_cash_flow: Number(parsed.net_cash_flow) || 0
    };
  } catch (_) {
    return null;
  }
}

function saveEquitySnapshotBaseline(startDatetime, startCapital, netCashFlow = 0) {
  const payload = {
    start_datetime: startDatetime || '',
    start_capital: Number(startCapital) || 0,
    net_cash_flow: Number(netCashFlow) || 0
  };
  localStorage.setItem(LS_EQUITY_SNAPSHOT_BASELINE, JSON.stringify(payload));
}

function refreshEquitySnapshotCurrentFields(equityOverride = null) {
  const currentAssetEl = qs('es-current-asset');
  const currentDtEl = qs('es-current-datetime');
  if (!currentAssetEl || !currentDtEl) return;

  const currentEquity = equityOverride != null ? Number(equityOverride) || 0 : getEquityFromSystem();
  currentAssetEl.value = formatUsdtFull(currentEquity);
  currentDtEl.value = new Date().toLocaleString('ko-KR', { hour12: false });
}

function recalcEquitySnapshot() {
  const startDtEl = qs('es-start-datetime');
  const startInput = qs('es-start-capital');
  const netCashFlowInput = qs('es-net-cash-flow');
  const currentInput = qs('es-current-asset');
  if (!startInput || !currentInput || !netCashFlowInput || !startDtEl) return;

  const startCapital = parseUsdtValue(startInput.value);
  const netCashFlow = parseUsdtValue(netCashFlowInput.value);
  const currentAsset = parseUsdtValue(currentInput.value);
  const adjustedBaseCapital = startCapital + netCashFlow;
  const netDelta = currentAsset - adjustedBaseCapital;
  const grossDelta = currentAsset - startCapital;
  const pct = adjustedBaseCapital > 0 ? (netDelta / adjustedBaseCapital) * 100 : 0;
  const profit = Math.max(0, netDelta);
  const loss = Math.max(0, -netDelta);

  const pctEl = qs('es-change-pct');
  const deltaEl = qs('es-change-usdt');
  const profitEl = qs('es-profit-usdt');
  const lossEl = qs('es-loss-usdt');
  const adjustedBaseEl = qs('es-adjusted-base-capital');
  const grossDeltaEl = qs('es-gross-change-usdt');
  const proj1PctEl = qs('es-proj-1pct');
  const projTrendEl = qs('es-proj-trend');
  const projTrendInfoEl = qs('es-proj-trend-info');

  if (pctEl) {
    pctEl.textContent = `${pct >= 0 ? '+' : ''}${pct.toFixed(2)}%`;
    pctEl.className = `h4 mb-0 ${pct >= 0 ? 'text-success' : 'text-danger'}`;
  }
  if (deltaEl) {
    deltaEl.textContent = `${netDelta >= 0 ? '+' : '-'}${formatUsdtFull(Math.abs(netDelta))}`;
    deltaEl.className = `h4 mb-0 ${netDelta >= 0 ? 'text-success' : 'text-danger'}`;
  }
  if (profitEl) profitEl.textContent = formatUsdtFull(profit);
  if (lossEl) lossEl.textContent = formatUsdtFull(loss);
  if (adjustedBaseEl) adjustedBaseEl.textContent = formatUsdtFull(adjustedBaseCapital);
  if (grossDeltaEl) {
    grossDeltaEl.textContent = `${grossDelta >= 0 ? '+' : '-'}${formatUsdtFull(Math.abs(grossDelta))}`;
    grossDeltaEl.className = `h5 mb-0 ${grossDelta >= 0 ? 'text-success' : 'text-danger'}`;
  }

  const yearFactor1Pct = Math.pow(1.01, 365);
  const projected1Pct = currentAsset > 0 ? currentAsset * yearFactor1Pct : 0;
  if (proj1PctEl) {
    proj1PctEl.textContent = formatUsdtFull(projected1Pct);
  }

  let projectedTrend = 0;
  let dailyRate = null;
  let trendInfoText = '-';
  // Use current net change (%) directly as "current average %/day".
  if (adjustedBaseCapital > 0 && currentAsset > 0) {
    dailyRate = pct / 100;
    if (Number.isFinite(dailyRate) && dailyRate > -0.9999) {
      projectedTrend = currentAsset * Math.pow(1 + dailyRate, 365);
      trendInfoText = `${dailyRate >= 0 ? '+' : ''}${(dailyRate * 100).toFixed(3)}%/day`;
    } else {
      dailyRate = null;
    }
  }

  if (projTrendEl) {
    projTrendEl.textContent = projectedTrend > 0 ? formatUsdtFull(projectedTrend) : '-';
  }
  if (projTrendInfoEl) {
    if (dailyRate == null || !Number.isFinite(dailyRate)) {
      projTrendInfoEl.textContent = trendInfoText;
      projTrendInfoEl.className = 'small text-muted';
    } else {
      projTrendInfoEl.textContent = trendInfoText;
      projTrendInfoEl.className = `small ${dailyRate >= 0 ? 'text-success' : 'text-danger'}`;
    }
  }
}

function setEquitySnapshotBaselineFromInputs() {
  const dtEl = qs('es-start-datetime');
  const startEl = qs('es-start-capital');
  const netCashFlowEl = qs('es-net-cash-flow');
  if (!dtEl || !startEl || !netCashFlowEl) return;
  saveEquitySnapshotBaseline(
    dtEl.value,
    parseUsdtValue(startEl.value),
    parseUsdtValue(netCashFlowEl.value),
  );
}

function hideEquitySnapshotToday() {
  localStorage.setItem(LS_EQUITY_SNAPSHOT_HIDE_DATE, nowDateString());
  if (equitySnapshotModal) equitySnapshotModal.hide();
}

function openEquitySnapshotPopup(force = false) {
  const modalEl = qs('equity-snapshot-modal');
  if (!modalEl || typeof bootstrap === 'undefined') return;
  if (!equitySnapshotModal) equitySnapshotModal = new bootstrap.Modal(modalEl);

  if (!force) {
    const hiddenDate = localStorage.getItem(LS_EQUITY_SNAPSHOT_HIDE_DATE);
    if (hiddenDate === nowDateString()) return;
  }
  equitySnapshotModal.show();
}

function bindEquitySnapshotEvents() {
  const openBtn = qs('btn-equity-snapshot-popup');
  const hideTodayBtn = qs('btn-equity-snapshot-hide-today');
  const saveBtn = qs('btn-equity-snapshot-save');
  const fetchStartBtn = qs('btn-es-fetch-start-capital');
  const startDtEl = qs('es-start-datetime');
  const startCapitalEl = qs('es-start-capital');
  const netCashFlowEl = qs('es-net-cash-flow');

  if (openBtn) {
    openBtn.addEventListener('click', () => openEquitySnapshotPopup(true));
  }
  if (hideTodayBtn) {
    hideTodayBtn.addEventListener('click', hideEquitySnapshotToday);
  }
  if (saveBtn) {
    saveBtn.addEventListener('click', () => {
      setEquitySnapshotBaselineFromInputs();
      recalcEquitySnapshot();
      showToast('수익 스냅샷 기준값 저장 완료 (입출금 보정 포함)', 'success');
    });
  }
  if (fetchStartBtn) {
    fetchStartBtn.addEventListener('click', async () => {
      if (!startDtEl?.value) {
        setEquitySnapshotSourceText('기준 시각을 먼저 입력하세요.', 'warning');
        return;
      }
      await fetchStartCapitalFromDateTime(startDtEl.value);
    });
  }
  if (startDtEl) {
    startDtEl.addEventListener('change', async () => {
      setEquitySnapshotBaselineFromInputs();
      await fetchStartCapitalFromDateTime(startDtEl.value);
    });
  }
  if (startCapitalEl) {
    startCapitalEl.addEventListener('input', () => {
      recalcEquitySnapshot();
    });
    startCapitalEl.addEventListener('change', () => {
      const v = parseUsdtValue(startCapitalEl.value);
      startCapitalEl.value = formatUsdtFull(v);
      setEquitySnapshotBaselineFromInputs();
      recalcEquitySnapshot();
    });
    startCapitalEl.addEventListener('blur', () => {
      const v = parseUsdtValue(startCapitalEl.value);
      startCapitalEl.value = formatUsdtFull(v);
    });
  }
  if (netCashFlowEl) {
    netCashFlowEl.addEventListener('input', () => {
      recalcEquitySnapshot();
    });
    netCashFlowEl.addEventListener('change', () => {
      const v = parseUsdtValue(netCashFlowEl.value);
      netCashFlowEl.value = formatUsdtFull(v);
      setEquitySnapshotBaselineFromInputs();
      recalcEquitySnapshot();
    });
    netCashFlowEl.addEventListener('blur', () => {
      const v = parseUsdtValue(netCashFlowEl.value);
      netCashFlowEl.value = formatUsdtFull(v);
    });
  }
}

async function initEquitySnapshotPopup() {
  if (equitySnapshotInitDone) return;
  equitySnapshotInitDone = true;

  const startDtEl = qs('es-start-datetime');
  const startCapitalEl = qs('es-start-capital');
  const netCashFlowEl = qs('es-net-cash-flow');
  if (!startDtEl || !startCapitalEl || !netCashFlowEl) return;

  const baseline = loadEquitySnapshotBaseline();
  const currentEquity = getEquityFromSystem();

  if (baseline?.start_datetime) {
    startDtEl.value = baseline.start_datetime;
  } else {
    startDtEl.value = todayStartDateTimeLocalValue();
  }

  if (baseline?.start_capital > 0) {
    startCapitalEl.value = formatUsdtFull(baseline.start_capital);
  } else {
    const loaded = await fetchStartCapitalFromDateTime(startDtEl.value);
    if (!loaded) {
      const initial = currentEquity > 0 ? currentEquity : 0;
      startCapitalEl.value = formatUsdtFull(initial);
      setEquitySnapshotSourceText('자동 조회 실패: 현재 총자산으로 임시 설정됨', 'warning');
      saveEquitySnapshotBaseline(startDtEl.value, initial);
    }
  }
  netCashFlowEl.value = formatUsdtFull(baseline?.net_cash_flow || 0);

  refreshEquitySnapshotCurrentFields(currentEquity);
  recalcEquitySnapshot();

  setTimeout(() => openEquitySnapshotPopup(false), 1200);
}

