// Initialization
// ============================================================

async function init() {
  console.log('Autocoin OS Dashboard v2 initializing...');
  
  // Theme first
  initTheme();
  initLanguage();
  
  // Bind events
  bindNavigationEvents();
  bindAdminPanelEvents();
  bindStrategyPanelEvents();
  bindAIRiskEvents();
  bindReportEvents();
  bindQuickTradeEvents();
  bindQuickTrade2Events();  // 2026-02-02: Markets 탭 Quick Trade
  bindKimchiEvents();
  bindLongHoldEvents();
  bindManualTradeEvents();
  bindPnlEvents();
  bindPriceGridEvents();
  bindSettingsEvents();
  bindGuardMatrixEvents();
  bindMarketSignalsEvents();  // 2026-02-04: Market Signals Dashboard
  bindReservedSnapshotEvents();
  bindEquitySnapshotEvents();
  
  // New feature bindings
  bindRankingEvents();
  bindKimchiPremiumEvents();
  bindMarketAlertsEvents();
  bindHoldingsUpsideEvents();
  bindAiGateEvents();
  initSparklineControls();
  initPriceChart();
  
  // ============================================================
  // ★ [2026-05-11] 단계별 8초 stagger → 병렬 즉시 로드 (1.44 플로피 탈출)
  //   Phase 1~7 setTimeout 체인 폐기. 모두 Promise 병렬 + 페이지별 데이터는 loadPageData 가 처리.
  //   브라우저는 HTTP/1.1 6 connection / HTTP/2 multiplex 로 알아서 multiplex.
  // ============================================================
  // Critical first paint (block here for system + equity — UI shell 골격 세움)
  await fetchSystemStatus();
  await initEquitySnapshotPopup();

  // Init sortable tables (empty first)
  initSortableTable('active-markets-table', state.managedMarkets, renderMarketsTable);
  ensureMarketDatalist();

  // WS 즉시 연결 (500ms 지연 폐기)
  initWebSocket();
  setInterval(sendWsPing, 30000);

  // Universal background data — 한 번에 병렬 발사 (fire-and-forget)
  Promise.all([
    fetchActiveMarkets(),
    fetchGuards(),
    fetchReserved(),
    loadStrategyGuards(),
    loadKimchiData(),
    fetchAIStats(),
    fetchAITopPick(),
    loadMarketAlerts(),
    loadHoldingsUpside(),
    loadAiGate(),
    loadGlobalGuards(),
    loadDailyPnL(),
    fetchReservedSettings(),
  ].map(p => p && typeof p.catch === 'function' ? p.catch(() => {}) : p)).catch(() => {});

  // ★ 현재 페이지 데이터 즉시 트리거 (FOCUS 포지션 빈칸 방지)
  //   state.currentPage = 'overview' (default) → refreshFocusStatus + fetchActiveMarkets + fetchReserved
  //   사용자가 strategy-focus 등으로 이동 시 sidebar click 핸들러가 loadPageData 재호출
  try { loadPageData(state.currentPage || 'overview'); } catch (_) {}

  // 랭킹은 진짜 무거운 편 — 500ms 후 (다른 API 와 경합 피함)
  setTimeout(() => {
    loadRankings('rebound', API.marketRebound);
    loadReboundRanking();
    loadRsiRanking();
    loadTechScoreRanking();
  }, 500);
  
  // Start auto candidate search countdowns for strategy pages
  // NOTE: startCandidateCountdowns was removed - countdown is now handled per-page
  // setTimeout(() => {
  //   startCandidateCountdowns();
  // }, 3000);
  
  // Auto Sync initialization
  initAutoSync();
  
  // Quick Trade initialization
  initQuickTrade();
  
  // Keyboard shortcuts
  initKeyboardShortcuts();
  
  // Polling - 핵심만 유지, 나머지는 페이지 진입 시 로드
  // WS 연결 중엔 status 폴링 건너뜀 (WS onopen에서 즉시 1회 호출)
  setTimeout(() => setInterval(() => fetchSystemStatus(), 10000), 0); // [2026-05-11] 5→10s (체감 영향 X, 부하 절반)
  setTimeout(() => setInterval(fetchActiveMarkets, 30000), 5000); // 5초 시작, 30초 간격
  setTimeout(() => setInterval(fetchGuards, 60000), 10000);       // 10초 시작, 60초 간격
  // fetchAIStats, loadMarketAlerts, loadHoldingsUpside, loadKimchiData → 해당 페이지 진입 시에만 로드
  
  console.log('Dashboard v2 initialized');
}

