async function saveLadderGuards() {
  const guards = {
    strategy: 'LADDER',
    entry_ob_guard_enabled: qs('lf-guard-ob')?.checked || false,
    entry_ceiling_guard: qs('lf-guard-ceiling')?.checked || false,
    entry_qty_guard: qs('lf-guard-qty')?.checked || false,
    exit_profit_guard: qs('lf-guard-profit')?.checked || false,
    tp_limit_exit_enabled: qs('lf-guard-tp-limit')?.checked || false,
    drawdown_guard: qs('lf-guard-drawdown')?.checked || false,
    min_order_usdt: parseFloat(qs('lf-guard-min-order')?.value) || 5,
    entry_global_gap_sec: parseFloat(qs('lf-guard-entry-gap')?.value) || 0,
    exit_min_net_profit_pct: parseFloat(qs('lf-guard-min-profit-pct')?.value) || 0.5,
    exit_slippage_guard_bps: parseFloat(qs('lf-guard-slippage')?.value) || 50,
  };
  
  try {
    const res = await authFetch('/api/system/guards/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ guards, strategy_override: 'LADDER' })
    });
    if (res.ok) {
      showToast('LADDER Guards 저장 완료!', 'success');
    } else {
      showToast('저장 실패', 'error');
    }
  } catch (e) {
    showToast('저장 오류: ' + e.message, 'error');
  }
}

