function getSniperGuardDefaults() {
  return {
    strategy: 'SNIPER',
    entry_ob_guard_enabled: true,
    time_filter_enabled: false,
    min_order_usdt: 5,
    sniper_cooldown_sec: 300,
    exit_profit_guard: true,
    trail_tp: true,
    trail_dist_pct: 1.5,
    exit_slippage_guard_bps: 30,
    user_sell_only: false,
    deep_sl: false,
    use_limit: true,
    fallback_to_market: false,
  };
}

function applySniperGuardSettings(guards) {
  const g = { ...getSniperGuardDefaults(), ...(guards || {}) };
  setChecked('sn-guard-ob', g.entry_ob_guard_enabled);
  setChecked('sn-guard-time', g.time_filter_enabled);
  setValue('sn-guard-min-order', g.min_order_usdt);
  setValue('sn-guard-cooldown', g.sniper_cooldown_sec);
  setChecked('sn-guard-profit', g.exit_profit_guard);
  setChecked('sn-guard-trail-exit', g.trail_tp);
  setValue('sn-guard-trail-dist', g.trail_dist_pct);
  setValue('sn-guard-slippage', g.exit_slippage_guard_bps);
  setChecked('sn-lock', g.user_sell_only);
  setChecked('sn-deep-sl', g.deep_sl);
  // deploy 영역과 guard 프리셋 동기화
  setChecked('sn-time-filter', g.time_filter_enabled);
  setChecked('sn-trail', g.trail_tp);
  setValue('sn-trail-dist', g.trail_dist_pct);
  setChecked('sn-lmt', g.use_limit);
  setChecked('sn-lmt-fallback', g.fallback_to_market);
}

async function saveSniperGuards(options = {}) {
  const silent = !!options.silent;
  const toFloat = (id, fallback) => {
    const n = parseFloat(qs(id)?.value);
    return Number.isFinite(n) ? n : fallback;
  };
  const toInt = (id, fallback) => {
    const n = parseInt(qs(id)?.value, 10);
    return Number.isFinite(n) ? n : fallback;
  };

  const guards = {
    strategy: 'SNIPER',
    entry_ob_guard_enabled: qs('sn-guard-ob')?.checked || false,
    time_filter_enabled: qs('sn-guard-time')?.checked || false,
    min_order_usdt: toFloat('sn-guard-min-order', 5),
    sniper_cooldown_sec: toInt('sn-guard-cooldown', 300),
    exit_profit_guard: qs('sn-guard-profit')?.checked || false,
    trail_tp: qs('sn-guard-trail-exit')?.checked || false,
    trail_dist_pct: toFloat('sn-guard-trail-dist', 1.5),
    exit_slippage_guard_bps: toFloat('sn-guard-slippage', 30),
    user_sell_only: qs('sn-lock')?.checked || false,
    deep_sl: qs('sn-deep-sl')?.checked || false,
    use_limit: qs('sn-lmt')?.checked || false,
    fallback_to_market: qs('sn-lmt-fallback')?.checked !== false,
  };

  applySniperGuardSettings(guards);

  try {
    const res = await authFetch('/api/system/guards/save', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ guards, strategy_override: 'SNIPER' })
    });
    if (res.ok) {
      if (!silent) showToast('SNIPER Guards 저장 완료!', 'success');
    } else if (!silent) {
      showToast('저장 실패', 'error');
    }
  } catch (e) {
    if (!silent) showToast('저장 오류: ' + e.message, 'error');
  }
}

