// Strategy-level Guard Load Functions
// ============================================================

async function loadStrategyGuards() {
  // Load guards for all strategies at once
  try {
    const res = await authFetch('/api/system/guards/strategies');
    if (!res.ok) return;
    const data = await res.json();
    if (!data.ok) return;
    
    const guards = data.guards || {};
    
    // LADDER Guards
    if (guards.LADDER) {
      const g = guards.LADDER;
      setChecked('lf-guard-ob', g.entry_ob_guard_enabled);
      setChecked('lf-guard-ceiling', g.entry_ceiling_guard);
      setChecked('lf-guard-qty', g.entry_qty_guard);
      setChecked('lf-guard-profit', g.exit_profit_guard);
      setChecked('lf-guard-tp-limit', g.tp_limit_exit_enabled);
      setChecked('lf-guard-drawdown', g.drawdown_guard);
      setValue('lf-guard-min-order', g.min_order_usdt);
      setValue('lf-guard-entry-gap', g.entry_global_gap_sec);
      setValue('lf-guard-min-profit-pct', g.exit_min_net_profit_pct);
      setValue('lf-guard-slippage', g.exit_slippage_guard_bps);
      updateGuardCount('ladder-guards-count', g);
    }
    
    // LIGHTNING Guards
    if (guards.LIGHTNING) {
      const g = guards.LIGHTNING;
      setChecked('ltg-guard-ob', g.entry_ob_guard_enabled);
      setChecked('ltg-guard-ceiling', g.entry_ceiling_guard);
      setChecked('ltg-guard-profit', g.exit_profit_guard);
      setChecked('ltg-guard-drawdown', g.drawdown_guard);
      setValue('ltg-guard-min-order', g.min_order_usdt);
      setValue('ltg-guard-entry-gap', g.entry_global_gap_sec);
      setValue('ltg-guard-min-profit', g.exit_min_net_profit_pct);
      setValue('ltg-guard-slippage', g.exit_slippage_guard_bps);
      updateGuardCount('lightning-guards-count', g);
    }
    
    // GAZUA Guards
    if (guards.GAZUA) {
      const g = guards.GAZUA;
      setChecked('gz-guard-ob', g.entry_ob_guard_enabled);
      setChecked('gz-guard-ceiling', g.entry_ceiling_guard);
      setChecked('gz-guard-ai', g.ai_position_sizing_enabled);
      setChecked('gz-guard-profit', g.exit_profit_guard);
      setChecked('gz-guard-drawdown', g.drawdown_guard);
      setChecked('gz-guard-dynamic-sl', g.dynamic_stoploss_enabled);
      setValue('gz-guard-min-order', g.min_order_usdt);
      setValue('gz-guard-ai-threshold', g.ai_buy_threshold);
      setValue('gz-guard-min-profit', g.exit_min_net_profit_pct);
      setValue('gz-guard-slippage', g.exit_slippage_guard_bps);
      updateGuardCount('gazua-guards-count', g);
    }
    
    // CONTRARIAN Guards
    if (guards.CONTRARIAN) {
      const g = guards.CONTRARIAN;
      setChecked('ct-guard-ob', g.entry_ob_guard_enabled);
      setChecked('ct-guard-rsi-filter', g.contrarian_rsi_filter);
      setChecked('ct-guard-volume', g.contrarian_volume_check);
      setChecked('ct-guard-profit', g.exit_profit_guard);
      setChecked('ct-guard-atr-sl', g.contrarian_atr_sl);
      setChecked('ct-guard-trail', g.contrarian_trail_tp);
      setValue('ct-guard-min-order', g.min_order_usdt);
      setValue('ct-guard-min-score', g.contrarian_min_score);
      setValue('ct-guard-trail-dist', g.contrarian_trail_dist_pct);
      setValue('ct-guard-cooldown', g.contrarian_cooldown_sec);
      updateGuardCount('contrarian-guards-count', g);
    }

    // SNIPER Guards
    const sniperRaw = guards.SNIPER;
    const hasSniperSaved = !!(sniperRaw && Object.keys(sniperRaw).length > 0);
    applySniperGuardSettings(hasSniperSaved ? sniperRaw : getSniperGuardDefaults());
    if (!hasSniperSaved) {
      await saveSniperGuards({ silent: true });
      console.log('SNIPER guard defaults initialized');
    }
    
    console.log('Strategy guards loaded');
  } catch (e) {
    console.error('Failed to load strategy guards:', e);
  }
}

function updateGuardCount(elementId, guards) {
  const el = qs(elementId);
  if (!el) return;
  const count = Object.values(guards).filter(v => v === true).length;
  el.textContent = count;
}

function setChecked(id, value) {
  const el = qs(id);
  if (el) el.checked = Boolean(value);
}

function setValue(id, value) {
  const el = qs(id);
  if (el && value !== undefined && value !== null) el.value = value;
}

