// [2026-03-23] ①② 상호 배타: 체크박스 change 시 상대방 자동 해제
// 서버 측과 동일한 규칙 — 나중에 ON한 쪽 우선
let _smartRiskMEXRegistered = false;
function _initSmartRiskMutualExclusion() {
  if (_smartRiskMEXRegistered) return;
  const dynEl = document.getElementById('chk-dynamic-size-mult');
  const regEl = document.getElementById('chk-regime-per-strategy');
  if (!dynEl || !regEl) return;
  dynEl.addEventListener('change', () => {
    if (dynEl.checked && regEl.checked) {
      regEl.checked = false;
    }
  });
  regEl.addEventListener('change', () => {
    if (regEl.checked && dynEl.checked) {
      dynEl.checked = false;
    }
  });
  _smartRiskMEXRegistered = true;
}

async function loadGlobalGuards() {
  try {
    const res = await authFetch('/api/system/guards');
    if (!res.ok) return;
    const data = await res.json();
    if (!data.ok) return;
    
    const g = data.guards || {};
    
    // Safety Guards
    setChecked('gg-correlation-guard', g.correlation_guard_enabled);
    setChecked('gg-risk-budget', g.risk_budget_enabled);
    setValue('gg-daily-loss-limit', g.daily_loss_limit_pct);
    setValue('gg-circuit-breaker-pct', g.circuit_breaker_loss_pct ?? 10);
    setValue('gg-circuit-breaker-cooldown', g.circuit_breaker_cooldown_min ?? 30);
    setValue('gg-max-same-sector', g.max_same_sector);
    
    // Entry Guards
    setChecked('gg-entry-ob-guard', g.entry_ob_guard_enabled);
    setChecked('gg-entry-ceiling-guard', g.entry_ceiling_guard);
    setChecked('gg-entry-qty-guard', g.entry_qty_guard);
    setValue('gg-min-order', g.min_order_usdt);
    setValue('gg-entry-gap', g.entry_global_gap_sec);
    const bybitSel = qs('gg-bybit-v5-category');
    if (bybitSel) {
      const bc = String(g.bybit_v5_category || 'default').toLowerCase();
      if (bc === 'spot' || bc === 'linear' || bc === 'default') {
        bybitSel.value = bc;
      } else {
        bybitSel.value = 'default';
      }
    }
    
    // Exit Guards
    setChecked('gg-exit-profit-guard', g.exit_profit_guard);
    setChecked('gg-drawdown-guard', g.drawdown_guard);
    setChecked('gg-dynamic-stoploss', g.dynamic_stoploss_enabled);
    setValue('gg-min-profit-pct', g.exit_min_net_profit_pct);
    setValue('gg-slippage-bps', g.exit_slippage_guard_bps);

    // [2026-03-23] 스마트 리스크 ①②③
    setChecked('chk-dynamic-size-mult', g.dynamic_size_mult_enabled ?? true);
    setValue('inp-size-mult-hi', g.size_mult_hi_pct ?? -2.0);
    setValue('inp-size-mult-floor', g.size_mult_floor ?? 0.4);
    setChecked('chk-regime-per-strategy', g.regime_per_strategy_enabled ?? false);
    setChecked('chk-concentration-limit', g.concentration_limit_enabled ?? false);
    setValue('inp-concentration-pct', g.concentration_limit_pct ?? 15.0);
    _initSmartRiskMutualExclusion(); // ①② 상호 배타 이벤트 등록 (1회)

    // Update count
    const count = [
      g.correlation_guard_enabled, g.risk_budget_enabled,
      g.entry_ob_guard_enabled, g.entry_ceiling_guard, g.entry_qty_guard,
      g.exit_profit_guard, g.drawdown_guard, g.dynamic_stoploss_enabled,
      g.dynamic_size_mult_enabled, g.concentration_limit_enabled
    ].filter(Boolean).length;
    const countEl = qs('global-guards-count');
    if (countEl) countEl.textContent = count;
    
    console.log('Global guards loaded');
  } catch (e) {
    console.error('Failed to load global guards:', e);
  }
}

