async function loadDailyPnL() {
  const tbody = qs('daily-pnl-body');
  if (!tbody) return;
  
  try {
    const [todayRes, summaryRes] = await Promise.all([
      authFetch('/api/system/daily-pnl/today').then(r => r.json()),
      authFetch('/api/system/daily-pnl/summary?days=7').then(r => r.json())
    ]);
    
    let rows = [];
    
    // 오늘 데이터
    if (todayRes.ok && todayRes.report) {
      const r = todayRes.report;
      rows.push({
        date: r.date,
        pnl: r.total_pnl_usdt || 0,
        trades: r.total_trades || 0,
        winRate: r.win_rate || 0,
        isToday: true
      });
    }
    
    // 과거 데이터
    if (summaryRes.ok && summaryRes.daily) {
      const today = new Date().toISOString().slice(0, 10);
      summaryRes.daily.forEach(d => {
        if (d.date !== today) {
          rows.push({
            date: d.date,
            pnl: d.pnl_usdt || 0,
            trades: d.trades || 0,
            winRate: d.win_rate || 0,
            isToday: false
          });
        }
      });
    }
    
    rows.sort((a, b) => b.date.localeCompare(a.date));
    
    if (rows.length === 0) {
      tbody.innerHTML = `<tr><td colspan="4" class="text-center text-muted">${t('empty.no_data', 'No data')}</td></tr>`;
      return;
    }
    
    tbody.innerHTML = rows.map(r => {
      const pnlClass = r.pnl >= 0 ? 'text-success' : 'text-danger';
      const pnlSign = r.pnl >= 0 ? '+' : '';
      const winPct = (r.winRate * 100).toFixed(0);
      const dateLabel = r.isToday ? `<strong>${r.date}</strong> <span class="badge bg-blue-lt">${t('status.today', 'Today')}</span>` : r.date;
      return `
        <tr>
          <td>${dateLabel}</td>
          <td class="text-end ${pnlClass} fw-bold">${pnlSign}${r.pnl.toLocaleString()}</td>
          <td class="text-center">${r.trades}</td>
          <td class="text-center">${winPct}%</td>
        </tr>
      `;
    }).join('');
  } catch (e) {
    tbody.innerHTML = `<tr><td colspan="4" class="text-center text-danger">${t('label.error', 'Error')}: ${e.message}</td></tr>`;
  }
}

