// ============================================================
// LADDER Circuit Breaker
// ============================================================

async function loadCircuitBreakerStatus() {
  try {
    const res = await authFetch('/api/ladder/grid/circuit-breaker');
    if (!res.ok) return;
    const d = await res.json();
    const badge = qs('cb-status-badge');
    const avgEl = qs('cb-avg-down');
    const cntEl = qs('cb-market-count');
    const chk = qs('cb-enabled');
    const thEl = qs('cb-threshold');
    const detailEl = qs('cb-detail');
    const listEl = qs('cb-market-list');

    if (chk) chk.checked = !!d.enabled;
    if (thEl) thEl.value = d.threshold || 2.0;
    if (avgEl) avgEl.textContent = (d.avg_consecutive_down_buys || 0).toFixed(2);
    if (cntEl) cntEl.textContent = d.market_count || 0;

    if (badge) {
      if (d.tripped) {
        badge.textContent = 'TRIPPED';
        badge.className = 'badge ms-1 bg-danger';
      } else if (d.enabled) {
        badge.textContent = 'ARMED';
        badge.className = 'badge ms-1 bg-success';
      } else {
        badge.textContent = 'OFF';
        badge.className = 'badge ms-1 bg-secondary';
      }
    }

    if (detailEl && listEl && d.markets) {
      const entries = Object.entries(d.markets);
      if (entries.length > 0) {
        detailEl.style.display = '';
        listEl.innerHTML = entries.map(([m, v]) =>
          `<span class="me-2">${m.replace(/USDT$/i,'')}:<strong class="${v >= (d.threshold||2) ? 'text-danger' : ''}">${v}</strong></span>`
        ).join('');
      } else {
        detailEl.style.display = 'none';
      }
    }
  } catch (e) {
    console.warn('CB status error:', e);
  }
}

async function toggleCircuitBreaker(enabled) {
  try {
    const res = await authFetch(`/api/ladder/grid/circuit-breaker/toggle?enabled=${enabled}`, { method: 'POST' });
    if (res.ok) {
      showToast(`Circuit Breaker ${enabled ? 'ON' : 'OFF'}`, 'success');
      loadCircuitBreakerStatus();
    }
  } catch (e) {
    showToast('CB toggle error: ' + e.message, 'error');
  }
}

async function setCircuitBreakerThreshold(val) {
  const th = parseFloat(val);
  if (!th || th < 1) return;
  try {
    const res = await authFetch(`/api/ladder/grid/circuit-breaker/threshold?threshold=${th}`, { method: 'POST' });
    if (res.ok) {
      showToast(`CB Threshold → ${th}`, 'success');
      loadCircuitBreakerStatus();
    }
  } catch (e) {
    showToast('CB threshold error: ' + e.message, 'error');
  }
}

window.toggleCircuitBreaker = toggleCircuitBreaker;
window.setCircuitBreakerThreshold = setCircuitBreakerThreshold;
window.loadCircuitBreakerStatus = loadCircuitBreakerStatus;

// ============================================================
// Auto Sync (Periodic Reconcile)
// ============================================================

const LS_AUTO_SYNC = 'autocoin_auto_sync_v1';
let autoSyncTimer = null;
let autoSyncInFlight = false;

function syncLegacyAutoSyncToggle(enabled) {
  const legacyToggle = qs('chk-auto-sync');
  if (legacyToggle) legacyToggle.checked = !!enabled;
}

function loadAutoSyncState() {
  try {
    const saved = localStorage.getItem(LS_AUTO_SYNC);
    let enabled = false;
    let intervalSec = 10;
    if (saved) {
      const state = JSON.parse(saved) || {};
      const toggle = qs('auto-sync-toggle');
      const interval = qs('auto-sync-interval');
      enabled = !!state.enabled;
      intervalSec = parseInt(state.interval) || 10;
      if (toggle) toggle.checked = enabled;
      if (interval) interval.value = intervalSec;
    }
    syncLegacyAutoSyncToggle(enabled);
  } catch (e) {}
}

function saveAutoSyncState() {
  try {
    const toggle = qs('auto-sync-toggle');
    const legacyToggle = qs('chk-auto-sync');
    const interval = qs('auto-sync-interval');
    const enabled = !!(toggle?.checked ?? legacyToggle?.checked);
    const intervalSec = parseInt(interval?.value) || 10;
    localStorage.setItem(LS_AUTO_SYNC, JSON.stringify({
      enabled,
      interval: intervalSec
    }));
  } catch (e) {}
}

async function runAutoSyncOnce() {
  if (autoSyncInFlight) return;
  autoSyncInFlight = true;
  try {
    await authFetch('/api/system/reconcile', { method: 'POST' });
    console.log('Auto sync completed');
  } catch (e) {
    console.error('Auto sync failed:', e);
  } finally {
    autoSyncInFlight = false;
  }
}

function startAutoSync() {
  stopAutoSync();
  const interval = parseInt(qs('auto-sync-interval')?.value) || 10;
  const sec = Math.max(5, Math.min(60, interval));
  
  runAutoSyncOnce();
  autoSyncTimer = setInterval(() => {
    const enabled = !!(qs('auto-sync-toggle')?.checked ?? qs('chk-auto-sync')?.checked);
    if (enabled) {
      runAutoSyncOnce();
    }
  }, sec * 1000);
  
  showToast(`Auto Sync ON (${sec}초)`, 'success');
  saveAutoSyncState();
}

function stopAutoSync() {
  if (autoSyncTimer) {
    clearInterval(autoSyncTimer);
    autoSyncTimer = null;
  }
}

function toggleAutoSync() {
  const toggle = qs('auto-sync-toggle');
  const legacyToggle = qs('chk-auto-sync');
  const enabled = !!(toggle?.checked ?? legacyToggle?.checked);
  syncLegacyAutoSyncToggle(enabled);
  if (enabled) {
    startAutoSync();
  } else {
    stopAutoSync();
    showToast('Auto Sync OFF', 'info');
    saveAutoSyncState();
  }
}

function initAutoSync() {
  loadAutoSyncState();
  
  const toggle = qs('auto-sync-toggle');
  const legacyToggle = qs('chk-auto-sync');
  const interval = qs('auto-sync-interval');
  
  if (toggle) {
    toggle.addEventListener('change', toggleAutoSync);
    if (toggle.checked) startAutoSync();
  }

  if (legacyToggle) {
    legacyToggle.addEventListener('change', (e) => {
      if (toggle) toggle.checked = !!e.target?.checked;
      toggleAutoSync();
    });
    if (!toggle && legacyToggle.checked) startAutoSync();
  }
  
  if (interval) {
    interval.addEventListener('change', () => {
      saveAutoSyncState();
      const enabled = !!(qs('auto-sync-toggle')?.checked ?? qs('chk-auto-sync')?.checked);
      if (enabled) startAutoSync();
    });
  }
  
  // [2026-02-02] Auto Engine Start toggle
  initAutoEngineStart();
}

// [2026-02-02] Auto Engine Start on Boot
async function initAutoEngineStart() {
  const toggle = qs('auto-engine-start-toggle');
  if (!toggle) return;
  
  // Load current state from server
  try {
    const res = await authFetch(API.reservedSettings);
    const data = await res.json();
    if (data.ok && data.settings && data.settings.autopilot) {
      toggle.checked = !!data.settings.autopilot.auto_engine_start;
    }
  } catch (err) {
    console.error('Auto Engine Start 상태 로드 실패:', err);
  }
  
  // Toggle handler
  toggle.addEventListener('change', async () => {
    try {
      const params = new URLSearchParams();
      params.set('auto_engine_start', toggle.checked ? 'true' : 'false');
      const res = await authFetch(`${API.reservedSettings}?${params.toString()}`, { method: 'POST' });
      const data = await res.json();
      if (data.ok) {
        showToast(`Auto Engine Start ${toggle.checked ? 'ON' : 'OFF'}`, 'success');
      } else {
        showToast('설정 저장 실패', 'error');
        toggle.checked = !toggle.checked; // revert
      }
    } catch (err) {
      showToast('설정 저장 오류', 'error');
      toggle.checked = !toggle.checked; // revert
    }
  });
}

// ============================================================
// Quick Trade Panel
// ============================================================

function initQuickTrade() {
  const marketInput = qs('quick-market');
  const modeRadios = document.querySelectorAll('input[name="quick-mode"]');
  
  if (marketInput) {
    marketInput.addEventListener('input', updateQuickPrice);
  }
  
  modeRadios.forEach(r => {
    r.addEventListener('change', () => {
      const condOpts = qs('quick-cond-opts');
      if (condOpts) condOpts.style.display = r.value === 'cond' && r.checked ? 'block' : 'none';
      updateQuickCondEstimate();
    });
  });
  
  // 조건부 타입 변경 핸들러
  qs('quick-cond-type')?.addEventListener('change', () => {
    const condType = qs('quick-cond-type')?.value || 'price';
    const priceOpts = qs('quick-cond-price-opts');
    const rangeOpts = qs('quick-cond-range-opts');
    
    if (condType === 'price') {
      if (priceOpts) priceOpts.style.display = 'flex';
      if (rangeOpts) rangeOpts.style.display = 'none';
    } else {
      if (priceOpts) priceOpts.style.display = 'none';
      if (rangeOpts) rangeOpts.style.display = 'flex';
    }
    updateQuickCondHint();
  });
  
  // 범위 조건 파라미터 변경 핸들러
  ['quick-cond-lookback', 'quick-cond-threshold', 'quick-cond-expiry'].forEach(id => {
    qs(id)?.addEventListener('input', updateQuickCondHint);
  });
  
  qs('quick-amount')?.addEventListener('input', updateQuickCondEstimate);
  qs('quick-cond-price')?.addEventListener('input', updateQuickCondEstimate);
  qs('quick-cond-dir')?.addEventListener('change', updateQuickCondEstimate);
  
  loadQuickPending();
}

function updateQuickCondHint() {
  const hintEl = qs('quick-cond-hint');
  if (!hintEl) return;
  
  const condType = qs('quick-cond-type')?.value || 'price';
  const lookback = parseInt(qs('quick-cond-lookback')?.value) || 15;
  const threshold = parseFloat(qs('quick-cond-threshold')?.value) || 0.3;
  const expiry = parseInt(qs('quick-cond-expiry')?.value) || 30;
  
  if (condType === 'near_low') {
    hintEl.textContent = tf('hint.quick_near_low', 'Buy when near low within {lookback}m ±{threshold}% (valid {expiry}m)', {
      lookback, threshold, expiry
    });
  } else if (condType === 'near_high') {
    hintEl.textContent = tf('hint.quick_near_high', 'Sell when near high within {lookback}m ±{threshold}% (valid {expiry}m)', {
      lookback, threshold, expiry
    });
  }
}

function updateQuickPrice() {
  const market = qs('quick-market')?.value?.trim().toUpperCase() || '';
  const priceEl = qs('quick-price');
  if (!priceEl) return;
  
  let price = state.prices?.[market] || state.prices?.[`${market}USDT`];
  if (typeof price === 'object') price = price.price;
  priceEl.textContent = price ? `$${price.toLocaleString()}` : '—';
  
  updateQuickCondEstimate();
}

function updateQuickCondEstimate() {
  const hintEl = qs('quick-cond-hint');
  if (!hintEl) return;
  
  const marketRaw = qs('quick-market')?.value?.trim().toUpperCase() || '';
  const market = marketRaw.endsWith('USDT') ? marketRaw : `${marketRaw}USDT`;
  const amount = parseFloat(qs('quick-amount')?.value) || 0;
  const targetPrice = parseFloat(qs('quick-cond-price')?.value) || 0;
  const dir = qs('quick-cond-dir')?.value || 'above';
  
  let currentPrice = state.prices?.[market] || state.prices?.[marketRaw];
  if (typeof currentPrice === 'object') currentPrice = currentPrice.price;
  
  if (!marketRaw || !targetPrice || !currentPrice) {
    hintEl.textContent = '';
    return;
  }
  
  const diff = targetPrice - currentPrice;
  const diffPct = (diff / currentPrice) * 100;
  const direction = dir === 'above' ? t('label.above_or_equal', 'above') : t('label.below_or_equal', 'below');
  
  const estQty = amount / targetPrice;
  const pctStr = diffPct >= 0 ? `+${diffPct.toFixed(2)}%` : `${diffPct.toFixed(2)}%`;
  
  hintEl.textContent = tf('hint.quick_target_estimate', 'Target: ${price} {direction} ({pct}) · Est Qty: {qty}', {
    price: targetPrice.toLocaleString(),
    direction,
    pct: pctStr,
    qty: estQty.toFixed(6)
  });
}

async function quickBuy() {
  await executeQuickTradeLegacy('buy');
}

async function quickSell() {
  await executeQuickTradeLegacy('sell');
}

async function quickSellAll() {
  const market = qs('quick-market')?.value?.trim().toUpperCase();
  if (!market) return showQuickMsg(t('error.enter_market', 'Please enter a market'), false);

  if (!confirm(tf('confirm.quick_sell_all_market', 'Sell all on {market}?', { market }))) return;

  try {
    const res = await authFetch('/api/trade/manual', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ market: market.endsWith('USDT') ? market : `${market}USDT`, side: 'sell', mode: 'all', value: 100 })
    });
    const data = await res.json();
    showQuickMsg(data.ok ? t('status.quick_sell_all_done', 'Sell all completed') : (data.error || t('status.failed', 'Failed')), data.ok);
  } catch (e) {
    showQuickMsg(`${t('label.error', 'Error')}: ${e.message}`, false);
  }
}

async function executeQuickTradeLegacy(side) {
  const marketRaw = qs('quick-market')?.value?.trim().toUpperCase();
  if (!marketRaw) return showQuickMsg(t('error.enter_market', 'Please enter a market'), false);
  
  const market = marketRaw.endsWith('USDT') ? marketRaw : `${marketRaw}USDT`;
  const amount = parseFloat(qs('quick-amount')?.value) || 10;
  const isCond = document.querySelector('input[name="quick-mode"]:checked')?.value === 'cond';
  
  if (isCond) {
    const condType = qs('quick-cond-type')?.value || 'price';
    
    if (condType === 'price') {
      // 지정가 조건부
      const dir = qs('quick-cond-dir')?.value || 'above';
      const targetPrice = parseFloat(qs('quick-cond-price')?.value);
      if (!targetPrice) return showQuickMsg(t('error.enter_target_price', 'Please enter target price'), false);
      
      try {
        const res = await authFetch('/api/trade/quick/conditional', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ market, side, amount_usdt: amount, condition: dir, target_price: targetPrice })
        });
        const data = await res.json();
        showQuickMsg(data.ok ? t('status.quick_conditional_registered', 'Conditional order registered') : (data.error || t('status.failed', 'Failed')), data.ok);
        if (data.ok) loadQuickPending();
      } catch (e) {
        showQuickMsg(`${t('label.error', 'Error')}: ${e.message}`, false);
      }
    } else {
      // 최저가/최고가 조건부 (near_low, near_high)
      const lookback = parseInt(qs('quick-cond-lookback')?.value) || 15;
      const threshold = parseFloat(qs('quick-cond-threshold')?.value) || 0.3;
      const expiry = parseInt(qs('quick-cond-expiry')?.value) || 30;
      
      // near_low → 매수, near_high → 매도
      const actualSide = condType === 'near_low' ? 'buy' : 'sell';
      
      try {
        const res = await authFetch('/api/trade/quick/conditional', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            market,
            side: actualSide,
            amount_usdt: amount,
            condition: condType,
            lookback_minutes: lookback,
            threshold_pct: threshold,
            expiry_minutes: expiry
          })
        });
        const data = await res.json();
        const label = condType === 'near_low' ? t('sniper.entry_low_buy', 'Snipe Buy Near Low') : t('sniper.exit_high_sell', 'Snipe Sell Near High');
        showQuickMsg(data.ok ? tf('status.quick_order_registered', '{label} order registered', { label }) : (data.error || t('status.failed', 'Failed')), data.ok);
        if (data.ok) loadQuickPending();
      } catch (e) {
        showQuickMsg(`${t('label.error', 'Error')}: ${e.message}`, false);
      }
    }
  } else {
    try {
      const res = await authFetch('/api/trade/manual', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ market, side, mode: 'usdt', value: amount })
      });
      const data = await res.json();
      showQuickMsg(data.ok ? tf('status.side_completed', '{side} completed', { side: side.toUpperCase() }) : (data.error || t('status.failed', 'Failed')), data.ok);
    } catch (e) {
      showQuickMsg(`${t('label.error', 'Error')}: ${e.message}`, false);
    }
  }
}

async function loadQuickPending() {
  const section = qs('quick-pending');
  const list = qs('quick-pending-list');
  if (!section || !list) return;
  
  try {
    const res = await authFetch('/api/trade/quick/pending/list');
    const data = await res.json();
    
    if (!data.ok || !data.orders?.length) {
      section.style.display = 'none';
      return;
    }
    
    section.style.display = 'block';
    list.innerHTML = data.orders.map(o => `
      <div class="d-flex justify-content-between align-items-center mb-1">
        <span>${o.market} ${o.side} ${o.condition} $${o.target_price?.toLocaleString()}</span>
        <button class="btn btn-ghost-danger btn-sm p-0" onclick="cancelQuickOrder('${o.id}')"><i class="ti ti-x"></i></button>
      </div>
    `).join('');
  } catch (e) {
    section.style.display = 'none';
  }
}

async function cancelQuickOrder(id) {
  try {
    await authFetch(`/api/trade/quick/pending/${id}`, { method: 'DELETE' });
    loadQuickPending();
  } catch (e) {}
}

function showQuickMsg(msg, ok) {
  const el = qs('quick-msg');
  if (el) {
    el.textContent = msg;
    el.className = `small mt-2 ${ok ? 'text-success' : 'text-danger'}`;
    setTimeout(() => { el.textContent = ''; }, 3000);
  }
}

// ============================================================
// Keyboard Shortcuts
// ============================================================

function initKeyboardShortcuts() {
  document.addEventListener('keydown', handleKeyboardShortcut);
}

function handleKeyboardShortcut(e) {
  // 입력 필드에서는 단축키 비활성화
  const tag = e.target.tagName;
  const isEditable = e.target.isContentEditable;
  if (['INPUT', 'TEXTAREA', 'SELECT'].includes(tag) || isEditable) return;
  
  const key = e.key.toLowerCase();
  const ctrl = e.ctrlKey || e.metaKey;
  const shift = e.shiftKey;
  
  // Ctrl+R or just R: Refresh (새로고침)
  if (key === 'r' && !ctrl) {
    e.preventDefault();
    fetchSystemStatus();
    fetchActiveMarkets();
    showToast(t('action.refresh', 'Refresh'), 'info');
    return;
  }
  
  // E: Emergency Stop 토글
  if (key === 'e' && !ctrl) {
    e.preventDefault();
    if (confirm(t('confirm.toggle_emergency', 'Do you want to toggle emergency state?'))) {
      toggleEmergency();
    }
    return;
  }
  
  // 1-9: 페이지 전환
  if (/^[1-9]$/.test(key) && !ctrl) {
    e.preventDefault();
    const pages = ['overview', 'pingpong', 'autoloop', 'ladder', 'lightning', 'gazua', 'contrarian', 'market-active', 'settings'];
    const idx = parseInt(key) - 1;
    if (pages[idx]) showPage(pages[idx]);
    return;
  }
  
  // Escape: 모달 닫기 (기본 동작)
  
  // ?: 단축키 도움말
  if (key === '?' || (key === '/' && shift)) {
    e.preventDefault();
    showShortcutHelp();
    return;
  }
  
  // Ctrl+S: Guards 저장
  if (key === 's' && ctrl) {
    e.preventDefault();
    saveGlobalGuards();
    return;
  }
}

function showShortcutHelp() {
  const shortcuts = `
    <div class="list-group list-group-flush">
      <div class="list-group-item d-flex justify-content-between"><kbd>R</kbd><span>${t('action.refresh', 'Refresh')}</span></div>
      <div class="list-group-item d-flex justify-content-between"><kbd>E</kbd><span>${t('label.emergency_toggle', 'Emergency toggle')}</span></div>
      <div class="list-group-item d-flex justify-content-between"><kbd>1-9</kbd><span>${t('label.page_switch', 'Switch page')}</span></div>
      <div class="list-group-item d-flex justify-content-between"><kbd>Ctrl+S</kbd><span>${t('label.save_guards', 'Save guards')}</span></div>
      <div class="list-group-item d-flex justify-content-between"><kbd>?</kbd><span>${t('label.this_help', 'This help')}</span></div>
    </div>
  `;
  
  // Bootstrap 모달 또는 Toast로 표시
  showToast(t('status.shortcut_help', 'Shortcuts: R(Refresh) E(Emergency) 1-9(Pages) ?(Help)'), 'info');
}

// ============================================================
// Table Sorting
// ============================================================

const sortState = {};

function initSortableTable(tableId, data, renderFn) {
  sortState[tableId] = { column: null, direction: 'asc', data };
  
  const table = document.getElementById(tableId);
  if (!table) return;
  
  table.querySelectorAll('th[data-sort]').forEach(th => {
    th.style.cursor = 'pointer';
    th.classList.add('sortable');
    
    th.addEventListener('click', () => {
      const column = th.dataset.sort;
      const st = sortState[tableId];
      
      if (st.column === column) {
        st.direction = st.direction === 'asc' ? 'desc' : 'asc';
      } else {
        st.column = column;
        st.direction = 'asc';
      }
      
      table.querySelectorAll('th[data-sort]').forEach(h => {
        h.classList.remove('sort-asc', 'sort-desc');
      });
      th.classList.add(`sort-${st.direction}`);
      
      const sorted = sortData(st.data, column, st.direction);
      renderFn(sorted);
    });
  });
}

function sortData(data, column, direction) {
  return [...data].sort((a, b) => {
    let aVal = a[column];
    let bVal = b[column];
    
    if (typeof aVal === 'number' && typeof bVal === 'number') {
      return direction === 'asc' ? aVal - bVal : bVal - aVal;
    }
    
    aVal = String(aVal || '').toLowerCase();
    bVal = String(bVal || '').toLowerCase();
    
    if (direction === 'asc') {
      return aVal.localeCompare(bVal);
    } else {
      return bVal.localeCompare(aVal);
    }
  });
}

function updateSortableTableData(tableId, data) {
  if (sortState[tableId]) {
    sortState[tableId].data = data;
  }
}

