// Guard Matrix
// ============================================================

// Guard lamp state tracking for animation
if (!window._guardPrev) window._guardPrev = {};

async function fetchGuardMatrix() {
  try {
    // 2026-01-30: API 호출 최적화 - 필수 2개만 병렬 호출
    const [guardsRes, marketsRes] = await Promise.all([
      authFetch(API.systemGuards),
      authFetch(API.managerMarkets)
    ]);
    const guardsData = await guardsRes.json();
    const marketsData = await marketsRes.json();
    
    state.guards = guardsData;
    
    // [2026-03-01] Guard Matrix scope: ACTIVE/RECOVERY only
    const activeList = (marketsData.active || []).map(m => ({ ...m, state: 'ACTIVE' }));
    const recoveryList = (marketsData.recovery || []).map(m => ({ ...m, state: 'RECOVERY' }));
    let markets = [...activeList, ...recoveryList];
    
    // coordinator 정보에서 전략 정보 추출 (추가 API 호출 없이)
    const coord = (guardsData && guardsData.coordinator) ? guardsData.coordinator : {};
    window._guardCoord = coord;
    
    // coordinator에서 전략 정보 병합
    markets.forEach(m => {
      const marketKey = m.market || m.code || m.symbol;
      const c = coord[marketKey];
      if (c) {
        const strat = c.strategy || (c.controls && c.controls.strategy && c.controls.strategy.mode);
        if (strat && strat !== 'OFF') {
          m.strategy = strat;
        }
        // state가 없으면 coordinator에서 가져오기
        if (!m.state && c.market_state) {
          m.state = c.market_state.toUpperCase();
        }
      }
    });
    
    // 렌더링
    renderGuardGlobalControls(guardsData);
    renderGuardSmartAllocation(guardsData);
    renderGuardMarketSelect(markets);
    renderGuardGrid(guardsData, markets);
    
    // Apply 버튼 바인딩
    const applyBtn = qs('btn-apply-guards');
    if (applyBtn) {
      applyBtn.onclick = applyGuardSettings;
    }
  } catch (err) {
    console.error('Guard Matrix 조회 실패:', err);
  }
}

