async function applyMarketOverrides(market) {
  const box = qs('guardMarketOverrides');
  if (!box) return;
  
  const overrides = {};
  box.querySelectorAll('[data-ov]').forEach(el => {
    const key = el.dataset.ov;
    if (el.type === 'checkbox') {
      overrides[key] = el.checked;
    } else if (el.type === 'number' && el.value) {
      overrides[key] = parseFloat(el.value);
    }
  });
  
  try {
    const res = await authFetch(`/api/coordinator/context/${encodeURIComponent(market)}/guards`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(overrides)
    });
    const data = await res.json();
    if (data.ok) {
      showToast(tf('status.guard_apply_done', '{market} guard settings applied', { market }), 'success');
    } else {
      showToast(tf('status.guard_apply_failed', 'Apply failed: {error}', { error: data.error || 'Unknown' }), 'error');
    }
  } catch (err) {
    showToast(`${t('label.error', 'Error')}: ${err.message}`, 'error');
  }
}

async function resetMarketOverrides(market) {
  if (!confirm(tf('confirm.reset_market_guards', 'Reset guard settings for {market}?', { market }))) return;
  
  try {
    const res = await authFetch(`/api/coordinator/context/${encodeURIComponent(market)}/guards/reset`, { method: 'POST' });
    const data = await res.json();
    if (data.ok) {
      showToast(tf('status.guard_reset_done', '{market} guard settings reset', { market }), 'success');
      await fetchGuardMatrix();
    } else {
      showToast(tf('status.guard_reset_failed', 'Reset failed: {error}', { error: data.error || 'Unknown' }), 'error');
    }
  } catch (err) {
    showToast(`${t('label.error', 'Error')}: ${err.message}`, 'error');
  }
}

