  setNum('entry_recent_high_lookback_hours', 'g_entry_recent_high_lookback_hours');
  setNum('entry_recent_high_near_pct', 'g_entry_recent_high_near_pct');
  setNum('entry_recent_high_cooldown_sec', 'g_entry_recent_high_cooldown_sec');
  setNum('entry_recent_high_candle_unit_min', 'g_entry_recent_high_candle_unit_min');
