// [2026-02-02] Guard Matrix pagination state
if (!window._guardPage) window._guardPage = { page: 1, size: 12 };

function renderGuardGrid(guardsData, markets) {
  const box = qs('guardGrid');
  if (!box) return;
  
  box.innerHTML = '';
  
  const g = (guardsData && guardsData.guards) ? guardsData.guards : {};
  const safety = (guardsData && guardsData.safety) ? guardsData.safety : {};
  const coord = (guardsData && guardsData.coordinator) ? guardsData.coordinator : {};
  
  // Filter to ACTIVE/RECOVERY markets only
  const allActiveMarkets = markets
    .filter((m) => {
      const st = String(m.state || '').toUpperCase();
      return st === 'ACTIVE' || st === 'RECOVERY';
    })
    .map(m => m.market);
  
  const countEl = qs('guard-market-count');
  if (countEl) countEl.textContent = `${allActiveMarkets.length} markets`;
  
  if (allActiveMarkets.length === 0) {
    box.innerHTML = '<div class="text-muted text-center py-4">No active markets</div>';
    const paginationEl = qs('guard-pagination');
    if (paginationEl) paginationEl.style.display = 'none';
    return;
  }
  
  // [2026-02-02] Pagination logic
  const pageSize = window._guardPage.size || 12;
  const totalItems = allActiveMarkets.length;
  const totalPages = pageSize > 0 ? Math.ceil(totalItems / pageSize) : 1;
  let currentPage = Math.min(window._guardPage.page || 1, totalPages);
  window._guardPage.page = currentPage;
  
  let activeMarkets;
  if (pageSize > 0) {
    const startIdx = (currentPage - 1) * pageSize;
    const endIdx = startIdx + pageSize;
    activeMarkets = allActiveMarkets.slice(startIdx, endIdx);
  } else {
    activeMarkets = allActiveMarkets; // All
  }
  
  // Render pagination controls
  const paginationEl = qs('guard-pagination');
  if (paginationEl) {
    if (pageSize > 0 && totalPages > 1) {
      paginationEl.style.display = 'flex';
      const startNum = (currentPage - 1) * pageSize + 1;
      const endNum = Math.min(currentPage * pageSize, totalItems);
      const infoEl = qs('guard-page-info');
      if (infoEl) infoEl.textContent = `${startNum}-${endNum} of ${totalItems}`;
      
      const btnsEl = qs('guard-page-btns');
      if (btnsEl) {
        btnsEl.innerHTML = '';
        for (let p = 1; p <= totalPages; p++) {
          const btn = document.createElement('button');
          btn.className = 'btn btn-outline-secondary' + (p === currentPage ? ' active' : '');
          btn.textContent = p;
          btn.onclick = () => {
            window._guardPage.page = p;
            renderGuardGrid(window._lastGuardData, window._lastGuardMarkets);
          };
          btnsEl.appendChild(btn);
        }
      }
    } else {
      paginationEl.style.display = 'none';
    }
  }
  
  // Store for re-render
  window._lastGuardData = guardsData;
  window._lastGuardMarkets = markets;
  
  const globalCdRemain = Number((safety.global_entry_cooldown && safety.global_entry_cooldown.remaining_sec) || 0);
  const pendingTotal = Number((safety.order_pressure && safety.order_pressure.pending_orders_total) || 0);
  const maxPending = Number((safety.order_pressure && safety.order_pressure.max_pending_orders_total) || 0);
  
  const coolRemainSec = (ts) => {
    if (!ts) return 0;
    const remain = (ts - Date.now()) / 1000;
    return remain > 0 ? remain : 0;
  };
  
  const mkLampBox = (market, row, key, baseState, title, isCause = false) => {
    const fullKey = `${market}:${row}:${key}`;
    const prev = window._guardPrev[fullKey];
    
    let drawState = baseState;
    if (prev && prev !== baseState) {
      if (baseState === 'pass') drawState = 'just-pass';
      if (baseState === 'block') drawState = 'just-block';
    }
    window._guardPrev[fullKey] = baseState;
    
    const wrap = document.createElement('div');
    wrap.className = 'lampbox';
    wrap.title = title || key;
    
    const lamp = document.createElement('span');
    lamp.className = `guard-lamp ${drawState}`;
    if (isCause) lamp.classList.add('cause');
    
    const lab = document.createElement('span');
    lab.className = 'lamp-label';
    lab.textContent = key;
    
    wrap.appendChild(lamp);
    wrap.appendChild(lab);
    return wrap;
  };
  
  const mapEntryCause = (entryState, entryReason) => {
    if (String(entryState || '').toUpperCase() !== 'BLOCKED') return '';
    const r = String(entryReason || '').toLowerCase();
    if (r.includes('emergency_stop')) return 'EMR';
    if (r.includes('recovery')) return 'REC';
    if (r.includes('entry_disabled')) return 'EN';
    if (r.includes('manual_mode')) return 'MAN';  // [2026-02-02] 수동 모드
    if (r.includes('order_pending')) return 'PND';
    if (r.includes('global_cooldown')) return 'GCD';
    if (r.includes('max_pending')) return 'MAXP';
    if (r.includes('entry_global_gap')) return 'GAP';
    if (r.includes('entry_cooldown')) return 'LCD';
    if (r.includes('min_order')) return 'MIN';
    if (r.includes('already_in_position')) return 'POS';
    if (r.includes('ceiling')) return 'CEIL';
    if (r.includes('recent_high')) return 'RHI';
    if (r.includes('qty')) return 'QTY';
    if (r.includes('orderbook')) return 'OB';
    if (r.includes('entry_limit') || r.includes('limit_unfilled')) return 'LMT';
    return 'BUY';
  };
  
  const mapExitCause = (exitState, exitReason) => {
    if (String(exitState || '').toUpperCase() !== 'BLOCKED') return '';
    const r = String(exitReason || '').toLowerCase();
    if (r.includes('manual_mode')) return 'MAN';      // [2026-02-02] 수동 모드
    if (r.includes('longhold')) return 'LH';          // [2026-02-02] LongHold 보호
    if (r.includes('warmup')) return 'WRM';           // [2026-02-02] 워밍업 보호
    if (r.includes('order_pending')) return 'PND';
    if (r.includes('exit_cooldown')) return 'XCD';
    if (r.includes('dust')) return 'DST';             // [2026-02-02] Dust 쿨다운
    if (r.includes('no_position')) return 'NCP';
    if (r.includes('profit_guard')) return 'PFT';
    if (r.includes('entry_limit') || r.includes('limit_unfilled')) return 'LMT';
    return 'SELL';
  };
  
  const stratColors = {
    'LADDER': '#f5a623',
    'LIGHTNING': '#4fc3f7',
    'GAZUA': '#66bb6a',
    'PINGPONG': '#9fa8da',
    'AUTOLOOP': '#ef9a9a',
    'CONTRARIAN': '#ce93d8',
    'AI': '#888',
    'OFF': '#555'
  };
  
  // [2026-02-02] Helper functions for strategy meta display
  const fmtNum = (v, d = 2) => (v != null && !isNaN(v)) ? Number(v).toFixed(d) : '-';
  const fmtPrice = (v) => (v != null && !isNaN(v) && v > 0) ? Number(v).toLocaleString('ko-KR', {maximumFractionDigits: 0}) : '-';
  const nVal = (v) => (v != null && !isNaN(v)) ? Number(v) : null;
  
  // [2026-02-02] Get strategy-specific meta info string
  const getStrategyMetaInfo = (strat, meta, c) => {
    if (!meta || typeof meta !== 'object') return '';
    const levels = meta.levels || {};
    const telemetry = meta.telemetry || {};
    const aiPred = nVal(c.ai_prediction);
    const aiStr = aiPred !== null ? `AI:${fmtNum(aiPred * 100, 0)}%` : '';
    
    switch (strat) {
      case 'PINGPONG': {
        const anchor = nVal(levels.anchor_price || meta.anchor_price);
        const buyP = nVal(levels.buy_price || meta.buy_price);
        const sellP = nVal(levels.sell_price || meta.sell_price);
        let parts = [];
        if (anchor !== null) parts.push(`A:${fmtPrice(anchor)}`);
        if (buyP !== null) parts.push(`B:${fmtPrice(buyP)}`);
        if (sellP !== null) parts.push(`S:${fmtPrice(sellP)}`);
        if (aiStr) parts.push(aiStr);
        return parts.join(' ');
      }
      case 'AUTOLOOP': {
        const rsi = nVal(telemetry.rsi || meta.rsi);
        const z = nVal(telemetry.zscore || meta.zscore);
        let parts = [];
        if (rsi !== null) parts.push(`RSI:${fmtNum(rsi, 1)}`);
        if (z !== null) parts.push(`Z:${fmtNum(z, 2)}`);
        if (aiStr) parts.push(aiStr);
        return parts.join(' ');
      }
      case 'SNIPER': {
        const rsi = nVal(telemetry.rsi || meta.rsi);
        let parts = [];
        if (rsi !== null) parts.push(`RSI:${fmtNum(rsi, 1)}`);
        if (aiStr) parts.push(aiStr);
        return parts.join(' ');
      }
      case 'LADDER':
      case 'LIGHTNING':
      case 'GAZUA': {
        const surge = nVal(meta.surge_pct || telemetry.surge_pct);
        let parts = [];
        if (surge !== null) parts.push(`Surge:${fmtNum(surge, 1)}%`);
        if (aiStr) parts.push(aiStr);
        return parts.join(' ');
      }
      case 'CONTRARIAN': {
        const rsi = nVal(telemetry.rsi || meta.rsi);
        let parts = [];
        if (rsi !== null) parts.push(`RSI:${fmtNum(rsi, 1)}`);
        if (aiStr) parts.push(aiStr);
        return parts.join(' ');
      }
      default:
        return aiStr;
    }
  };
  
  // [2026-02-02] Get strategy signal light state
  const getSignalLights = (strat, meta, c) => {
    const lights = [];
    if (!meta || typeof meta !== 'object') return lights;
    const levels = meta.levels || {};
    const telemetry = meta.telemetry || {};
    const lastSig = String(c.last_signal || '').toLowerCase();
    
    switch (strat) {
      case 'PINGPONG': {
        const inBand = !!levels.in_buy_zone || !!meta.in_buy_zone;
        const atExit = !!levels.at_exit || !!meta.at_exit || !!levels.exit?.triggered;
        lights.push({ key: 'BAND', state: inBand ? 'pass' : 'off', title: 'In Buy Zone' });
        lights.push({ key: 'EXIT', state: atExit ? 'block' : 'off', title: 'Exit Triggered' });
        break;
      }
      case 'AUTOLOOP': {
        const rsi = nVal(telemetry.rsi || meta.rsi);
        const rsiBuy = nVal(telemetry.rsi_buy_th) || 28;
        const rsiSell = nVal(telemetry.rsi_sell_th) || 58;
        const rsiOk = rsi !== null && rsi <= rsiBuy;
        const rsiHigh = rsi !== null && rsi >= rsiSell;
        lights.push({ key: 'RSI', state: rsiOk ? 'pass' : (rsiHigh ? 'block' : 'off'), title: `RSI: ${fmtNum(rsi, 1)}` });
        const z = nVal(telemetry.zscore || meta.zscore);
        const zOk = z !== null && z <= -1.5;
        lights.push({ key: 'Z', state: zOk ? 'pass' : 'off', title: `Z-Score: ${fmtNum(z, 2)}` });
        break;
      }
      case 'SNIPER': {
        const aiPred = nVal(c.ai_prediction);
        const aiOk = aiPred !== null && aiPred >= 0.6;
        lights.push({ key: 'AI', state: aiOk ? 'pass' : 'off', title: `AI: ${fmtNum((aiPred || 0) * 100, 0)}%` });
        break;
      }
      case 'LADDER':
      case 'LIGHTNING':
      case 'GAZUA': {
        const surge = nVal(meta.surge_pct || telemetry.surge_pct);
        const surgeOk = surge !== null && surge >= 3.0;
        lights.push({ key: 'SRG', state: surgeOk ? 'pass' : 'off', title: `Surge: ${fmtNum(surge, 1)}%` });
        break;
      }
      case 'CONTRARIAN': {
        const rsi = nVal(telemetry.rsi || meta.rsi);
        const rsiLow = rsi !== null && rsi <= 25;
        lights.push({ key: 'RSI', state: rsiLow ? 'pass' : 'off', title: `RSI: ${fmtNum(rsi, 1)}` });
        break;
      }
    }
    
    // Common: last signal indicator
    if (lastSig === 'buy') {
      lights.push({ key: 'BUY', state: 'just-pass', title: 'Last Signal: BUY' });
    } else if (lastSig === 'sell') {
      lights.push({ key: 'SELL', state: 'just-block', title: 'Last Signal: SELL' });
    }
    
    return lights;
  };
  
  for (const m of activeMarkets) {
    const c = coord[m] || {};
    const marketData = markets.find(x => x.market === m) || {};
    const marketState = (c.market_state || marketData.state || 'WATCH').toUpperCase();
    const inRecovery = marketState === 'RECOVERY' || !!c.recovery;
    const strat = (c.strategy || marketData.strategy || 'OFF').toUpperCase();
    
    const entryState = String(c.entry_state || '').toUpperCase();
    const exitState = String(c.exit_state || '').toUpperCase();
    const entryReason = (c.entry_block_reason || '').toString();
    const exitReason = (c.exit_block_reason || '').toString();
    
    const posQty = Number(c.position_qty || 0);
    const hasPos = posQty > 0;
    const hasOrder = !!c.order_state;
    
    const entryRemain = coolRemainSec(c.entry_block_until_ts);
    const exitRemain = coolRemainSec(c.exit_block_until_ts);
    
    const ov = (c.controls && c.controls.guards && typeof c.controls.guards === 'object') ? c.controls.guards : {};
    const effBool = (k, d) => (ov[k] !== undefined && ov[k] !== null) ? !!ov[k] : !!d;
    
    const entryEnabled = effBool('entry_enabled', true);
    const obOn = effBool('entry_ob_guard_enabled', g.entry_ob_guard_enabled);
    const qtyOn = effBool('entry_qty_guard', g.entry_qty_guard);
    const ceilOn = effBool('entry_ceiling_guard', g.entry_ceiling_guard);
    const rhOn = effBool('entry_recent_high_guard', g.entry_recent_high_guard);
    const profitOn = effBool('exit_profit_guard', g.exit_profit_guard);
    const tpOn = effBool('tp_limit_exit_enabled', g.tp_limit_exit_enabled);
    const entryLimitOn = effBool('entry_limit_buy_enabled', g.entry_limit_buy_enabled);
    
    const entryCause = mapEntryCause(entryState, entryReason);
    const exitCause = mapExitCause(exitState, exitReason);
    
    const buyOutcome = (entryState === 'BLOCKED') ? 'block' : 'pass';
    const sellOutcome = (exitState === 'BLOCKED') ? 'block' : 'pass';
    
    const stratColor = stratColors[strat] || '#888';
    
    // [2026-02-02] Warmup status
    const isReady = c.is_ready !== false;
    const warmupTicks = Number(c.warmup_ticks || 0);
    const minTicks = Number(c.min_ticks || 5);
    const isWarmup = !isReady && warmupTicks < minTicks;
    
    // [2026-02-02] Strategy meta info
    const lastMeta = c.last_meta || {};
    const stratMetaInfo = getStrategyMetaInfo(strat, lastMeta, c);
    const signalLights = getSignalLights(strat, lastMeta, c);
    
    // Create card
    const card = document.createElement('div');
    card.className = 'guard-card' + (isWarmup ? ' warmup' : '');
    
    // Title with warmup badge
    const stateClass = marketState === 'ACTIVE' ? 'active' : (marketState === 'RECOVERY' ? 'recovery' : 'watch');
    const warmupBadge = isWarmup ? `<span class="warmup-badge" title="Warming up: ${warmupTicks}/${minTicks} ticks">WRM ${warmupTicks}/${minTicks}</span>` : '';
    const metaSpan = stratMetaInfo ? `<span class="strat-meta text-muted small ms-1">${escHtml(stratMetaInfo)}</span>` : '';
    
    let titleHtml = `
      <div class="guard-card-title">
        <div>
          <span class="market-badge">${escHtml(m)}</span>
          <span class="state-badge ${stateClass}">${escHtml(marketState)}</span>
          ${warmupBadge}
          <span class="strat-badge" style="background:${stratColor}22; color:${stratColor};">${escHtml(strat)}</span>
          ${metaSpan}
        </div>
        <div>
          ${entryState === 'BLOCKED' ? `<span class="block-chip">BUY:${escHtml(entryCause)}</span>` : ''}
          ${exitState === 'BLOCKED' ? `<span class="block-chip ms-1">SELL:${escHtml(exitCause)}</span>` : ''}
        </div>
      </div>
    `;
    card.innerHTML = titleHtml;
    
    // BUY row
    const buyRow = document.createElement('div');
    buyRow.className = 'guard-row';
    buyRow.innerHTML = '<div class="guard-row-label">BUY</div>';
    
    const buyLights = document.createElement('div');
    buyLights.className = 'guard-lights';
    
    buyLights.appendChild(mkLampBox(m, 'BUY', 'BUY', buyOutcome, 'Last BUY outcome', entryCause === 'BUY'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'EN', entryEnabled ? 'pass' : 'block', 'Entry enabled', entryCause === 'EN'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'EMR', !!g.emergency_stop ? 'block' : 'pass', 'Emergency stop', entryCause === 'EMR'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'REC', inRecovery ? 'block' : 'pass', 'Recovery blocks entry', entryCause === 'REC'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'PND', hasOrder ? 'block' : 'pass', 'Pending order blocks entry', entryCause === 'PND'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'GCD', globalCdRemain > 0 ? 'block' : 'pass', `Global cooldown: ${globalCdRemain.toFixed(1)}s`, entryCause === 'GCD'));
    
    const maxpNow = (maxPending > 0) ? (pendingTotal >= maxPending) : false;
    buyLights.appendChild(mkLampBox(m, 'BUY', 'MAXP', (maxPending > 0) ? ((maxpNow) ? 'block' : 'pass') : 'off', `Pending: ${pendingTotal}/${maxPending || '∞'}`, entryCause === 'MAXP'));
    
    const gapState = (entryCause === 'GAP') ? 'block' : (buyOutcome === 'pass' ? 'pass' : 'off');
    buyLights.appendChild(mkLampBox(m, 'BUY', 'GAP', gapState, 'Entry global gap', entryCause === 'GAP'));
    
    buyLights.appendChild(mkLampBox(m, 'BUY', 'LCD', entryRemain > 0 ? 'block' : 'pass', `Local cooldown: ${entryRemain.toFixed(1)}s`, entryCause === 'LCD'));
    
    const minState = (entryCause === 'MIN') ? 'block' : (buyOutcome === 'pass' ? 'pass' : 'off');
    buyLights.appendChild(mkLampBox(m, 'BUY', 'MIN', minState, 'Min order USDT', entryCause === 'MIN'));
    
    buyLights.appendChild(mkLampBox(m, 'BUY', 'POS', hasPos ? 'block' : 'pass', 'Already in position', entryCause === 'POS'));
    
    const ceilState = !ceilOn ? 'off' : ((entryCause === 'CEIL') ? 'block' : (buyOutcome === 'pass' ? 'pass' : 'off'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'CEIL', ceilState, 'Ceiling guard', entryCause === 'CEIL'));
    const rhState = !rhOn ? 'off' : ((entryCause === 'RHI') ? 'block' : (buyOutcome === 'pass' ? 'pass' : 'off'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'RHI', rhState, 'Recent-high guard', entryCause === 'RHI'));

    const qtyState = !qtyOn ? 'off' : ((entryCause === 'QTY') ? 'block' : (buyOutcome === 'pass' ? 'pass' : 'off'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'QTY', qtyState, 'Qty guard', entryCause === 'QTY'));
    
    const obState = !obOn ? 'off' : ((entryCause === 'OB') ? 'block' : (buyOutcome === 'pass' ? 'pass' : 'off'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'OB', obState, 'Orderbook guard', entryCause === 'OB'));
    
    const lmtBuyState = !entryLimitOn ? 'off' : ((entryCause === 'LMT') ? 'block' : (buyOutcome === 'pass' ? 'pass' : 'off'));
    buyLights.appendChild(mkLampBox(m, 'BUY', 'LMT', lmtBuyState, 'Entry Limit mode', entryCause === 'LMT'));
    
    buyRow.appendChild(buyLights);
    card.appendChild(buyRow);
    
    // SELL row
    const sellRow = document.createElement('div');
    sellRow.className = 'guard-row';
    sellRow.innerHTML = '<div class="guard-row-label">SELL</div>';
    
    const sellLights = document.createElement('div');
    sellLights.className = 'guard-lights';
    
    sellLights.appendChild(mkLampBox(m, 'SELL', 'SELL', sellOutcome, 'Last SELL outcome', exitCause === 'SELL'));
    sellLights.appendChild(mkLampBox(m, 'SELL', 'PND', hasOrder ? 'block' : 'pass', 'Pending order blocks exit', exitCause === 'PND'));
    sellLights.appendChild(mkLampBox(m, 'SELL', 'XCD', exitRemain > 0 ? 'block' : 'pass', `Exit cooldown: ${exitRemain.toFixed(1)}s`, exitCause === 'XCD'));
    sellLights.appendChild(mkLampBox(m, 'SELL', 'NCP', hasPos ? 'pass' : 'block', 'No coin position', exitCause === 'NCP'));
    
    const pftState = !profitOn ? 'off' : ((exitCause === 'PFT') ? 'block' : (sellOutcome === 'pass' ? 'pass' : 'off'));
    sellLights.appendChild(mkLampBox(m, 'SELL', 'PFT', pftState, 'Profit guard', exitCause === 'PFT'));
    
    sellLights.appendChild(mkLampBox(m, 'SELL', 'TP', tpOn ? 'pass' : 'off', 'TP limit exit enabled', false));
    
    const lmtSellState = !entryLimitOn ? 'off' : ((exitCause === 'LMT') ? 'block' : 'pass');
    sellLights.appendChild(mkLampBox(m, 'SELL', 'LMT', lmtSellState, 'Entry Limit unfilled', exitCause === 'LMT'));
    
    sellRow.appendChild(sellLights);
    card.appendChild(sellRow);
    
    // [2026-02-02] SIG row - Strategy signal lights
    if (signalLights.length > 0) {
      const sigRow = document.createElement('div');
      sigRow.className = 'guard-row';
      sigRow.innerHTML = '<div class="guard-row-label">SIG</div>';
      
      const sigLights = document.createElement('div');
      sigLights.className = 'guard-lights';
      
      for (const light of signalLights) {
        sigLights.appendChild(mkLampBox(m, 'SIG', light.key, light.state, light.title, false));
      }
      
      sigRow.appendChild(sigLights);
      card.appendChild(sigRow);
    }
    
    box.appendChild(card);
  }
}

// Guard Matrix refresh button binding
function bindGuardMatrixEvents() {
  const refreshBtn = qs('btn-guard-refresh');
  if (refreshBtn) {
    refreshBtn.addEventListener('click', async () => {
      refreshBtn.disabled = true;
      await fetchGuardMatrix();
      refreshBtn.disabled = false;
    });
  }
  
  // [2026-02-02] Page size buttons
  const pageSizeGroup = qs('guard-page-size-group');
  if (pageSizeGroup) {
    pageSizeGroup.querySelectorAll('button[data-size]').forEach(btn => {
      btn.addEventListener('click', () => {
        const size = parseInt(btn.dataset.size, 10);
        window._guardPage.size = size;
        window._guardPage.page = 1;
        // Update active state
        pageSizeGroup.querySelectorAll('button').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        // Re-render
        if (window._lastGuardData && window._lastGuardMarkets) {
          renderGuardGrid(window._lastGuardData, window._lastGuardMarkets);
        }
      });
    });
  }
}

// ============================================================
// SNIPER Strategy Candidates
// ============================================================

async function renderSniperCandidates() {
  const container = document.getElementById('sniper-candidates');
  if (!container) return;
  
  try {
    const strategyLabel = getSniperRecommendStrategy();
    const res = await authFetch(API.recommendations(strategyLabel, 5));
    const data = await res.json();
    
    if (!data.ok || !data.items?.length) {
      container.innerHTML = `<div class="text-muted small p-2">${t('empty.no_recommendations', 'No recommendations')}</div>`;
      return;
    }
    
    container.innerHTML = data.items.map(item => {
      const coin = item.market.replace(/USDT$/i,'');
      const params = item.recommended_params || {};
      const currentPrice = item.price || 0;
      // 동적 파라미터 사용
      const entryLookback = params.entry_lookback_min || params.lookback_min || 60;
      const entryThres = params.entry_threshold_pct || params.threshold_pct || 0.3;
      const exitThres = params.exit_threshold_pct || params.threshold_pct || 0.3;
      const expiry = params.expiry_min || 60;
      const entryPrice = item.entry_target_price || (currentPrice * (1 - entryThres / 100));
      const exitPrice = item.exit_target_price || (currentPrice * (1 + exitThres / 100));
      const aiScore = (item.ai_score * 100).toFixed(0);
      const aiClass = item.ai_score >= 0.6 ? 'text-success' : (item.ai_score >= 0.4 ? 'text-warning' : 'text-danger');
      
      // lookback 표시 포맷 (분→시간 변환)
      const formatLookback = (min) => {
        if (min >= 1440) return `${Math.round(min / 1440)}${t('unit.day', 'd')}`;
        if (min >= 60) return `${Math.round(min / 60)}${t('unit.hour', 'h')}`;
        return `${min}${t('unit.minute', 'm')}`;
      };
      const lookbackDisplay = formatLookback(entryLookback);
      
      return `
        <div class="candidate-item p-2 border-bottom" 
             data-market="${item.market}" 
             data-params='${JSON.stringify(params)}'>
          <div class="d-flex justify-content-between align-items-center mb-1">
            <div>
              <strong>${coin}</strong>
              <span class="badge ${aiClass} ms-1">AI ${aiScore}%</span>
              <span class="badge bg-primary-lt ms-1">${strategyLabel}</span>
              <span class="badge bg-secondary-lt ms-1">${lookbackDisplay}</span>
            </div>
            <button class="btn btn-sm btn-outline-primary sniper-setup-btn">Setup</button>
          </div>
          <div class="d-flex justify-content-between small">
            <span class="text-success">${t('table.planned_entry', 'Planned Entry')}: $${formatNumber(entryPrice)}</span>
            <span>${t('table.current', 'Current')}: $${formatNumber(currentPrice)}</span>
            <span class="text-danger">${t('table.planned_exit', 'Planned Exit')}: $${formatNumber(exitPrice)}</span>
          </div>
        </div>
      `;
    }).join('');
    
    // Setup 버튼 이벤트
    container.querySelectorAll('.sniper-setup-btn').forEach(btn => {
      btn.addEventListener('click', (e) => {
        const item = e.target.closest('.candidate-item');
        const market = item.dataset.market;
        const params = JSON.parse(item.dataset.params || '{}');
        openSniperSetupModal(market, params);
      });
    });
  } catch (err) {
    console.error('[SNIPER] candidates error:', err);
    container.innerHTML = `<div class="text-danger small p-2">${t('status.load_failed', 'Load failed')}</div>`;
  }
}

function openSniperSetupModal(market, params) {
  // Fill sniper form fields if they exist - 동적 파라미터 사용
  if (qs('sn-market')) qs('sn-market').value = market;
  if (qs('sn-profile')) qs('sn-profile').value = String(params.profile || 'SNIPER').toUpperCase();
  if (qs('sn-side')) qs('sn-side').value = String(params.side || 'LONG').toUpperCase();
  
  // [2026-02-02] lookback: 분 단위로 들어오면 시간 단위로 변환하여 표시
  const lookbackMin = params.entry_lookback_min || params.lookback_min || params.lookback || 240;
  const exitLookbackMin = params.exit_lookback_min || lookbackMin;
  
  // 60분 이상이면 시간 단위로 표시
  if (lookbackMin >= 60) {
    if (qs('sn-entry-lookback')) qs('sn-entry-lookback').value = Math.round(lookbackMin / 60);
    if (qs('sn-entry-unit')) qs('sn-entry-unit').value = 'hour';
  } else {
    if (qs('sn-entry-lookback')) qs('sn-entry-lookback').value = lookbackMin;
    if (qs('sn-entry-unit')) qs('sn-entry-unit').value = 'min';
  }
  
  if (exitLookbackMin >= 60) {
    if (qs('sn-exit-lookback')) qs('sn-exit-lookback').value = Math.round(exitLookbackMin / 60);
    if (qs('sn-exit-unit')) qs('sn-exit-unit').value = 'hour';
  } else {
    if (qs('sn-exit-lookback')) qs('sn-exit-lookback').value = exitLookbackMin;
    if (qs('sn-exit-unit')) qs('sn-exit-unit').value = 'min';
  }
  
  // threshold
  const threshold = params.entry_threshold_pct || params.threshold_pct || params.threshold || 0.3;
  if (qs('sn-entry-threshold')) qs('sn-entry-threshold').value = threshold;
  if (qs('sn-exit-threshold')) qs('sn-exit-threshold').value = params.exit_threshold_pct || threshold;
  // expiry (분 단위)
  const expiryMin = params.expiry_min || params.expiry || 360;
  if (qs('sn-expiry')) qs('sn-expiry').value = expiryMin;
  // budget, tp, sl
  if (qs('sn-budget')) qs('sn-budget').value = params.budget || 50;
  if (qs('sn-tp')) qs('sn-tp').value = params.tp_pct || params.tp || 2;
  if (qs('sn-sl')) qs('sn-sl').value = Math.abs(params.sl_pct || params.sl || 1.5);
  if (qs('sn-cycle-mode')) qs('sn-cycle-mode').value = String(params.cycle_mode || 'AUTO').toUpperCase();
  if (qs('sn-no-demote')) qs('sn-no-demote').checked = !!params.no_demote;
  if (qs('sn-auto-reentry')) qs('sn-auto-reentry').checked = !!params.auto_reentry;
  syncSniperProfileUI();
  
  // Show modal if using Bootstrap modal
  const modal = document.getElementById('sniper-setup-modal');
  if (modal && typeof bootstrap !== 'undefined') {
    const bsModal = new bootstrap.Modal(modal);
    bsModal.show();
  }
  
  showToast(tf('status.setup_ready', 'SNIPER: {market} setup ready', { market }), 'info');
}

// loadSniperList - SNIPER 전략 목록 로드
async function loadSniperList() {
  try {
    const res = await authFetch(API.sniperList);
    const data = await res.json();
    const rawItems = data.items || data.markets || [];
    const activeItems = (Array.isArray(rawItems) ? rawItems : []).filter((item) => {
      const stateTag = String(item?.state || item?.status || '').toUpperCase();
      if (stateTag !== 'ACTIVE') return false;
      const p = item?.params || {};
      const profile = String(p.profile || '').toUpperCase();
      const source = String(p.source || '').toLowerCase();
      return profile !== 'SNIPERS' && source !== 'precision_scope';
    });
    renderStrategyListTable('sniper', activeItems);
    
    // Update count badge if exists
    const countBadge = qs('sniper-candidate-count');
    if (countBadge) {
      countBadge.textContent = String(activeItems.length);
    }
  } catch (err) {
    console.error('[SNIPER] list load error:', err);
  }
}

// Expose for external use
window.renderSniperCandidates = renderSniperCandidates;
window.openSniperSetupModal = openSniperSetupModal;
window.loadSniperList = loadSniperList;

