let perfCurrentPeriod = 24;  // Default: 24 hours

async function loadPerformancePage() {
  // Setup event listeners
  setupPerformanceListeners();
  
  // Load initial data
  await fetchPerformanceSummary(perfCurrentPeriod);
  await fetchStrategyPerformance(perfCurrentPeriod);
  await fetchTopPerformers(perfCurrentPeriod);
  await fetchPeriodPerformance(24);  // Daily by default
}

function setupPerformanceListeners() {
  // Period selector
  document.querySelectorAll('input[name="perf-period"]').forEach(radio => {
    radio.addEventListener('change', async (e) => {
      perfCurrentPeriod = parseInt(e.target.value);
      await fetchPerformanceSummary(perfCurrentPeriod);
      await fetchStrategyPerformance(perfCurrentPeriod);
      await fetchTopPerformers(perfCurrentPeriod);
    });
  });
  
  // Period view selector
  document.querySelectorAll('input[name="period-view"]').forEach(radio => {
    radio.addEventListener('change', async (e) => {
      const periodHours = parseInt(e.target.value);
      await fetchPeriodPerformance(periodHours);
    });
  });
  
  // Refresh button
  document.getElementById('btn-refresh-performance')?.addEventListener('click', async () => {
    await loadPerformancePage();
  });
}

async function fetchPerformanceSummary(since_hours = 24) {
  try {
    const resp = await authFetch(`/api/performance/summary?since_hours=${since_hours}`);
    if (!resp.ok) throw new Error('Failed to fetch performance summary');
    
    const data = await resp.json();
    
    // Update summary cards
    document.getElementById('perf-total-trades').textContent = data.total_trades.toLocaleString();
    document.getElementById('perf-total-pnl').textContent = formatAmount(data.total_pnl_usdt);
    document.getElementById('perf-roi').textContent = `${data.roi_pct.toFixed(2)}%`;
    document.getElementById('perf-roi').className = `h2 mb-0 ${data.roi_pct >= 0 ? 'text-success' : 'text-danger'}`;
    document.getElementById('perf-sharpe').textContent = data.sharpe_ratio.toFixed(2);
    document.getElementById('perf-mdd').textContent = `${data.max_drawdown_pct.toFixed(2)}%`;
    document.getElementById('perf-invested').textContent = formatAmount(data.total_invested_usdt);
    const feesEl = document.getElementById('perf-total-fees');
    const feeImpactEl = document.getElementById('perf-fee-impact');
    if (feesEl) feesEl.textContent = formatAmount(data.total_fees_usdt || 0);
    if (feeImpactEl) {
      const fees = data.total_fees_usdt || 0;
      const pnl = data.total_pnl_usdt || 0;
      if (pnl > 0 && fees > 0) {
        const pct = (fees / pnl * 100).toFixed(1);
        feeImpactEl.textContent = `수수료/순이익 ${pct}%`;
      } else {
        feeImpactEl.textContent = '—';
      }
    }
  } catch (err) {
    console.error('Failed to fetch performance summary:', err);
    showAlert(t('error.performance_summary_load_failed', 'Failed to load performance summary'), 'danger');
  }
}

async function fetchStrategyPerformance(since_hours = 24) {
  try {
    const resp = await authFetch(`/api/performance/strategy?since_hours=${since_hours}`);
    if (!resp.ok) throw new Error('Failed to fetch strategy performance');
    
    const data = await resp.json();
    const tbody = document.getElementById('perf-strategy-body');
    
    if (Object.keys(data).length === 0) {
      tbody.innerHTML = `<tr><td colspan="9" class="text-center text-muted py-5">${t('empty.no_trade_records', 'No trade records')}</td></tr>`;
      return;
    }
    
    // Sort by ROI descending
    const strategies = Object.entries(data).sort((a, b) => b[1].roi_pct - a[1].roi_pct);
    
    tbody.innerHTML = strategies.map(([name, perf]) => {
      const winRate = (perf.win_rate * 100).toFixed(1);
      const roiClass = perf.roi_pct >= 0 ? 'text-success' : 'text-danger';
      
      return `
        <tr>
          <td><strong>${name}</strong></td>
          <td class="text-center">${perf.total_trades}</td>
          <td class="text-center">${winRate}% <span class="text-muted small">(${perf.wins}/${perf.losses})</span></td>
          <td class="text-end ${perf.avg_return_pct >= 0 ? 'text-success' : 'text-danger'}">
            ${perf.avg_return_pct.toFixed(2)}%
          </td>
          <td class="text-end ${roiClass}">${formatAmount(perf.total_pnl_usdt)}</td>
          <td class="text-end ${roiClass}">${perf.roi_pct.toFixed(2)}%</td>
          <td class="text-end ${perf.max_drawdown_pct >= 0 ? 'text-success' : 'text-danger'}">
            ${perf.max_drawdown_pct.toFixed(2)}%
          </td>
          <td class="text-end">${perf.sharpe_ratio.toFixed(2)}</td>
          <td class="text-center">${perf.markets.length}</td>
        </tr>
      `;
    }).join('');
  } catch (err) {
    console.error('Failed to fetch strategy performance:', err);
    showAlert(t('error.strategy_performance_load_failed', 'Failed to load strategy performance'), 'danger');
  }
}

async function fetchTopPerformers(since_hours = 24) {
  try {
    // Top ROI
    const roiResp = await authFetch(`/api/performance/top?metric=roi_pct&limit=5&since_hours=${since_hours}`);
    const roiData = await roiResp.json();
    renderTopPerformers('perf-top-roi', roiData, 'roi_pct', '%');
    
    // Top Win Rate
    const wrResp = await authFetch(`/api/performance/top?metric=win_rate&limit=5&since_hours=${since_hours}`);
    const wrData = await wrResp.json();
    renderTopPerformers('perf-top-winrate', wrData, 'win_rate', '%', 100);
    
    // Top PnL
    const pnlResp = await authFetch(`/api/performance/top?metric=total_pnl_usdt&limit=5&since_hours=${since_hours}`);
    const pnlData = await pnlResp.json();
    renderTopPerformers('perf-top-pnl', pnlData, 'total_pnl_usdt', t('unit.usdt', ' USDT'), 1, true);
  } catch (err) {
    console.error('Failed to fetch top performers:', err);
  }
}

function renderTopPerformers(containerId, data, metric, suffix, multiplier = 1, isQuoteCurrency = false) {
  const container = document.getElementById(containerId);
  if (!container) return;
  
  if (!data || data.length === 0) {
    container.innerHTML = `<div class="text-center text-muted py-3">${t('empty.no_data', 'No data')}</div>`;
    return;
  }
  
  const html = data.map((item, idx) => {
    const value = item.metric_value * multiplier;
    const displayValue = isQuoteCurrency ? formatAmount(value) : value.toFixed(2) + suffix;
    const badge = idx === 0 ? 'bg-warning' : idx === 1 ? 'bg-azure-lt' : 'bg-secondary-lt';
    
    return `
      <div class="d-flex justify-content-between align-items-center mb-2">
        <div class="d-flex align-items-center">
          <span class="badge ${badge} me-2">${idx + 1}</span>
          <strong>${item.strategy}</strong>
        </div>
        <span class="${value >= 0 ? 'text-success' : 'text-danger'}">${displayValue}</span>
      </div>
    `;
  }).join('');
  
  container.innerHTML = html;
}

async function fetchPeriodPerformance(period_hours = 24) {
  try {
    const limit = period_hours === 24 ? 7 : 4;  // 7 days or 4 weeks
    const resp = await authFetch(`/api/performance/period?period_hours=${period_hours}&limit=${limit}`);
    if (!resp.ok) throw new Error('Failed to fetch period performance');
    
    const data = await resp.json();
    const tbody = document.getElementById('perf-period-body');
    
    if (!data || data.length === 0) {
      tbody.innerHTML = `<tr><td colspan="5" class="text-center text-muted py-5">${t('empty.no_trade_records', 'No trade records')}</td></tr>`;
      return;
    }
    
    tbody.innerHTML = data.map(period => {
      const roiClass = period.roi_pct >= 0 ? 'text-success' : 'text-danger';
      
      // Strategy breakdown
      const topStrategies = Object.entries(period.strategies)
        .sort((a, b) => b[1].total_pnl_usdt - a[1].total_pnl_usdt)
        .slice(0, 3)
        .map(([name, perf]) => {
          const pnl = perf.total_pnl_usdt;
          const badge = pnl >= 0 ? 'bg-success-lt' : 'bg-danger-lt';
          return `<span class="badge ${badge} me-1">${name}</span>`;
        }).join('');
      
      return `
        <tr>
          <td>${period.period_name}</td>
          <td class="text-center">${period.total_trades}</td>
          <td class="text-end ${roiClass}">${formatAmount(period.total_pnl_usdt)}</td>
          <td class="text-end ${roiClass}">${period.roi_pct.toFixed(2)}%</td>
          <td>${topStrategies || '<span class="text-muted">-</span>'}</td>
        </tr>
      `;
    }).join('');
  } catch (err) {
    console.error('Failed to fetch period performance:', err);
    showAlert(t('error.period_performance_load_failed', 'Failed to load period performance'), 'danger');
  }
}

function formatAmount(amount) {
  const n = Number(amount) || 0;
  const absAmount = Math.abs(n);
  const sign = n < 0 ? '-' : '';
  if (absAmount >= 1e6) return `${sign}${(absAmount / 1e6).toFixed(2)}M USDT`;
  if (absAmount >= 1e3) return `${sign}${(absAmount / 1e3).toFixed(1)}K USDT`;
  return `${sign}${absAmount.toFixed(2)} USDT`;
}

