// ── Fast-Reject Presets ──
const FR_PRESETS = {
  conservative: { min: 900, max: 1800, pnl: -0.8, peak: 0.2,  label: '보수 (15~30분, -0.8%)' },
  balanced:     { min: 600, max: 1500, pnl: -0.5, peak: 0.15, label: '보편 (10~25분, -0.5%)' },
  aggressive:   { min: 300, max: 900,  pnl: -0.3, peak: 0.15, label: '공격 (5~15분, -0.3%)' },
};
function fastRejectPreset(name) {
  const p = FR_PRESETS[name];
  if (!p) return;
  _focusEditing = true;
  const _s = (id, v) => { const e = document.getElementById(id); if (e) e.value = v; };
  _s('focus-cfg-fr-min', p.min);
  _s('focus-cfg-fr-max', p.max);
  _s('focus-cfg-fr-pnl', p.pnl);
  _s('focus-cfg-fr-peak', p.peak);
  const lbl = document.getElementById('focus-fr-preset-label');
  if (lbl) lbl.textContent = p.label;
}
function _updateFrPresetLabel() {
  const min = parseFloat(document.getElementById('focus-cfg-fr-min')?.value) || 0;
  const pnl = parseFloat(document.getElementById('focus-cfg-fr-pnl')?.value) || 0;
  const lbl = document.getElementById('focus-fr-preset-label');
  if (!lbl) return;
  const match = Object.values(FR_PRESETS).find(p => p.min === min && p.pnl === pnl);
  lbl.textContent = match ? match.label : 'Custom';
}
window.fastRejectPreset = fastRejectPreset;

