// 동생 1차 (aee7091): momentum_deriv / mtf_align / scanner_conv / raw_body 4종만 → 본체 가드 (min_conviction, min_adx) 안 건드려 체감 미미.
// 진짜 완화 (이 commit): 본체 가드까지 한 방향(진입 늘리기)으로 일관 조정 → 단계마다 명확한 체감.
// 버튼 클릭 → input 자동 채움. Save Config 클릭해야 봇에 적용.
window._focusApplyStrictnessPreset = function(level) {
  const presets = {
    strict: {
      // [2026-05-17 100점 체계 ×10] 본체 가드 (default)
      min_conviction: 70,
      scanner_min_conviction: 70,
      min_adx_entry: 20,
      scanner_min_adx: 25,
      microtiming_5m_min_score: 2,
      // 동생 4종 가드 (default)
      mtf_momentum_align_min_aligned: 2,
      momentum_deriv_guard_require_both: false,
      raw_body_guard_min_net_pct: 0.0,
      _label: 'Strict (default) — conv 70 / ADX 20 / mtf 2'
    },
    mild1: {
      // ★ 본체 conviction 10점 ↓ (70→60)
      min_conviction: 60,
      scanner_min_conviction: 60,
      min_adx_entry: 20,
      scanner_min_adx: 25,
      microtiming_5m_min_score: 2,
      mtf_momentum_align_min_aligned: 2,
      momentum_deriv_guard_require_both: false,
      raw_body_guard_min_net_pct: 0.0,
      _label: '진짜 완화 1 (살짝) — conv 70→60'
    },
    mild2: {
      // ★ + ADX/mtf 까지 풀어 추세 약한 코인도 진입
      min_conviction: 60,
      scanner_min_conviction: 60,
      min_adx_entry: 17,
      scanner_min_adx: 22,
      microtiming_5m_min_score: 2,
      mtf_momentum_align_min_aligned: 1,
      momentum_deriv_guard_require_both: false,
      raw_body_guard_min_net_pct: 0.0,
      _label: '진짜 완화 2 (중간) — + ADX 20→17, mtf 2→1'
    },
    mild3: {
      // ★ conviction 50 + microtiming 1 — 공격적. 활발장 전용.
      min_conviction: 50,
      scanner_min_conviction: 50,
      min_adx_entry: 17,
      scanner_min_adx: 22,
      microtiming_5m_min_score: 1,
      mtf_momentum_align_min_aligned: 1,
      momentum_deriv_guard_require_both: false,
      raw_body_guard_min_net_pct: 0.0,
      _label: '진짜 완화 3 (공격) — + conv 50, microtiming 1. 노이즈 위험 ↑'
    }
  };
  const p = presets[level];
  if (!p) { console.warn('[Strictness] unknown level:', level); return; }
  // ★ [2026-05-16 형 fix] _focusEditing=true 안 세우면 status fetch (refreshFocusStatus L18975)
  // 가 _fc() 로 input 값을 서버값으로 덮어씀 → Save Config 시 옛 값 POST.
  // 동생 1차 (aee7091) 가 이 플래그 누락 → 완화3 미반영 사고 (config_post_revert_bug).
  // FR_PRESETS (L21451) / EQ_PRESETS (L21479) 도 동일 패턴.
  _focusEditing = true;
  const _setVal = (id, val) => { const e = document.getElementById(id); if (e) e.value = val; };
  const _setChk = (id, val) => { const e = document.getElementById(id); if (e) e.checked = !!val; };
  // 본체 가드
  _setVal('focus-cfg-min-conviction', p.min_conviction);
  _setVal('focus-cfg-scanner-conv', p.scanner_min_conviction);
  _setVal('focus-cfg-min-adx', p.min_adx_entry);
  _setVal('focus-cfg-scanner-adx', p.scanner_min_adx);
  _setVal('focus-cfg-mt5m-min-score', p.microtiming_5m_min_score);
  // 동생 4종 가드
  _setVal('focus-cfg-mtf-mom-min-aligned', p.mtf_momentum_align_min_aligned);
  _setChk('focus-cfg-md-guard-require-both', p.momentum_deriv_guard_require_both);
  _setVal('focus-cfg-raw-body-min-net', p.raw_body_guard_min_net_pct);
  console.log(`[Strictness] ${p._label} applied to inputs. Click "Save Config" to commit.`);
  if (typeof showToast === 'function') {
    showToast(`Strictness "${p._label}" → input 채워짐. Save Config 클릭해 적용.`, 'info', 5000);
  } else {
    alert(`Strictness "${p._label}" 적용됨.\n\nSave Config 클릭해 저장하세요.`);
  }
};

