// ── Daily PnL Chart ────────────────────────────────────────
async function loadDailyChart() {
  const placeholder = document.getElementById('daily-chart-placeholder');
  const canvas = document.getElementById('daily-pnl-canvas');
  if (!canvas) return;
  try {
    const res = await fetch('/api/strategy/focus/daily-snapshots', {credentials:'include'}).then(r => r.json());
    if (!res.ok || !res.snapshots || res.snapshots.length === 0) {
      if (placeholder) placeholder.textContent = 'No daily data yet';
      return;
    }
    // 오늘 today_pnl도 포함
    const snaps = res.snapshots;
    // today_pnl from journal summary (이미 로드됨)
    const todayEl = document.getElementById('journal-today-pnl');
    if (todayEl) {
      // 정규식이 `-` 보존하므로 parseFloat 결과가 이미 부호 반영됨 (중복 곱 금지)
      const todayVal = parseFloat(todayEl.textContent.replace(/[^0-9.\-]/g, '')) || 0;
      const todayDate = new Date().toLocaleDateString('en-CA', {timeZone:'Asia/Seoul'});
      const existing = snaps.find(s => s.date === todayDate);
      if (!existing) {
        snaps.push({date: todayDate, total_pnl: todayVal, total_trades: 0, weekday: ''});
      }
    }

    if (placeholder) placeholder.style.display = 'none';
    canvas.style.display = 'block';
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.parentElement.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);
    const W = rect.width, H = rect.height;

    const data = snaps.map(s => ({date: s.date, pnl: s.total_pnl, trades: s.total_trades}));
    const maxAbs = Math.max(5, ...data.map(d => Math.abs(d.pnl))) * 1.2;
    const mid = H / 2;
    const padL = 50, padR = 20;
    const barW = Math.min(40, (W - padL - padR) / data.length - 4);
    const gap = (W - padL - padR) / data.length;

    ctx.clearRect(0, 0, W, H);

    // 0선
    ctx.strokeStyle = '#555';
    ctx.lineWidth = 1;
    ctx.setLineDash([4, 4]);
    ctx.beginPath();
    ctx.moveTo(padL, mid);
    ctx.lineTo(W - padR, mid);
    ctx.stroke();
    ctx.setLineDash([]);

    // 누적선
    let cumPnl = 0;
    const cumPoints = [];

    // 바 그리기
    data.forEach((d, i) => {
      const x = padL + i * gap + gap / 2;
      const barH = (d.pnl / maxAbs) * (mid - 10);
      const y = d.pnl >= 0 ? mid - barH : mid;
      const h = Math.abs(barH);

      ctx.fillStyle = d.pnl >= 0 ? 'rgba(76,175,80,0.7)' : 'rgba(244,67,54,0.7)';
      ctx.fillRect(x - barW / 2, y, barW, h);

      // 금액 라벨
      ctx.fillStyle = d.pnl >= 0 ? '#4caf50' : '#f44336';
      ctx.font = '10px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('$' + d.pnl.toFixed(0), x, d.pnl >= 0 ? y - 3 : y + h + 11);

      // 날짜 라벨
      ctx.fillStyle = '#888';
      ctx.font = '9px sans-serif';
      const label = d.date.slice(5);  // MM-DD
      ctx.fillText(label, x, H - 3);

      // 누적
      cumPnl += d.pnl;
      cumPoints.push({x, y: mid - (cumPnl / maxAbs) * (mid - 10)});
    });

    // 누적선 그리기
    if (cumPoints.length > 1) {
      ctx.strokeStyle = '#ffb74d';
      ctx.lineWidth = 2;
      ctx.beginPath();
      cumPoints.forEach((p, i) => i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y));
      ctx.stroke();
      // 누적 끝 값
      ctx.fillStyle = '#ffb74d';
      ctx.font = 'bold 10px sans-serif';
      ctx.textAlign = 'left';
      const last = cumPoints[cumPoints.length - 1];
      ctx.fillText('$' + cumPnl.toFixed(0), last.x + 5, last.y - 3);
    }

    // Y축 라벨
    ctx.fillStyle = '#888';
    ctx.font = '9px sans-serif';
    ctx.textAlign = 'right';
    ctx.fillText('+$' + maxAbs.toFixed(0), padL - 5, 14);
    ctx.fillText('-$' + maxAbs.toFixed(0), padL - 5, H - 14);
    ctx.fillText('$0', padL - 5, mid + 4);

  } catch(e) {
    console.error('[DailyChart]', e);
    if (placeholder) placeholder.textContent = 'Chart error';
  }
}
window.loadDailyChart = loadDailyChart;
// FOCUS 페이지 진입 시 로드
