// 형의 선물 UI: Coin Report Card + Drawdown Shield + Correlation
// ============================================================

const _gradeColors = {S:'#fbbf24',A:'#34d399',B:'#60a5fa',C:'#94a3b8',D:'#f97316',F:'#ef4444'};
const _gradeBg = {S:'rgba(251,191,36,0.15)',A:'rgba(52,211,153,0.12)',B:'rgba(96,165,250,0.10)',C:'rgba(148,163,184,0.08)',D:'rgba(249,115,22,0.12)',F:'rgba(239,68,68,0.12)'};

async function loadCoinGrades() {
  try {
    const r = await fetch('/api/strategy/focus/coin-grades');
    const d = await r.json();
    if (!d.ok || !d.rankings) return;
    const tb = document.getElementById('coin-grades-tbody');
    if (!tb) return;
    tb.innerHTML = d.rankings.map(c => {
      const gc = _gradeColors[c.grade] || '#94a3b8';
      const gb = _gradeBg[c.grade] || '';
      const coin = d.coins?.[c.coin] || {};
      const pnlC = c.pnl >= 0 ? 'color:#34d399' : 'color:#ef4444';
      const avgPnl = coin.avg_pnl ?? 0;
      const avgC = avgPnl >= 0 ? 'color:#34d399' : 'color:#ef4444';
      const pf = coin.profit_factor ?? 0;
      return `<tr>
        <td>${c.rank}</td>
        <td class="fw-bold">${c.coin.replace('USDT','')}</td>
        <td><span style="background:${gb};color:${gc};padding:2px 8px;border-radius:4px;font-weight:700;font-size:0.85em;">${c.grade}</span></td>
        <td>${c.score.toFixed(1)}</td>
        <td>${coin.trades??0} <span class="text-muted">(${coin.wins??0}W/${coin.losses??0}L)</span></td>
        <td>${(coin.win_rate??0).toFixed(1)}%</td>
        <td style="${pnlC}">$${c.pnl>=0?'+':''}${c.pnl.toFixed(2)}</td>
        <td style="${avgC}">$${avgPnl>=0?'+':''}${avgPnl.toFixed(2)}</td>
        <td>${pf>=100?'∞':pf.toFixed(1)}</td>
      </tr>`;
    }).join('');
  } catch(e) { console.warn('Coin grades load error:', e); }
}
window.loadCoinGrades = loadCoinGrades;

async function loadDayOfWeek() {
  try {
    const r = await fetch('/api/strategy/focus/analytics/by-dow');
    const d = await r.json();
    if (!d.ok || !d.days) return;
    const tb = document.getElementById('dow-tbody');
    if (!tb) return;
    const best = d.days.length > 0 ? d.days[0].day : '';
    const worst = d.days.length > 0 ? d.days[d.days.length - 1].day : '';
    tb.innerHTML = d.days.map(r => {
      const pC = r.pnl >= 0 ? 'color:#34d399' : 'color:#ef4444';
      const tag = r.day === best ? ' <span style="color:#fbbf24;font-size:0.75em;">BEST</span>' :
                  (r.day === worst && r.pnl < 0 ? ' <span style="color:#ef4444;font-size:0.75em;">WORST</span>' : '');
      return `<tr>
        <td class="fw-bold">${r.day}${tag}</td>
        <td style="${pC};font-weight:600;">$${r.pnl>=0?'+':''}${r.pnl.toFixed(2)}</td>
        <td>${r.trades} <span class="text-muted">(${r.wins}W)</span></td>
        <td>${r.win_rate.toFixed(1)}%</td>
      </tr>`;
    }).join('');
  } catch(e) { console.warn('DOW load error:', e); }
}

async function loadTimeSlots() {
  try {
    const r = await fetch('/api/strategy/focus/analytics/by-slot');
    const d = await r.json();
    if (!d.ok || !d.slots) return;
    const tb = document.getElementById('slot-tbody');
    if (!tb) return;
    const maxPnl = Math.max(...d.slots.map(s => s.pnl));
    const minPnl = Math.min(...d.slots.map(s => s.pnl));
    tb.innerHTML = d.slots.map(s => {
      const pC = s.pnl >= 0 ? 'color:#34d399' : 'color:#ef4444';
      const tag = s.pnl === maxPnl ? ' <span style="color:#fbbf24;font-size:0.7em;">GOLDEN</span>' :
                  (s.pnl === minPnl && s.pnl < 0 ? ' <span style="color:#ef4444;font-size:0.7em;">DANGER</span>' : '');
      return `<tr>
        <td class="fw-bold">${s.slot}${tag}</td>
        <td style="${pC};font-weight:600;">$${s.pnl>=0?'+':''}${s.pnl.toFixed(2)}</td>
        <td>${s.trades} <span class="text-muted">(${s.wins}W)</span></td>
        <td>${s.win_rate.toFixed(1)}%</td>
      </tr>`;
    }).join('');
  } catch(e) { console.warn('Slot load error:', e); }
}

